import React, { useState, useRef, useEffect } from 'react';
import { Role, ChatMessage, FileData } from '../types';
import { geminiService } from '../services/geminiService';
import { FileUpload } from './FileUpload';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useWebSearch, setUseWebSearch] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = () => {
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useWebSearch);
      setInput('');
      setFiles([]);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-full relative">
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 space-y-6 pb-40"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto opacity-80">
            <div className="w-16 h-16 bg-indigo-500/10 rounded-2xl flex items-center justify-center mb-6">
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#6366f1" strokeWidth="2">
                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
              </svg>
            </div>
            <h2 className="text-2xl font-bold text-white mb-2">Welcome to Rahix AI</h2>
            <p className="text-slate-400">
              Analyze complex documents, generate high-quality images, or start collaborative writing sessions. How can I help you today?
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === Role.USER ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`max-w-[85%] space-y-2`}>
              <div className="flex items-center gap-2 mb-1">
                <span className="text-[10px] text-slate-500 font-medium uppercase tracking-wider">
                  {msg.role === Role.USER ? 'You' : 'Rahix AI'}
                </span>
              </div>

              <div 
                className={`p-4 rounded-2xl ${
                  msg.role === Role.USER 
                    ? 'bg-indigo-600 text-white rounded-tr-none' 
                    : 'bg-[#1e293b] text-slate-200 rounded-tl-none border border-[#334155]'
                }`}
              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-3">
                    {msg.files.map((f, idx) => (
                      <div key={idx} className="bg-white/10 p-2 rounded-lg flex items-center gap-2 border border-white/10">
                        {f.type.startsWith('image/') ? (
                          <img src={f.previewUrl || f.data} className="w-10 h-10 object-cover rounded" />
                        ) : (
                          <div className="w-10 h-10 bg-indigo-500/20 rounded flex items-center justify-center text-xl">📄</div>
                        )}
                        <div className="text-[10px] overflow-hidden">
                          <p className="font-bold truncate max-w-[80px]">{f.name}</p>
                          <p className="opacity-60">{(f.size / 1024).toFixed(1)} KB</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {msg.isImageGeneration ? (
                   <div className="space-y-3">
                      <p className="text-sm italic opacity-80 mb-2">Generated based on: "{msg.text}"</p>
                      <img src={msg.text} className="w-full rounded-lg shadow-xl cursor-pointer hover:scale-[1.01] transition-transform" />
                      <div className="flex gap-2">
                        <button className="text-xs px-3 py-1.5 bg-white/10 hover:bg-white/20 rounded flex items-center gap-1">
                          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" /></svg>
                          Download
                        </button>
                      </div>
                   </div>
                ) : (
                  <div className="whitespace-pre-wrap text-sm leading-relaxed prose prose-invert">
                    {msg.text}
                  </div>
                )}

                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-slate-700/50">
                    <p className="text-[10px] text-slate-500 font-bold mb-2 uppercase tracking-widest">Sources</p>
                    <div className="flex flex-wrap gap-2">
                      {msg.sources.map((s, idx) => (
                        <a 
                          key={idx} 
                          href={s.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-[11px] bg-slate-800 hover:bg-slate-700 text-indigo-400 px-2 py-1 rounded border border-slate-700 flex items-center gap-1 transition-colors"
                        >
                          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" /><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" /></svg>
                          {s.title}
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex gap-2 px-1">
                  <button 
                    onClick={() => onEditInCanvas(msg.text)}
                    className="p-1.5 hover:bg-[#1e293b] rounded text-slate-500 hover:text-indigo-400 transition-colors"
                    title="Edit in Canvas"
                  >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" /><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" /></svg>
                  </button>
                  <button className="p-1.5 hover:bg-[#1e293b] rounded text-slate-500 hover:text-slate-200 transition-colors">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-[#1e293b] border border-[#334155] p-4 rounded-2xl rounded-tl-none flex items-center gap-3">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
              </div>
              <span className="text-xs text-slate-400 font-medium">Rahix AI is thinking...</span>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-[#0f172a] via-[#0f172a]/95 to-transparent">
        <div className="max-w-4xl mx-auto space-y-4">
          <div className="flex items-center gap-3 px-2">
             <button 
                onClick={() => setUseWebSearch(!useWebSearch)}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[11px] font-bold transition-all border ${
                  useWebSearch 
                    ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/30' 
                    : 'bg-slate-800 text-slate-400 border-slate-700'
                }`}
             >
               <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>
               {useWebSearch ? 'Web Search Enabled' : 'Search Web'}
             </button>
             <div className="h-4 w-px bg-slate-700"></div>
             <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
          </div>

          <div className="relative group">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyPress}
              placeholder="Type your request... (e.g., 'Generate an image of a futuristic city' or 'Analyze this PDF')"
              className="w-full bg-[#1e293b] border border-[#334155] focus:border-indigo-500/50 focus:ring-2 focus:ring-indigo-500/20 text-slate-100 rounded-2xl py-4 pl-4 pr-16 resize-none min-h-[60px] max-h-[200px] transition-all outline-none"
              rows={1}
            />
            <button
              onClick={handleSend}
              disabled={isLoading || (!input.trim() && files.length === 0)}
              className="absolute right-3 bottom-3 p-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:hover:bg-indigo-600 text-white rounded-xl transition-all shadow-lg shadow-indigo-500/20"
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" />
              </svg>
            </button>
          </div>
          <p className="text-[10px] text-center text-slate-600">
            Rahix AI can make mistakes. Consider checking important information.
          </p>
        </div>
      </div>
    </div>
  );
};

import React, { useRef } from 'react';
import { FileData } from '../types';
import { SUPPORTED_FILE_TYPES } from '../constants';

interface FileUploadProps {
  onFilesSelected: (files: FileData[]) => void;
  selectedFiles: FileData[];
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFilesSelected, selectedFiles }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newFiles: FileData[] = [];
    let processedCount = 0;

    files.forEach(file => {
      if (!SUPPORTED_FILE_TYPES.includes(file.type)) {
        alert(`File type ${file.type} not supported.`);
        processedCount++;
        return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        newFiles.push({
          name: file.name,
          type: file.type,
          size: file.size,
          data: base64,
          previewUrl: file.type.startsWith('image/') ? base64 : undefined
        });

        processedCount++;
        if (processedCount === files.length) {
          onFilesSelected([...selectedFiles, ...newFiles]);
          if (fileInputRef.current) fileInputRef.current.value = '';
        }
      };
      reader.readAsDataURL(file);
    });
  };

  const removeFile = (index: number) => {
    onFilesSelected(selectedFiles.filter((_, i) => i !== index));
  };

  return (
    <div className="flex items-center gap-2">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        multiple
        className="hidden"
        accept={SUPPORTED_FILE_TYPES.join(',')}
      />
      <button
        onClick={() => fileInputRef.current?.click()}
        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold transition-all border ${
          selectedFiles.length > 0 
            ? 'bg-indigo-500/10 text-indigo-400 border-indigo-500/30' 
            : 'bg-slate-800 text-slate-400 border-slate-700'
        }`}
      >
        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48" /></svg>
        {selectedFiles.length > 0 ? `${selectedFiles.length} File(s)` : 'Attach'}
      </button>

      {selectedFiles.length > 0 && (
        <div className="flex gap-1 overflow-x-auto max-w-[200px] scrollbar-hide">
          {selectedFiles.map((f, i) => (
            <div key={i} className="relative group shrink-0">
              <div className="w-6 h-6 bg-slate-800 rounded border border-slate-700 flex items-center justify-center text-[8px] text-white">
                {f.type.startsWith('image/') ? '🖼️' : '📄'}
              </div>
              <button 
                onClick={() => removeFile(i)}
                className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full flex items-center justify-center text-[6px] text-white opacity-0 group-hover:opacity-100 transition-opacity"
              >
                ✕
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { CanvasState } from '../types';
import { geminiService } from '../services/geminiService';

interface CanvasModeProps {
  state: CanvasState;
  onClose: () => void;
  onUpdateContent: (content: string) => void;
}

export const CanvasMode: React.FC<CanvasModeProps> = ({ state, onClose, onUpdateContent }) => {
  const [instruction, setInstruction] = useState('');
  const [isRefining, setIsRefining] = useState(false);

  const handleRefine = async () => {
    if (!instruction.trim()) return;
    setIsRefining(true);
    try {
      const refined = await geminiService.refineCanvasContent(state.content, instruction, state.mode);
      onUpdateContent(refined);
      setInstruction('');
    } catch (error) {
      console.error(error);
    } finally {
      setIsRefining(false);
    }
  };

