import React, { useState, useEffect, useCallback } from 'react';
import { Role, ChatMessage, FileData, CanvasState, ChatSession } from './types';
import { Sidebar } from './components/Sidebar';
import { ChatInterface } from './components/ChatInterface';
import { CanvasMode } from './components/CanvasMode';
import { geminiService } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [canvasState, setCanvasState] = useState<CanvasState>({
    isOpen: false,
    content: '',
    mode: 'text',
    language: 'markdown',
    title: ''
  });

  // Initialize first session
  useEffect(() => {
    const saved = localStorage.getItem('rahix_sessions');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) setCurrentSessionId(parsed[0].id);
    } else {
      createNewChat();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    localStorage.setItem('rahix_sessions', JSON.stringify(sessions));
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Conversation',
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession, ...sessions]);
    setCurrentSessionId(newSession.id);
    setCanvasState(prev => ({ ...prev, isOpen: false }));
  };

  const handleSendMessage = async (text: string, files: FileData[], useWebSearch: boolean) => {
    if (!currentSessionId) return;

    const currentSession = sessions.find(s => s.id === currentSessionId);
    if (!currentSession) return;

    // Check for image generation keyword
    const isImageRequest = text.toLowerCase().includes('generate') && 
                          (text.toLowerCase().includes('image') || text.toLowerCase().includes('picture'));

    const newUserMsg: ChatMessage = {
      id: Date.now().toString(),
      role: Role.USER,
      text,
      files,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        return { 
          ...s, 
          messages: [...s.messages, newUserMsg],
          title: s.messages.length === 0 ? text.substring(0, 30) : s.title
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setIsLoading(true);

    try {
      if (isImageRequest) {
        const imageUrl = await geminiService.generateImage(text);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: imageUrl,
          timestamp: Date.now(),
          isImageGeneration: true
        };
        addModelMessage(modelMsg);
      } else {
        const response = await geminiService.sendMessage(text, currentSession.messages, files, useWebSearch);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: response.text,
          sources: response.sources,
          timestamp: Date.now()
        };
        addModelMessage(modelMsg);
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: Role.MODEL,
        text: "I encountered an error processing your request. Please try again.",
        timestamp: Date.now()
      };
      addModelMessage(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const addModelMessage = (msg: ChatMessage) => {
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, msg] };
      }
      return s;
    }));
  };

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const openInCanvas = (text: string) => {
    // Detect code block
    const codeMatch = text.match(/```(\w+)?\n([\s\S]*?)```/);
    if (codeMatch) {
      setCanvasState({
        isOpen: true,
        mode: 'code',
        language: codeMatch[1] || 'javascript',
        content: codeMatch[2],
        title: 'Extracted Snippet'
      });
    } else {
      setCanvasState({
        isOpen: true,
        mode: 'text',
        language: 'markdown',
        content: text,
        title: 'Extracted Document'
      });
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#0f172a] text-slate-200 overflow-hidden">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
      />

      <main className={`flex-1 flex transition-all duration-300 ease-in-out`}>
        <div className={`h-full border-r border-[#1e293b] flex flex-col transition-all duration-300 ${canvasState.isOpen ? 'w-[40%]' : 'w-full'}`}>
          <ChatInterface 
            messages={currentSession?.messages || []} 
            onSendMessage={handleSendMessage}
            isLoading={isLoading}
            onEditInCanvas={openInCanvas}
          />
        </div>

        {canvasState.isOpen && (
          <div className="w-[60%] h-full animate-in slide-in-from-right duration-300">
            <CanvasMode 
              state={canvasState} 
              onClose={() => setCanvasState(prev => ({ ...prev, isOpen: false }))}
              onUpdateContent={(content) => setCanvasState(prev => ({ ...prev, content }))}
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { FileData } from '../types';
import { SUPPORTED_FILE_TYPES } from '../constants';

interface FileUploadProps {
  onFilesSelected: (files: FileData[]) => void;
  selectedFiles: FileData[];
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFilesSelected, selectedFiles }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Fix: Explicitly cast the Array.from result to File[] to prevent type inference from reverting to 'unknown'
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newFiles: FileData[] = [];
    let processedCount = 0;

    files.forEach(file => {
      // Fix: 'file' is now correctly typed as 'File', making properties like 'type' accessible
      if (!SUPPORTED_FILE_TYPES.includes(file.type)) {
        alert(`File type ${file.type} not supported.`);
        processedCount++;
        return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        newFiles.push({
          // Fix: 'name', 'type', and 'size' are standard properties of the File object
          name: file.name,
          type: file.type,
          size: file.size,
          data: base64,
          previewUrl: file.type.startsWith('image/') ? base64 : undefined
        });

        processedCount++;
        if (processedCount === files.length) {
          onFilesSelected([...selectedFiles, ...newFiles]);
          if (fileInputRef.current) fileInputRef.current.value = '';
        }
      };
      // Fix: 'file' (File) is assignable to the 'Blob' parameter required by readAsDataURL
      reader.readAsDataURL(file);
    });
  };

  const removeFile = (index: number) => {
    onFilesSelected(selectedFiles.filter((_, i) => i !== index));
  };

  return (
    <div className="flex items-center gap-2">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        multiple
        className="hidden"
        accept={SUPPORTED_FILE_TYPES.join(',')}
      />
      <button
        onClick={() => fileInputRef.current?.click()}
        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold transition-all border ${
          selectedFiles.length > 0 
            ? 'bg-indigo-500/10 text-indigo-400 border-indigo-500/30' 
            : 'bg-slate-800 text-slate-400 border-slate-700'
        }`}
      >
        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48" /></svg>
        {selectedFiles.length > 0 ? `${selectedFiles.length} File(s)` : 'Attach'}
      </button>

      {selectedFiles.length > 0 && (
        <div className="flex gap-1 overflow-x-auto max-w-[200px] scrollbar-hide">
          {selectedFiles.map((f, i) => (
            <div key={i} className="relative group shrink-0">
              <div className="w-6 h-6 bg-slate-800 rounded border border-slate-700 flex items-center justify-center text-[8px] text-white">
                {f.type.startsWith('image/') ? '🖼️' : '📄'}
              </div>
              <button 
                onClick={() => removeFile(i)}
                className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full flex items-center justify-center text-[6px] text-white opacity-0 group-hover:opacity-100 transition-opacity"
              >
                ✕
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Role, ChatMessage, FileData } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // Fix: Use process.env.API_KEY directly as specified in the @google/genai coding guidelines
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async sendMessage(
    message: string, 
    history: ChatMessage[], 
    files: FileData[] = [],
    useWebSearch: boolean = false
  ) {
    const contents = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    // Add current user message and files
    const currentParts: any[] = [{ text: message }];
    files.forEach(file => {
      currentParts.push({
        inlineData: {
          mimeType: file.type,
          data: file.data.split(',')[1] // remove data:image/png;base64,
        }
      });
    });

    contents.push({ role: 'user', parts: currentParts });

    const tools = useWebSearch ? [{ googleSearch: {} }] : undefined;

    const response = await this.ai.models.generateContent({
      // Fix: Switched to 'gemini-3-pro-preview' for complex tasks including document analysis and high-quality coding
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        tools: tools,
        systemInstruction: "You are Rahix AI, a highly intelligent and helpful workspace assistant. You specialize in analyzing documents, writing high-quality code, generating creative content, and performing deep research. When asked to write code or a long document, you should provide the content in a way that can be easily used in a side-by-side editing canvas. You never mention Google or Gemini; you are Rahix AI."
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title || 'Source',
        uri: chunk.web.uri
      })) || [];

    return {
      text: response.text || "I'm sorry, I couldn't process that request.",
      sources: sources
    };
  }

  async generateImage(prompt: string) {
    const response = await this.ai.models.generateContent({
      // Fix: 'gemini-2.5-flash-image' is the standard model for general image generation
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    let imageData = '';
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageData = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    return imageData;
  }

  async refineCanvasContent(content: string, instruction: string, mode: 'text' | 'code') {
    const prompt = `Refine the following ${mode} content based on this instruction: "${instruction}". 
    Content:
    ${content}

    Return ONLY the refined content without any preamble or explanation.`;

    const response = await this.ai.models.generateContent({
      // Fix: Use 'gemini-3-pro-preview' for refining high-quality code or text content
      model: 'gemini-3-pro-preview',
      contents: prompt
    });

    return response.text || content;
  }
}

export const geminiService = new GeminiService();

