import React, { useEffect, useRef, useState } from 'react';

export const RahiRobot: React.FC = () => {
  const robotRef = useRef<HTMLDivElement>(null);
  const [eyePos, setEyePos] = useState({ x: 0, y: 0 });
  const [tilt, setTilt] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!robotRef.current) return;
      const rect = robotRef.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;

      const angle = Math.atan2(e.clientY - centerY, e.clientX - centerX);
      const distance = Math.min(8, Math.hypot(e.clientX - centerX, e.clientY - centerY) / 30);

      setEyePos({
        x: Math.cos(angle) * distance,
        y: Math.sin(angle) * distance
      });

      setTilt({
        x: (e.clientX - window.innerWidth / 2) / 60,
        y: (e.clientY - window.innerHeight / 2) / 60
      });
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  return (
    <div 
      ref={robotRef}
      className="relative flex flex-col items-center justify-center animate-float select-none"
      style={{
        perspective: '1000px',
        transform: `rotateY(${tilt.x}deg) rotateX(${-tilt.y}deg)`
      }}
    >
      {/* Speech Bubble */}
      <div className="absolute -top-16 -right-12 bg-white text-slate-800 px-4 py-2 rounded-2xl text-sm font-bold shadow-xl animate-bounce">
        Hi I'm Rahul!
        <div className="absolute bottom-[-6px] left-4 w-3 h-3 bg-white rotate-45"></div>
      </div>

      {/* Head */}
      <div className="robot-head w-[180px] h-[160px] relative flex items-center justify-center z-20">
        <div className="robot-face w-[140px] h-[90px] rounded-[28px] flex items-center justify-center gap-6 overflow-hidden">
          {/* Eyes */}
          {[0, 1].map((i) => (
            <div key={i} className="w-9 h-9 bg-black rounded-full flex items-center justify-center">
              <div 
                className="w-5 h-5 bg-cyan-400 rounded-full eye-glow relative"
                style={{ transform: `translate(${eyePos.x}px, ${eyePos.y}px)` }}
              >
                <div className="absolute top-1 right-1 w-1.5 h-1.5 bg-white/80 rounded-full"></div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Neck */}
      <div className="w-12 h-6 bg-slate-400 -mt-1 z-10"></div>

      {/* Body */}
      <div className="robot-body w-[150px] h-[180px] -mt-2 relative overflow-hidden flex flex-col items-center">
        <div className="mt-8 w-[100px] h-[80px] bg-white/20 backdrop-blur-md rounded-xl border border-white/20 shadow-inner">
           <div className="w-full h-full flex items-center justify-center">
             <div className="w-2 h-2 bg-pink-500 rounded-full animate-pulse shadow-[0_0_10px_#ec4899]"></div>
           </div>
        </div>

        {/* Arms */}
        <div className="absolute left-[-25px] top-4 w-10 h-32 bg-slate-300 rounded-full rotate-[15deg] shadow-lg"></div>
        <div className="absolute right-[-25px] top-4 w-10 h-32 bg-slate-300 rounded-full rotate-[-15deg] shadow-lg"></div>
      </div>

      {/* Shadow */}
      <div className="mt-8 w-[120px] h-4 bg-black/20 blur-md rounded-full"></div>
    </div>
  );
};

import React, { useState } from 'react';
import { CanvasState } from '../types';
import { geminiService } from '../services/geminiService';

interface CanvasModeProps {
  state: CanvasState;
  onClose: () => void;
  onUpdateContent: (content: string) => void;
}

export const CanvasMode: React.FC<CanvasModeProps> = ({ state, onClose, onUpdateContent }) => {
  const [instruction, setInstruction] = useState('');
  const [isRefining, setIsRefining] = useState(false);

  const handleRefine = async () => {
    if (!instruction.trim()) return;
    setIsRefining(true);
    try {
      const refined = await geminiService.refineCanvasContent(state.content, instruction, state.mode);
      onUpdateContent(refined);
      setInstruction('');
    } catch (error) {
      console.error(error);
    } finally {
      setIsRefining(false);
    }
  };

  return (
    <div className="h-full flex flex-col bg-[#1e293b] border-l border-[#334155] shadow-2xl z-50">
      <div className="flex items-center justify-between p-4 border-b border-[#334155] bg-[#0f172a]/50">
        <div className="flex items-center gap-3">
          <div className={`p-1.5 rounded ${state.mode === 'code' ? 'bg-amber-500/10 text-amber-500' : 'bg-indigo-500/10 text-indigo-500'}`}>
            {state.mode === 'code' ? (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="16 18 22 12 16 6" /><polyline points="8 6 2 12 8 18" /></svg>
            ) : (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" /><line x1="16" y1="13" x2="8" y2="13" /><line x1="16" y1="17" x2="8" y2="17" /><polyline points="10 9 9 9 8 9" /></svg>
            )}
          </div>
          <div>
            <h2 className="text-sm font-bold text-slate-100">{state.title || 'Collaborative Canvas'}</h2>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest">{state.mode} Editing Mode</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => {
              const blob = new Blob([state.content], { type: 'text/plain' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url;
              a.download = `rahul-${state.title.replace(/\s+/g, '-').toLowerCase() || 'doc'}.txt`;
              a.click();
            }}
