          </button>
          <button onClick={onClose} className="p-2 hover:bg-[#334155] rounded text-slate-400 hover:text-white transition-colors">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col p-4 space-y-4 overflow-hidden">
        <div className="flex-1 bg-[#0f172a] border border-[#334155] rounded-xl overflow-hidden shadow-inner flex flex-col">
          <textarea
            value={state.content}
            onChange={(e) => onUpdateContent(e.target.value)}
            className={`w-full flex-1 p-6 bg-transparent text-slate-200 resize-none outline-none leading-relaxed ${state.mode === 'code' ? 'fira-code text-sm' : 'text-lg'}`}
            spellCheck={state.mode === 'text'}
          />
          <div className="bg-[#1e293b]/50 px-4 py-2 border-t border-[#334155] flex justify-between items-center">
            <span className="text-[10px] text-slate-500 font-mono">
              {state.content.length} chars | {state.content.split(/\s+/).filter(Boolean).length} words
