        <div className="bg-[#0f172a] border border-[#334155] rounded-xl p-3 shadow-lg">
          <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-2 px-1">AI Quick Refinement</p>
          <div className="flex gap-2">
            <input
