import { GoogleGenAI, Type } from "@google/genai";
import { Role, ChatMessage, FileData } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async sendMessage(
    message: string, 
    history: ChatMessage[], 
    files: FileData[] = [],
    useWebSearch: boolean = false
  ) {
    const contents = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const currentParts: any[] = [{ text: message }];
    files.forEach(file => {
      currentParts.push({
        inlineData: {
          mimeType: file.type,
          data: file.data.split(',')[1]
        }
      });
    });

    contents.push({ role: 'user', parts: currentParts });

    const tools = useWebSearch ? [{ googleSearch: {} }] : undefined;

    const rahulBio = `
      Identity: You are Rahul S (Rahul Shyam), a builder, CTO, and Full Stack Engineer based in Chennai, India. 
      Positioning: You don't just build websites — you engineer solutions. You are a second-year B.E. Civil Engineering student at Erode Sengunthar Engineering College (CGPA 8.6).
      Professional Roles:
      - CTO at a Green-Tech Infrastructure Startup (2025-Present), leading technical development for a government-funded climate-tech venture.
      - Freelance Web Developer & Builder (2024-Present).
      Technical Skills: React, Next.js, Tailwind CSS, TypeScript, Gemini AI integration, Three.js/3D Visualization, UI/UX, System Design.
      Key Projects:
      - Hostel Planner: AI interactive room designer.
      - CivilVision AI: Mobile AI tool for RCC defect identification.
      - Ecobrick: Digital twin for a climate-tech platform.
      - WebXR Shooter: Hand-tracking AR game.
      - TunnelViz: Educational tunnel engineering platform.
      Academic Engagements: Presented papers at PSG Tech, SRM, SRM Chennai, SRM IST, and SRM IST.
      Philosophy: Concepts first, logical flow mapping, and turning math into usable code.
      Contact: rahulshyam2006@outlook.com | LinkedIn: rahulshyamcivil.
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        tools: tools,
        systemInstruction: `You are the digital twin of Rahul. ${rahulBio}. Your personality is helpful, engineering-focused, and intelligent. You always speak as Rahul. When asked about yourself, use this background. When helping with code or documents, maintain high engineering standards.`
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title || 'Source',
        uri: chunk.web.uri
      })) || [];

    return {
      text: response.text || "I'm sorry, I couldn't process that request.",
      sources: sources
    };
  }

  async generateImage(prompt: string) {
    const response = await this.ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    let imageData = '';
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageData = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    return imageData;
  }

  async refineCanvasContent(content: string, instruction: string, mode: 'text' | 'code') {
    const prompt = `Refine the following ${mode} content based on this instruction: "${instruction}". 
    Content:
    ${content}

    Return ONLY the refined content without any preamble or explanation.`;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });

    return response.text || content;
  }
}

export const geminiService = new GeminiService();

