import React, { useState, useEffect } from 'react';
import { Role, ChatMessage, FileData, CanvasState, ChatSession } from './types';
import { Sidebar } from './components/Sidebar';
import { ChatInterface } from './components/ChatInterface';
import { CanvasMode } from './components/CanvasMode';
import { LandingPage } from './components/LandingPage';
import { ProfileView } from './components/ProfileView';
import { geminiService } from './services/geminiService';

type ViewMode = 'landing' | 'chat' | 'profile';

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>('landing');
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [canvasState, setCanvasState] = useState<CanvasState>({
    isOpen: false,
    content: '',
    mode: 'text',
    language: 'markdown',
    title: ''
  });

  // Initialize first session
  useEffect(() => {
    const saved = localStorage.getItem('rahix_sessions');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) {
        setCurrentSessionId(parsed[0].id);
      }
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('rahix_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Conversation',
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession, ...sessions]);
    setCurrentSessionId(newSession.id);
    setCanvasState(prev => ({ ...prev, isOpen: false }));
  };

  const handleSendMessage = async (text: string, files: FileData[], useWebSearch: boolean) => {
    if (!currentSessionId) {
      createNewChat();
      return; 
    }

    const currentSession = sessions.find(s => s.id === currentSessionId);
    if (!currentSession) return;

    const isImageRequest = text.toLowerCase().includes('generate') && 
                          (text.toLowerCase().includes('image') || text.toLowerCase().includes('picture'));

    const newUserMsg: ChatMessage = {
      id: Date.now().toString(),
      role: Role.USER,
      text,
      files,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        return { 
          ...s, 
          messages: [...s.messages, newUserMsg],
          title: s.messages.length === 0 ? text.substring(0, 30) : s.title
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setIsLoading(true);

    try {
      if (isImageRequest) {
        const imageUrl = await geminiService.generateImage(text);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: imageUrl,
          timestamp: Date.now(),
          isImageGeneration: true
        };
        addModelMessage(modelMsg);
      } else {
        const response = await geminiService.sendMessage(text, currentSession.messages, files, useWebSearch);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: response.text,
          sources: response.sources,
          timestamp: Date.now()
        };
        addModelMessage(modelMsg);
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: Role.MODEL,
        text: "I encountered an error processing your request. Please try again.",
        timestamp: Date.now()
      };
      addModelMessage(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const addModelMessage = (msg: ChatMessage) => {
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, msg] };
      }
      return s;
    }));
  };

