import { GoogleGenAI, Type } from "@google/genai";
import { Role, ChatMessage, FileData } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async sendMessage(
    message: string, 
    history: ChatMessage[], 
    files: FileData[] = [],
    useWebSearch: boolean = false
  ) {
    const contents = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const currentParts: any[] = [{ text: message }];
    files.forEach(file => {
      currentParts.push({
        inlineData: {
          mimeType: file.type,
          data: file.data.split(',')[1]
        }
      });
    });

    contents.push({ role: 'user', parts: currentParts });

    const tools = useWebSearch ? [{ googleSearch: {} }] : undefined;

    const rahixBio = `
      Identity: You are Rahix AI Pro Workspace, the intelligent digital twin of Rahul Shyam. 
      Professional Background: Rahul is a CTO and Full Stack Engineer based in Chennai. He specializes in high-performance engineering logic and climate-tech infrastructure.
      Tone: Premium, helpful, analytical, and product-focused.
      Abilities: Deep research, multi-modal analysis (images/PDFs), document generation, code refinement, and technical reasoning.
      Philosophy: Concepts first, logical flow mapping, and turning complex engineering problems into usable digital tools.
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        tools: tools,
        systemInstruction: `You are Rahix AI. ${rahixBio}. Speak with confidence. When asked to "Deep Research", explain your steps. When providing information, use citations when possible.`
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title || 'Source',
        uri: chunk.web.uri
      })) || [];

    return {
      text: response.text || "I'm sorry, I couldn't process that request.",
      sources: sources
    };
  }

  async generateImage(prompt: string) {
    const response = await this.ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    let imageData = '';
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageData = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    return imageData;
  }

  async refineCanvasContent(content: string, instruction: string, mode: 'text' | 'code' | 'presentation') {
    const prompt = `Refine this ${mode} document based on: "${instruction}". 
    Content:
    ${content}

    If mode is 'presentation', maintain a structured slide format (Slide 1: ..., Slide 2: ...).
    Return ONLY the refined content.`;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });

    return response.text || content;
  }
}

export const geminiService = new GeminiService();

