import React, { useState, useRef, useEffect } from 'react';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { RahiRobot } from './RahiRobot';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = () => {
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch);
      setInput('');
      setFiles([]);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-full relative overflow-hidden">
      {/* Background gradients for chat area */}
      <div className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] bg-indigo-600/10 blur-[120px] rounded-full -z-10 animate-pulse"></div>
      <div className="absolute bottom-[-20%] right-[-20%] w-[60%] h-[60%] bg-pink-600/10 blur-[120px] rounded-full -z-10 animate-pulse"></div>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-8 pb-48 scroll-smooth"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12">
            <div className="w-24 h-24 mb-8">
              <RahiRobot />
            </div>
            <h2 className="text-4xl font-black text-white mb-4 tracking-tight">Rahix AI Workspace</h2>
            <p className="text-slate-400 text-lg leading-relaxed">
              Synthesize complex research, engineer scalable code, or build professional documents with deep technical reasoning.
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}
          >
            <div className={`max-w-[85%] group`}>
