                  {msg.role === Role.USER ? 'U' : 'R'}
                </div>
                <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">
                  {msg.role === Role.USER ? 'You' : 'Rahix AI'}
                </span>
              </div>

              <div 
                className={`p-6 rounded-[24px] shadow-2xl relative transition-all border ${
                  msg.role === Role.USER 
                    ? 'bg-indigo-600/90 text-white rounded-tr-none border-white/10 shadow-indigo-500/10' 
                    : 'bg-white/5 backdrop-blur-xl text-slate-100 rounded-tl-none border-white/10 shadow-black/20'
                }`}
              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {msg.files.map((f, idx) => (
                      <div key={idx} className="bg-white/5 backdrop-blur-md p-3 rounded-xl flex items-center gap-3 border border-white/10 shadow-lg">
                        {f.type.startsWith('image/') ? (
                          <img src={f.previewUrl || f.data} className="w-12 h-12 object-cover rounded-lg" />
                        ) : (
                          <div className="w-12 h-12 bg-indigo-500/20 rounded-lg flex items-center justify-center text-2xl">📄</div>
                        )}
                        <div className="text-[10px] max-w-[100px]">
