                          <p className="text-slate-500">{(f.size / 1024).toFixed(1)} KB</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {msg.isImageGeneration ? (
                   <div className="space-y-4">
                      <p className="text-sm italic text-slate-400 mb-2">Prompt: "{msg.text}"</p>
                      <img src={msg.text} className="w-full rounded-2xl shadow-2xl border border-white/10 hover:scale-[1.02] transition-transform duration-500" />
                      <div className="flex gap-2">
                        <button className="text-[10px] font-bold px-4 py-2 bg-white/10 hover:bg-white/20 rounded-xl flex items-center gap-2 border border-white/10 transition-all">
