              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex gap-3 px-2 mt-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'text')}
                    className="flex items-center gap-2 px-3 py-1.5 bg-white/5 hover:bg-indigo-500/20 rounded-xl text-[10px] font-bold text-slate-500 hover:text-indigo-400 border border-white/5 transition-all"
                    title="Transfer to Workspace"
                  >
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                    Turn into Doc
                  </button>
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'presentation')}
                    className="flex items-center gap-2 px-3 py-1.5 bg-white/5 hover:bg-pink-500/20 rounded-xl text-[10px] font-bold text-slate-500 hover:text-pink-400 border border-white/5 transition-all"
