               {useDeepResearch ? 'DEEP RESEARCH ACTIVE' : 'DEEP RESEARCH'}
             </button>
             <div className="h-6 w-px bg-white/10"></div>
             <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
          </div>

          <div className="relative group">
            <textarea
