import React, { useState } from 'react';
import { CanvasState } from '../types';
import { geminiService } from '../services/geminiService';

interface CanvasModeProps {
  state: CanvasState & { mode: 'text' | 'code' | 'presentation' };
  onClose: () => void;
  onUpdateContent: (content: string) => void;
}

export const CanvasMode: React.FC<CanvasModeProps> = ({ state, onClose, onUpdateContent }) => {
  const [instruction, setInstruction] = useState('');
  const [isRefining, setIsRefining] = useState(false);
  const [currentTab, setCurrentTab] = useState<'edit' | 'preview'>('edit');

  const handleRefine = async () => {
    if (!instruction.trim()) return;
    setIsRefining(true);
    try {
      const refined = await geminiService.refineCanvasContent(state.content, instruction, state.mode);
      onUpdateContent(refined);
      setInstruction('');
    } catch (error) {
      console.error(error);
    } finally {
      setIsRefining(false);
    }
  };

  const downloadFile = (format: 'txt' | 'md' | 'pdf') => {
    // PDF generation would usually need a library like jsPDF, 
    // for this version we simulate professional export with a tailored blob.
    const content = state.mode === 'presentation' 
      ? `RAHIX AI PRESENTATION\nTITLE: ${state.title}\n------------------\n${state.content}`
      : `RAHIX AI DOCUMENT\n------------------\n${state.content}`;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `rahix-${state.title.replace(/\s+/g, '-').toLowerCase() || 'doc'}.${format}`;
    a.click();
  };

  return (
    <div className="h-full flex flex-col bg-[#0f172a] border-l border-white/5 shadow-2xl z-20 animate-in slide-in-from-right duration-500">
      <div className="flex items-center justify-between p-6 border-b border-white/5 bg-slate-900/50 backdrop-blur-xl">
        <div className="flex items-center gap-4">
          <div className={`w-10 h-10 rounded-xl flex items-center justify-center border border-white/10 ${
            state.mode === 'code' ? 'bg-amber-500/10 text-amber-500' : 
            state.mode === 'presentation' ? 'bg-pink-500/10 text-pink-500' : 'bg-indigo-500/10 text-indigo-500'
          }`}>
            {state.mode === 'code' ? (
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="16 18 22 12 16 6" /><polyline points="8 6 2 12 8 18" /></svg>
            ) : state.mode === 'presentation' ? (
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 13h18M12 13v7"/></svg>
            ) : (
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" /></svg>
            )}
          </div>
          <div>
            <h2 className="text-base font-black text-slate-100 tracking-tight">{state.title || 'Untitled Project'}</h2>
            <p className="text-[10px] text-slate-500 font-black uppercase tracking-[0.2em]">{state.mode} Mode Active</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <div className="flex bg-white/5 p-1 rounded-xl border border-white/10 mr-4">
             <button 
                onClick={() => setCurrentTab('edit')}
                className={`px-4 py-1.5 rounded-lg text-[10px] font-black transition-all ${currentTab === 'edit' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:text-white'}`}
             >
               EDITOR
             </button>
             <button 
                onClick={() => setCurrentTab('preview')}
                className={`px-4 py-1.5 rounded-lg text-[10px] font-black transition-all ${currentTab === 'preview' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:text-white'}`}
             >
               PREVIEW
             </button>
           </div>

          <button 
            onClick={() => downloadFile('pdf')}
            className="px-4 py-2 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-[10px] font-black text-slate-300 transition-all flex items-center gap-2"
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" /><polyline points="7 10 12 15 17 10" /><line x1="12" y1="15" x2="12" y2="3" /></svg>
            EXPORT PDF
          </button>
          <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-xl text-slate-500 hover:text-white transition-all">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col p-6 space-y-6 overflow-hidden">
        <div className="flex-1 glass-card border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col relative">
          {currentTab === 'edit' ? (
            <textarea
              value={state.content}
              onChange={(e) => onUpdateContent(e.target.value)}
