        <div className="bg-slate-900/60 backdrop-blur-2xl border border-white/10 rounded-[32px] p-4 shadow-2xl">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center border border-white/5">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#6366f1" strokeWidth="2.5"><path d="M12 2a10 10 0 1 0 10 10H12V2z"/><path d="M12 2a10 10 0 0 1 10 10h-10V2z"/><path d="M12 12L2.8 2.2"/><path d="M16.2 7.8l5.7 5.7"/><path d="M7.8 16.2l-5.7-5.7"/></svg>
            </div>
            <div className="flex-1 flex gap-3">
              <input
                type="text"
                value={instruction}
                onChange={(e) => setInstruction(e.target.value)}
                placeholder="Instruct Rahix to refine the document..."
                className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-5 py-3 text-sm text-slate-200 outline-none focus:border-indigo-500/50 transition-all placeholder:text-slate-600"
                onKeyPress={(e) => e.key === 'Enter' && handleRefine()}
              />
              <button
                onClick={handleRefine}
                disabled={isRefining || !instruction.trim()}
                className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white rounded-2xl px-8 py-3 text-sm font-black flex items-center gap-3 transition-all shadow-xl shadow-indigo-600/20 border border-white/10"
              >
                {isRefining ? (
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="13 17 18 12 13 7" /><polyline points="6 17 11 12 6 7" /></svg>
                )}
                REFINE
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Role, ChatMessage, FileData, CanvasState, ChatSession } from './types';
import { Sidebar } from './components/Sidebar';
import { ChatInterface } from './components/ChatInterface';
import { CanvasMode } from './components/CanvasMode';
import { LandingPage } from './components/LandingPage';
import { AboutPage } from './components/AboutPage';
import { ExpertisePage } from './components/ExpertisePage';
import { ProjectsPage } from './components/ProjectsPage';
import { geminiService } from './services/geminiService';

type ViewMode = 'landing' | 'chat' | 'about' | 'expertise' | 'projects';

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>('landing');
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [canvasState, setCanvasState] = useState<CanvasState & { mode: 'text' | 'code' | 'presentation' }>({
    isOpen: false,
    content: '',
    mode: 'text',
    language: 'markdown',
    title: ''
  });

  // Initialize first session
  useEffect(() => {
    const saved = localStorage.getItem('rahix_sessions');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) {
        setCurrentSessionId(parsed[0].id);
      }
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('rahix_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Session',
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession, ...sessions]);
    setCurrentSessionId(newSession.id);
    setCanvasState(prev => ({ ...prev, isOpen: false }));
  };

  const handleSendMessage = async (text: string, files: FileData[], useWebSearch: boolean) => {
    if (!currentSessionId) {
      createNewChat();
      return; 
    }

    const currentSession = sessions.find(s => s.id === currentSessionId);
    if (!currentSession) return;

    const isImageRequest = text.toLowerCase().includes('generate') && 
                          (text.toLowerCase().includes('image') || text.toLowerCase().includes('picture'));

    const newUserMsg: ChatMessage = {
      id: Date.now().toString(),
      role: Role.USER,
      text,
      files,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        return { 
          ...s, 
          messages: [...s.messages, newUserMsg],
          title: s.messages.length === 0 ? text.substring(0, 30) : s.title
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setIsLoading(true);

    try {
      if (isImageRequest) {
        const imageUrl = await geminiService.generateImage(text);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: imageUrl,
          timestamp: Date.now(),
          isImageGeneration: true
        };
        addModelMessage(modelMsg);
      } else {
        const response = await geminiService.sendMessage(text, currentSession.messages, files, useWebSearch);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: response.text,
          sources: response.sources,
          timestamp: Date.now()
        };
        addModelMessage(modelMsg);

        // Auto-sync logic for canvas if it looks like a document
        if (canvasState.isOpen && response.text.length > 300) {
            setCanvasState(prev => ({ ...prev, content: response.text }));
        }
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: Role.MODEL,
        text: "System interrupted. Error detected in Rahix Reasoning Engine. Please retry.",
        timestamp: Date.now()
      };
      addModelMessage(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const addModelMessage = (msg: ChatMessage) => {
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, msg] };
      }
      return s;
    }));
  };

  const openInCanvas = (text: string, mode: 'text' | 'code' | 'presentation' = 'text') => {
    const codeMatch = text.match(/```(\w+)?\n([\s\S]*?)```/);
    if (codeMatch) {
      setCanvasState({
        isOpen: true,
        mode: 'code',
        language: codeMatch[1] || 'javascript',
        content: codeMatch[2],
        title: 'Refining Snippet'
      });
    } else {
      setCanvasState({
        isOpen: true,
        mode: mode,
        language: 'markdown',
        content: text,
        title: mode === 'presentation' ? 'Pitch Deck Strategy' : 'Deep Report Analysis'
      });
    }
  };

  if (view === 'landing') {
    return <LandingPage 
      onGetStarted={() => {
        if (sessions.length === 0) createNewChat();
        setView('chat');
      }} 
      onNavigate={(v) => setView(v as ViewMode)}
    />;
  }

  if (view === 'about') return <AboutPage onBack={() => setView('landing')} />;
  if (view === 'expertise') return <ExpertisePage onBack={() => setView('landing')} />;
  if (view === 'projects') return <ProjectsPage onBack={() => setView('landing')} />;

  const currentSession = sessions.find(s => s.id === currentSessionId);

  return (
    <div className="flex h-screen w-full bg-[#0f172a] text-slate-200 overflow-hidden font-sans">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onNavigate={(v) => setView(v as ViewMode)}
      />

      <main className={`flex-1 flex transition-all duration-500 ease-in-out relative`}>
        {/* Deep ambient background for main area */}
        <div className="absolute inset-0 bg-[#0f172a] -z-20"></div>
        <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-indigo-600/5 blur-[150px] rounded-full -z-10 animate-pulse"></div>

        <div className={`h-full border-r border-white/5 flex flex-col transition-all duration-500 ${canvasState.isOpen ? 'w-[40%]' : 'w-full'}`}>
          <header className="h-16 border-b border-white/5 flex items-center px-8 justify-between shrink-0 glass-card bg-slate-900/40 backdrop-blur-xl relative z-10">
             <div className="flex items-center gap-4 cursor-pointer group" onClick={() => setView('landing')}>
               <div className="w-8 h-8 bg-indigo-500/10 rounded-xl flex items-center justify-center text-indigo-400 group-hover:bg-indigo-500 group-hover:text-white transition-all shadow-lg border border-white/5">
                 <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="15 18 9 12 15 6" /></svg>
               </div>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] group-hover:text-slate-300 transition-colors">PRO WORKSPACE</span>
             </div>
             <div className="flex items-center gap-3">
               <div className="text-[10px] font-black text-emerald-400 bg-emerald-500/10 border border-emerald-500/20 px-4 py-1.5 rounded-full uppercase tracking-widest shadow-lg">
                 Secure Link: Established
               </div>
             </div>
          </header>

          <ChatInterface 
            messages={currentSession?.messages || []} 
            onSendMessage={handleSendMessage}
            isLoading={isLoading}
            onEditInCanvas={openInCanvas}
          />
        </div>

        {canvasState.isOpen && (
          <div className="w-[60%] h-full">
            <CanvasMode 
              state={canvasState} 
              onClose={() => setCanvasState(prev => ({ ...prev, isOpen: false }))}
              onUpdateContent={(content) => setCanvasState(prev => ({ ...prev, content }))}
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
}

