            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}
          >
            <div className={`max-w-[85%] group flex flex-col ${msg.role === Role.USER ? 'items-end' : 'items-start'}`}>
              <div className={`flex items-center gap-2 mb-2 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'}`}>
                <span className="text-[10px] text-slate-500 font-black uppercase tracking-[0.2em]">
                  {msg.role === Role.USER ? 'You' : 'Rahix AI'}
                </span>
              </div>

              <div 
                className={`p-5 shadow-2xl transition-all border ${
