              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {msg.files.map((f, idx) => (
                      <div 
                        key={idx} 
                        onClick={() => f.type.startsWith('image/') && setPreviewImage(f.previewUrl || f.data)}
                        className={`bg-black/10 backdrop-blur-md p-2 rounded-xl flex items-center gap-3 border border-white/10 ${f.type.startsWith('image/') ? 'cursor-pointer hover:bg-black/20 transition-all' : ''}`}
