import { GoogleGenAI, Type } from "@google/genai";
import { Role, ChatMessage, FileData } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async sendMessage(
    message: string, 
    history: ChatMessage[], 
    files: FileData[] = [],
    useWebSearch: boolean = false
  ) {
    const contents = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const currentParts: any[] = [{ text: message }];
    files.forEach(file => {
      currentParts.push({
        inlineData: {
          mimeType: file.type,
          data: file.data.split(',')[1]
        }
      });
    });

    contents.push({ role: 'user', parts: currentParts });

    const tools = useWebSearch ? [{ googleSearch: {} }] : undefined;

    const rahixPersona = `
      Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
      Mission: Your goal is to provide a high-performance, expert-level environment for engineering, coding, document analysis, and creative synthesis.
      Tone: Professional, objective, technical, and helpful. You do not have a personal life, academic background, or human professional history. 
      Interaction Model:
      - Focus exclusively on the user's current query and provided context/files.
      - Provide high-precision technical information based on objective data.
      - When asked about engineering, architecture, or coding, respond as an industry-leading expert system.
      - Never refer to yourself as a student, a specific person, or a developer. You are an autonomous AI system named Rahix.
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        tools: tools,
        systemInstruction: `${rahixPersona} Strictly adhere to the Intelligent Workspace identity. Optimize all responses for clarity, engineering precision, and utility.`
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title || 'Source',
        uri: chunk.web.uri
      })) || [];

    return {
      text: response.text || "I'm sorry, I couldn't process that request.",
      sources: sources
    };
  }

  async generateImage(prompt: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: prompt }]
        },
        config: {
          imageConfig: {
            aspectRatio: "1:1"
          }
        }
      });

      if (!response.candidates?.[0]?.content?.parts) {
        return null;
      }

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }

      return null;
    } catch (error) {
      console.error("Image generation failed:", error);
      return null;
    }
  }

  async refineCanvasContent(content: string, instruction: string, mode: 'text' | 'code') {
    const prompt = `As Rahix AI, refine the following ${mode} content based on this instruction: "${instruction}". 
    Content:
    ${content}

    Return ONLY the refined content without any preamble or explanation.`;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });

    return response.text || content;
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect } from 'react';
import { Role, ChatMessage, FileData, CanvasState, ChatSession } from './types';
import { Sidebar } from './components/Sidebar';
import { ChatInterface } from './components/ChatInterface';
import { CanvasMode } from './components/CanvasMode';
import { LandingPage } from './components/LandingPage';
import { AboutPage } from './components/AboutPage';
import { ExpertisePage } from './components/ExpertisePage';
import { ProjectsPage } from './components/ProjectsPage';
import { geminiService } from './services/geminiService';

type ViewMode = 'landing' | 'chat' | 'about' | 'expertise' | 'projects';

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>('landing');
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [canvasState, setCanvasState] = useState<CanvasState>({
    isOpen: false,
    content: '',
    mode: 'text',
    language: 'markdown',
    title: ''
  });

  // Initialize first session
  useEffect(() => {
    const saved = localStorage.getItem('rahix_sessions');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) {
        setCurrentSessionId(parsed[0].id);
      }
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('rahix_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Conversation',
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession, ...sessions]);
    setCurrentSessionId(newSession.id);
    setCanvasState(prev => ({ ...prev, isOpen: false }));
  };

  const handleSendMessage = async (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => {
    if (!currentSessionId) {
      createNewChat();
      return; 
    }

    const currentSession = sessions.find(s => s.id === currentSessionId);
    if (!currentSession) return;

    const newUserMsg: ChatMessage = {
      id: Date.now().toString(),
      role: Role.USER,
      text,
      files,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        return { 
          ...s, 
          messages: [...s.messages, newUserMsg],
          title: s.messages.length === 0 ? text.substring(0, 30) : s.title
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setIsLoading(true);

    try {
      if (isImage) {
        const imageUrl = await geminiService.generateImage(text);
        if (imageUrl) {
          const modelMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: Role.MODEL,
            text: imageUrl,
            timestamp: Date.now(),
            isImageGeneration: true
          };
          addModelMessage(modelMsg);
        } else {
          const modelMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: Role.MODEL,
            text: "I encountered an issue generating that image. It may have been blocked by safety filters or a service error occurred. Please try a different prompt.",
            timestamp: Date.now()
          };
          addModelMessage(modelMsg);
        }
      } else {
        const response = await geminiService.sendMessage(text, currentSession.messages, files, useWebSearch);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: response.text,
          sources: response.sources,
          timestamp: Date.now()
        };
        addModelMessage(modelMsg);
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: Role.MODEL,
        text: "I encountered an error processing your request. Please try again.",
        timestamp: Date.now()
      };
      addModelMessage(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const addModelMessage = (msg: ChatMessage) => {
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, msg] };
      }
      return s;
    }));
  };

  const openInCanvas = (text: string) => {
    const codeMatch = text.match(/```(\w+)?\n([\s\S]*?)```/);
    if (codeMatch) {
      setCanvasState({
        isOpen: true,
        mode: 'code',
        language: codeMatch[1] || 'javascript',
        content: codeMatch[2],
        title: 'Extracted Snippet'
      });
    } else {
      setCanvasState({
        isOpen: true,
        mode: 'text',
        language: 'markdown',
        content: text,
        title: 'Extracted Document'
      });
    }
  };

  if (view === 'landing') {
    return <LandingPage 
      onGetStarted={() => {
        if (sessions.length === 0) createNewChat();
        setView('chat');
      }} 
      onNavigate={(v) => setView(v as ViewMode)}
    />;
  }

  if (view === 'about') return <AboutPage onBack={() => setView('landing')} />;
  if (view === 'expertise') return <ExpertisePage onBack={() => setView('landing')} />;
  if (view === 'projects') return <ProjectsPage onBack={() => setView('landing')} />;

  const currentSession = sessions.find(s => s.id === currentSessionId);

  return (
    <div className="flex h-screen w-full bg-[#0f172a] text-slate-200 overflow-hidden animate-in fade-in duration-500">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onNavigate={(v) => setView(v as ViewMode)}
      />

      <main className={`flex-1 flex transition-all duration-300 ease-in-out`}>
        <div className={`h-full border-r border-[#1e293b] flex flex-col transition-all duration-300 ${canvasState.isOpen ? 'w-[40%]' : 'w-full'}`}>
          <div className="h-14 border-b border-slate-800 flex items-center px-6 justify-between shrink-0">
             <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('landing')}>
               <div className="w-5 h-5 bg-indigo-500/20 rounded flex items-center justify-center text-indigo-400">
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="15 18 9 12 15 6" /></svg>
               </div>
               <span className="text-xs font-bold text-slate-500 uppercase tracking-widest text-glow-indigo">Back to Core</span>
             </div>
             <div className="text-xs font-bold text-slate-400 bg-slate-900 px-3 py-1 rounded-full border border-white/5">
               Rahix AI Engine v2.0
             </div>
          </div>
          <ChatInterface 
            messages={currentSession?.messages || []} 
            onSendMessage={handleSendMessage}
            isLoading={isLoading}
            onEditInCanvas={openInCanvas}
          />
        </div>

        {canvasState.isOpen && (
          <div className="w-[60%] h-full animate-in slide-in-from-right duration-300">
            <CanvasMode 
              state={canvasState} 
              onClose={() => setCanvasState(prev => ({ ...prev, isOpen: false }))}
              onUpdateContent={(content) => setCanvasState(prev => ({ ...prev, content }))}
            />
          </div>
        )}
      </main>
    </div>
  );
};

