When the chatbot is thinking the loading part is kind of bland, so i want to change it to something better, use this code for reference:
Here's a comprehensive, production-ready AI chatbot loading component collection in TypeScript/React with stunning visual effects:

```tsx
import React, { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

// Utility for random range
const random = (min: number, max: number) => Math.random() * (max - min) + min;

// ═══════════════════════════════════════════════════════════════════════════════
// 1. MATRIX RAIN LOADER - Cyberpunk code streaming effect
// ═══════════════════════════════════════════════════════════════════════════════

interface MatrixColumnProps {
  x: number;
  delay: number;
  speed: number;
}

const MatrixColumn: React.FC<MatrixColumnProps> = ({ x, delay, speed }) => {
  const chars = "アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワヲン0123456789ABCDEF<>{}[];:\\|";
  const [drops, setDrops] = useState<string[]>([]);

  useEffect(() => {
    const interval = setInterval(() => {
      setDrops(prev => {
        const newChar = chars[Math.floor(Math.random() * chars.length)];
        const newDrops = [newChar, ...prev.slice(0, 15)];
        return newDrops;
      });
    }, speed);
    return () => clearInterval(interval);
  }, [speed]);

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ delay: delay * 0.1 }}
      className="absolute top-0 text-green-400 text-xs font-mono leading-none pointer-events-none"
      style={{ 
        left: `${x}%`, 
        textShadow: '0 0 8px rgba(74, 222, 128, 0.8)',
        filter: 'blur(0.3px)'
      }}
    >
      {drops.map((char, i) => (
        <motion.div
          key={i}
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: i === 0 ? 1 : 0.8 - (i * 0.05), x: 0 }}
          className={i === 0 ? 'text-white font-bold text-sm' : ''}
        >
          {char}
        </motion.div>
      ))}
    </motion.div>
  );
};

export const MatrixLoader: React.FC = () => {
  const columns = Array.from({ length: 20 }, (_, i) => ({
    x: (i / 20) * 100,
    delay: i % 5,
    speed: random(50, 150)
  }));

  return (
    <div className="relative w-full h-64 bg-black/90 overflow-hidden rounded-xl border border-green-500/30 shadow-[0_0_30px_rgba(74,222,128,0.2)]">
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-green-500/5 to-transparent" />
      {columns.map((col, i) => (
        <MatrixColumn key={i} {...col} />
      ))}
      <div className="absolute inset-0 flex items-center justify-center">
        <motion.div 
          animate={{ opacity: [0.5, 1, 0.5] }}
          transition={{ duration: 2, repeat: Infinity }}
          className="text-green-400 font-mono text-lg tracking-widest bg-black/80 px-6 py-3 rounded-full border border-green-500/50 backdrop-blur-sm"
        >
          Initializing Neural Network...
        </motion.div>
      </div>
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════════════
// 2. QUANTUM CORE LOADER - Orbiting particles with gravitational pull
// ═══════════════════════════════════════════════════════════════════════════════

export const QuantumLoader: React.FC = () => {
  const particles = Array.from({ length: 12 }, (_, i) => ({
    id: i,
    angle: (i / 12) * 360,
    radius: random(40, 80),
    speed: random(3, 8),
    size: random(2, 6)
  }));

  return (
    <div className="relative w-64 h-64 flex items-center justify-center">
      {/* Central Core */}
      <motion.div
        animate={{ 
          scale: [1, 1.2, 1],
          boxShadow: [
            '0 0 20px rgba(139, 92, 246, 0.5)',
            '0 0 60px rgba(139, 92, 246, 0.8)',
            '0 0 20px rgba(139, 92, 246, 0.5)'
          ]
        }}
        transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
        className="absolute w-16 h-16 bg-gradient-to-br from-violet-400 to-fuchsia-600 rounded-full blur-sm"
      />
      <div className="absolute w-12 h-12 bg-white rounded-full shadow-[0_0_40px_rgba(255,255,255,0.5)]" />

      {/* Orbiting Particles */}
      {particles.map((p) => (
        <motion.div
          key={p.id}
          animate={{ rotate: 360 }}
          transition={{ 
            duration: p.speed, 
            repeat: Infinity, 
            ease: "linear" 
          }}
          className="absolute w-full h-full"
          style={{ rotate: p.angle }}
        >
          <motion.div
            animate={{ 
              scale: [1, 1.5, 1],
              opacity: [0.4, 1, 0.4]
            }}
            transition={{ 
              duration: p.speed * 0.3, 
              repeat: Infinity,
              ease: "easeInOut"
            }}
            className="absolute bg-gradient-to-r from-cyan-400 to-blue-500 rounded-full shadow-lg"
            style={{ 
              width: p.size, 
              height: p.size, 
              top: `calc(50% - ${p.radius}px)`,
              left: '50%',
              transform: 'translateX(-50%)',
              boxShadow: `0 0 ${p.size * 2}px rgba(6, 182, 212, 0.6)`
            }}
          />
        </motion.div>
      ))}

      {/* Connecting Lines SVG */}
      <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-30">
        <defs>
          <linearGradient id="lineGrad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#8b5cf6" stopOpacity="0" />
            <stop offset="50%" stopColor="#06b6d4" stopOpacity="1" />
            <stop offset="100%" stopColor="#8b5cf6" stopOpacity="0" />
          </linearGradient>
        </defs>
        <motion.circle
          cx="50%"
          cy="50%"
          r="60"
          fill="none"
          stroke="url(#lineGrad)"
          strokeWidth="0.5"
          strokeDasharray="10 10"
          animate={{ rotate: -360 }}
          transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
        />
      </svg>

      <div className="absolute -bottom-12 text-violet-300 font-medium tracking-wider text-sm">
        Synthesizing Response...
      </div>
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════════════
// 3. SYNTAX FLOW LOADER - Animated code brackets and typing syntax
// ═══════════════════════════════════════════════════════════════════════════════

export const SyntaxLoader: React.FC = () => {
  const [step, setStep] = useState(0);
  const snippets = [
    { text: 'const', color: 'text-purple-400', delay: 0 },
    { text: 'AI', color: 'text-blue-400', delay: 0.1 },
    { text: '=', color: 'text-white', delay: 0.2 },
    { text: 'new', color: 'text-purple-400', delay: 0.3 },
    { text: 'Intelligence', color: 'text-yellow-400', delay: 0.4 },
    { text: '()', color: 'text-white', delay: 0.5 },
    { text: '=>', color: 'text-pink-400', delay: 0.6 },
    { text: '{', color: 'text-white', delay: 0.7 },
    { text: 'learn', color: 'text-green-400', delay: 0.8 },
    { text: '()', color: 'text-white', delay: 0.9 },
    { text: '}', color: 'text-white', delay: 1.0 }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setStep((prev) => (prev + 1) % (snippets.length + 3));
    }, 200);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="bg-gray-900/90 p-8 rounded-2xl border border-gray-700 shadow-2xl min-w-[320px]">
      <div className="flex items-center gap-2 mb-6 border-b border-gray-700 pb-3">
        <div className="w-3 h-3 rounded-full bg-red-500" />
        <div className="w-3 h-3 rounded-full bg-yellow-500" />
        <div className="w-3 h-3 rounded-full bg-green-500" />
        <div className="ml-auto text-xs text-gray-500 font-mono">processing.js</div>
      </div>

      <div className="font-mono text-lg flex flex-wrap gap-1 items-center h-20">
        {snippets.map((snippet, i) => (
          <AnimatePresence key={i}>
            {step >= i && (
              <motion.span
                initial={{ opacity: 0, y: 10, filter: 'blur(10px)' }}
                animate={{ opacity: 1, y: 0, filter: 'blur(0px)' }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3, ease: "easeOut" }}
                className={snippet.color}
              >
                {snippet.text}
              </motion.span>
            )}
          </AnimatePresence>
        ))}
        <motion.span
          animate={{ opacity: [0, 1, 0] }}
          transition={{ duration: 0.8, repeat: Infinity }}
          className="w-2 h-5 bg-blue-400 ml-1 inline-block align-middle"
        />
      </div>

      <div className="mt-4 flex items-center gap-2">
        <div className="flex-1 h-1 bg-gray-800 rounded-full overflow-hidden">
          <motion.div 
            className="h-full bg-gradient-to-r from-purple-500 to-blue-500"
            animate={{ width: ["0%", "100%", "0%"] }}
            transition={{ duration: 3, repeat: Infinity, ease: "easeInOut" }}
          />
        </div>
