                    className={`p-2 rounded-lg transition-all ${copiedId === msg.id ? 'bg-emerald-500/20 text-emerald-400' : 'hover:bg-slate-800 text-slate-500 hover:text-slate-200'}`}
                    title={copiedId === msg.id ? "Copied!" : "Copy to Clipboard"}
                  >
                    {copiedId === msg.id ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    ) : (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                    )}
                  </button>
                  <div className="w-px h-3 bg-white/5 mx-1"></div>
                  <button className="p-2 hover:bg-emerald-500/10 rounded-lg text-slate-500 hover:text-emerald-400 transition-all">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M14 9V5a2 2 0 0 1 2-2l2 2v4h1a2 2 0 0 1 2 2v10a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V11a2 2 0 0 1 2-2h10z" /></svg>
                  </button>
                  <button className="p-2 hover:bg-rose-500/10 rounded-lg text-slate-500 hover:text-rose-400 transition-all">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M10 15V9a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v10a2 2 0 0 0 2 2h1a2 2 0 0 0 2-2v-4h10a2 2 0 0 0 2-2V5a2 2 0 0 0-2-2l-2 2v4H10z" /></svg>
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-500 gap-3 items-center">
            <RahiEye size="w-8 h-8" animating={true} />
            <div className="ai-bubble p-4 pr-8 flex items-center gap-6 border border-white/5 min-w-[200px]">
              <div className="shrink-0 scale-50 -ml-4 -mr-4">
                <QuantumLoader />
              </div>
              <div className="flex flex-col gap-1">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] whitespace-nowrap">Rahix Processing</span>
                <span className="text-[9px] text-slate-500 font-medium italic">Synthesizing neural workspace...</span>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Input Section - Refined Glassmorphic Pill */}
      <div className="absolute bottom-0 left-0 right-0 p-8 pt-0">
        <div className="max-w-4xl mx-auto relative">
          <div className="glass-card rounded-[40px] shadow-2xl border border-white/10 p-2 flex flex-col gap-2">

            {/* Action Bar inside pill */}
            <div className="flex items-center gap-2 px-4 pt-1">
               <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
               <div className="h-4 w-px bg-white/10 mx-1"></div>
               <button 
                  onClick={() => setUseDeepResearch(!useDeepResearch)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    useDeepResearch 
                      ? 'bg-indigo-600 text-white border-white/20 shadow-[0_0_15px_rgba(99,102,241,0.4)]' 
                      : 'bg-white/5 text-slate-400 border-white/5 hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>
                 DEEP RESEARCH
               </button>
               <button 
                  onClick={() => setIsImageMode(!isImageMode)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    isImageMode 
                      ? 'bg-pink-600 text-white border-white/20 shadow-[0_0_15px_rgba(236,72,153,0.4)]' 
                      : 'bg-white/5 text-slate-400 border-white/5 hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>
                 IMAGE MODE
               </button>
            </div>

            {/* Input area */}
            <div className="relative flex items-center">
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                disabled={isRateLimited}
                placeholder={isRateLimited ? `Rate limit reached. Resetting in ${rpmResetSeconds}s...` : isImageMode ? "Describe the vision you want to generate..." : "Message Rahix AI..."}
                className={`w-full bg-transparent text-slate-100 rounded-[32px] py-4 pl-6 pr-16 resize-none min-h-[64px] max-h-[200px] transition-all outline-none text-[15px] font-medium ${isRateLimited ? 'opacity-50 cursor-not-allowed' : ''}`}
                rows={1}
              />
              <button
                onClick={handleSend}
                disabled={isLoading || isRateLimited || (!input.trim() && files.length === 0)}
                className={`absolute right-3 p-3 text-white rounded-full transition-all shadow-xl ${
                  isRateLimited 
                    ? 'bg-slate-700 cursor-not-allowed' 
                    : isImageMode 
                      ? 'bg-pink-600 hover:bg-pink-500 shadow-pink-500/20' 
                      : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/20'
                }`}
              >
                {isRateLimited ? (
                  <span className="text-[10px] font-bold">{rpmResetSeconds}s</span>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                    <line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <div className="flex justify-center mt-3">
             <p className="text-[9px] text-slate-600 font-black uppercase tracking-[0.4em] flex items-center gap-3">
                <span>Rahix AI Pro Workspace</span>
                <span className="w-1 h-1 rounded-full bg-slate-700"></span>
                <span>Optimized Engine</span>
             </p>
          </div>
        </div>
      </div>
    </div>
  );
};

{
  "name": "Rahul AI - Your Intelligent Workspace",
  "description": "A multi-modal AI assistant featuring chat, file analysis, web search, image generation, and a collaborative Canvas Mode for document and code editing.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

interface VoiceInterfaceProps {
  isOpen: boolean;
  onClose: () => void;
  persona: string;
}

export const VoiceInterface: React.FC<VoiceInterfaceProps> = ({ isOpen, onClose, persona }) => {
  const [isActive, setIsActive] = useState(false);
  const [transcription, setTranscription] = useState('');
  const [aiTranscription, setAiTranscription] = useState('');
  const [status, setStatus] = useState<'idle' | 'connecting' | 'listening' | 'speaking'>('idle');

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // PCM Encoding/Decoding Helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const startSession = async () => {
    setStatus('connecting');
    try {
      const ai = new GoogleGenAI({ apiKey: (process.env.API_KEY as string) });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setStatus('listening');
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              setAiTranscription(prev => prev + message.serverContent!.outputTranscription!.text);
              setStatus('speaking');
            }
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => prev + message.serverContent!.inputTranscription!.text);
              setAiTranscription(''); // Clear AI transcription when user starts talking
            }
            if (message.serverContent?.turnComplete) {
              setStatus('listening');
              setTranscription('');
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputContextRef.current.currentTime);
              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, 24000, 1);
              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputContextRef.current.destination);
              source.onended = () => sourcesRef.current.delete(source);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setStatus('listening');
            }
          },
          onclose: () => handleClose(),
          onerror: (e) => {
            console.error("Live Error:", e);
            handleClose();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: persona,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } }
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Voice initialization failed:", err);
      handleClose();
    }
  };

  const handleClose = () => {
    setIsActive(false);
    setStatus('idle');
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (sessionRef.current) sessionRef.current.close();
    onClose();
  };

  useEffect(() => {
    if (isOpen) startSession();
    return () => handleClose();
  }, [isOpen]);

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[200] flex items-center justify-center bg-[#0a0a0f]/95 backdrop-blur-3xl p-6"
        >
          <div className="max-w-xl w-full flex flex-col items-center gap-12 text-center">
            {/* Pulsing Visualizer */}
            <div className="relative w-64 h-64 flex items-center justify-center">
              {[...Array(3)].map((_, i) => (
                <motion.div
                  key={i}
                  animate={{ 
                    scale: [1, 1.5 + (i * 0.2), 1],
                    opacity: [0.5, 0, 0.5],
                    borderWidth: [2, 1, 2]
                  }}
                  transition={{ 
                    duration: 3, 
                    repeat: Infinity, 
                    delay: i * 0.8,
                    ease: "easeInOut"
                  }}
                  className={`absolute inset-0 rounded-full border-2 ${
                    status === 'speaking' ? 'border-pink-500/50' : 'border-indigo-500/50'
                  }`}
                />
              ))}
              <div className={`relative z-10 w-24 h-24 rounded-full flex items-center justify-center shadow-2xl transition-all duration-500 ${
                status === 'speaking' ? 'bg-pink-600 shadow-pink-500/40 scale-110' : 'bg-indigo-600 shadow-indigo-500/40'
              }`}>
                <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5">
                  <path d="M12 1v11M12 23V12M19 8l-7 4-7-4M19 16l-7-4-7 4" />
                </svg>
              </div>
            </div>

            <div className="space-y-4 w-full">
              <h2 className="text-2xl font-black text-white tracking-tight uppercase">
                {status === 'connecting' ? 'Initializing Neural Link' : 
                 status === 'listening' ? 'Rahix is Listening' : 
                 status === 'speaking' ? 'Rahix is Speaking' : 'Voice Mode Ready'}
              </h2>
              <div className="min-h-[60px] flex flex-col justify-center items-center">
                {transcription && (
                  <motion.p 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="text-indigo-300 font-medium italic text-lg"
                  >
                    "{transcription}"
                  </motion.p>
                )}
                {aiTranscription && (
                  <motion.p 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="text-pink-300 font-bold text-xl"
                  >
                    {aiTranscription}
                  </motion.p>
                )}
              </div>
            </div>

            <div className="flex items-center gap-4">
              <button 
                onClick={handleClose}
                className="px-8 py-3 bg-white/5 hover:bg-white/10 text-white rounded-full font-black text-xs tracking-widest border border-white/10 transition-all uppercase"
              >
                Terminate Session
              </button>
            </div>

            <p className="text-[9px] text-slate-600 font-black uppercase tracking-[0.4em]">
