import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mic, MicOff, Volume2, Brain, Sparkles } from 'lucide-react';

type AudioState = 'idle' | 'listening' | 'speaking' | 'off';

interface AudioVisualizerProps {
  state: AudioState;
  audioData?: number[];
}

// Simulated audio data generator for demo purposes
const useSimulatedAudio = (state: AudioState) => {
  const [audioData, setAudioData] = useState<number[]>(new Array(64).fill(0));

  useEffect(() => {
    if (state === 'off' || state === 'idle') {
      setAudioData(new Array(64).fill(0));
      return;
    }

    const interval = setInterval(() => {
      setAudioData(prev => 
        prev.map(() => {
          if (state === 'listening') {
            // Irregular pattern for voice input (human speech)
            return Math.random() * 0.7 + 0.1;
          } else if (state === 'speaking') {
            // More rhythmic pattern for AI voice
            return Math.random() * 0.9 + 0.2;
          }
          return 0;
        })
      );
    }, 50);

    return () => clearInterval(interval);
  }, [state]);

  return audioData;
};

// Waveform Bar Component
const WaveBar: React.FC<{ height: number; delay: number; color: string }> = ({ 
  height, 
  delay, 
  color 
}) => (
  <motion.div
    className={`w-1 rounded-full ${color}`}
    initial={{ height: 4 }}
    animate={{ 
      height: Math.max(4, height * 120),
      opacity: height > 0.1 ? 1 : 0.3
    }}
    transition={{ 
      type: "spring",
      stiffness: 300,
      damping: 20,
      delay: delay * 0.01
    }}
    style={{
      boxShadow: height > 0.5 ? `0 0 20px ${color.includes('green') ? '#4ade80' : '#a78bfa'}` : 'none'
    }}
  />
);

// Circular Ripple Effect
const Ripple: React.FC<{ delay: number; isListening: boolean; color: string }> = ({ 
  delay, 
  isListening,
  color 
}) => (
  <motion.div
    className={`absolute rounded-full border-2 ${color} opacity-0`}
    initial={{ width: 80, height: 80, opacity: 0 }}
    animate={isListening ? {
      width: [80, 300],
      height: [80, 300],
      opacity: [0.8, 0],
      borderWidth: [2, 0]
    } : {
      width: 80,
      height: 80,
      opacity: 0
    }}
    transition={{
      duration: 2,
      repeat: Infinity,
      delay: delay * 0.4,
      ease: "easeOut"
    }}
  />
);

// Particle System for Speaking State
const Particle: React.FC<{ angle: number }> = ({ angle }) => (
  <motion.div
    className="absolute w-1 h-1 bg-purple-400 rounded-full"
    style={{
      left: '50%',
