export const VoiceInterface: React.FC<VoiceInterfaceProps> = ({ isOpen, onClose, persona }) => {
  const [status, setStatus] = useState<AudioState>('idle');
  const [transcription, setTranscription] = useState('');
  const [aiTranscription, setAiTranscription] = useState('');
  const [volumeData, setVolumeData] = useState<number[]>(new Array(32).fill(0));

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // PCM Helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  // UI Volume Simulation/Calculation
  const updateVolume = (data: Float32Array) => {
    let sum = 0;
    for (let i = 0; i < data.length; i++) sum += data[i] * data[i];
    const rms = Math.sqrt(sum / data.length);
    const normalized = Math.min(rms * 5, 1);

    setVolumeData(prev => {
      const next = [...prev];
      next.shift();
      next.push(normalized);
      return next;
    });
  };

  const startSession = async () => {
    setStatus('connecting');
    try {
      const ai = new GoogleGenAI({ apiKey: (process.env.API_KEY as string) });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('listening');
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              updateVolume(inputData);

              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;

              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => session && session.sendRealtimeInput({ media: pcmBlob })).catch(() => {});
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              setAiTranscription(prev => prev + message.serverContent!.outputTranscription!.text);
              setStatus('speaking');
            }
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => prev + message.serverContent!.inputTranscription!.text);
              setAiTranscription('');
              setStatus('listening');
            }
            if (message.serverContent?.turnComplete) {
              setStatus('listening');
              setTranscription('');
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current && outputContextRef.current.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputContextRef.current.currentTime);
              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, 24000, 1);

              // Simulate volume from output for bars
              updateVolume(buffer.getChannelData(0));

              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputContextRef.current.destination);
              source.onended = () => sourcesRef.current.delete(source);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setStatus('listening');
            }
          },
          onclose: () => handleClose(),
          onerror: () => handleClose()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: persona,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } }
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      handleClose();
    }
  };

  const handleClose = () => {
    setStatus('idle');
    if (audioContextRef.current?.state !== 'closed') audioContextRef.current?.close().catch(() => {});
    if (outputContextRef.current?.state !== 'closed') outputContextRef.current?.close().catch(() => {});
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    onClose();
  };

  useEffect(() => {
    if (isOpen) startSession();
    return () => handleClose();
  }, [isOpen]);

  const getStatusColor = () => {
    if (status === 'listening') return 'emerald-500';
    if (status === 'speaking') return 'indigo-500';
    return 'slate-500';
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[200] flex items-center justify-center bg-[#050508]/98 backdrop-blur-3xl"
        >
          {/* Background Ambient Glow */}
          <div className={`absolute inset-0 opacity-20 transition-colors duration-1000 ${
            status === 'listening' ? 'bg-emerald-600/10' : 
            status === 'speaking' ? 'bg-indigo-600/10' : 'bg-slate-900'
          }`} />

          <div className="relative max-w-2xl w-full h-full flex flex-col items-center justify-center p-8 gap-12 text-center overflow-hidden">

            {/* Visualizer Container */}
            <div className="relative w-80 h-80 flex items-center justify-center">

              {/* Ripple Effects for Listening */}
              {status === 'listening' && (
                <>
                  <Ripple delay={0} color="border-emerald-500/40" />
                  <Ripple delay={1} color="border-emerald-500/40" />
                </>
              )}

              {/* Particles for Speaking */}
              {status === 'speaking' && (
                <>
                  {[...Array(12)].map((_, i) => (
                    <Particle key={i} angle={i * 30} />
                  ))}
                </>
              )}

              {/* Center Mic Button - Reactive Glow */}
              <motion.div 
                animate={status !== 'connecting' ? {
                  scale: status === 'listening' ? [1, 1.05, 1] : 1,
                  boxShadow: status === 'listening' 
                    ? '0 0 60px rgba(16, 185, 129, 0.4)' 
                    : status === 'speaking' 
                    ? '0 0 60px rgba(99, 102, 241, 0.4)' 
                    : '0 0 20px rgba(255, 255, 255, 0.05)'
                } : {}}
                transition={{ duration: 1.5, repeat: Infinity }}
                className={`relative z-20 w-32 h-32 rounded-full flex items-center justify-center border border-white/10 transition-colors duration-500 ${
                  status === 'listening' ? 'bg-emerald-600' : 
                  status === 'speaking' ? 'bg-indigo-600' : 
                  'bg-slate-800'
                }`}
              >
                <div className="text-white">
                  {status === 'speaking' ? (
                    <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                      <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5" />
                      <path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07" />
                    </svg>
                  ) : (
                    <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                      <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
                      <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
                      <line x1="12" y1="19" x2="12" y2="23" />
                      <line x1="8" y1="23" x2="16" y2="23" />
                    </svg>
                  )}
                </div>
              </motion.div>
            </div>

            {/* Waveform Bars */}
            <div className="flex items-center justify-center gap-1.5 h-24">
              {volumeData.map((v, i) => (
                <WaveBar 
                  key={i} 
                  height={v} 
                  delay={i} 
                  color={status === 'listening' ? 'bg-emerald-400' : 'bg-indigo-400'} 
                />
              ))}
            </div>

            {/* Dynamic Status Display */}
            <div className="space-y-6 w-full max-w-md">
              <motion.div 
                animate={{ opacity: [0.6, 1, 0.6] }}
                transition={{ duration: 2, repeat: Infinity }}
                className={`text-sm font-black uppercase tracking-[0.4em] ${
                  status === 'listening' ? 'text-emerald-400' : 
                  status === 'speaking' ? 'text-indigo-400' : 'text-slate-500'
                }`}
              >
                {status === 'connecting' ? 'Establishing Neural Link' : 
                 status === 'listening' ? 'Rahix System Listening' : 
                 status === 'speaking' ? 'Rahix Neural Response' : 'Standby Mode'}
              </motion.div>

              <div className="min-h-[80px] flex flex-col justify-center items-center gap-2">
                <AnimatePresence mode="wait">
                  {transcription && (
                    <motion.p 
                      key="usr"
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0 }}
                      className="text-slate-300 font-medium italic text-lg line-clamp-2"
                    >
                      "{transcription}"
                    </motion.p>
                  )}
                  {aiTranscription && (
                    <motion.p 
                      key="ai"
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0 }}
                      className="text-white font-bold text-xl line-clamp-2 leading-tight"
                    >
                      {aiTranscription}
                    </motion.p>
                  )}
                </AnimatePresence>
              </div>
            </div>

            {/* Controls */}
            <div className="flex flex-col items-center gap-4">
              <button 
                onClick={handleClose}
                className="group relative px-10 py-4 bg-white/5 hover:bg-white/10 text-white rounded-full font-black text-xs tracking-widest border border-white/10 transition-all uppercase overflow-hidden"
              >
                <div className="relative z-10 flex items-center gap-2">
                  <span className="w-1.5 h-1.5 rounded-full bg-rose-500 animate-pulse"></span>
                  Terminate Session
                </div>
              </button>
              <p className="text-[10px] text-slate-600 font-bold uppercase tracking-[0.3em]">
                Secure End-to-End Neural Encryption Active
              </p>
            </div>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { QuantumLoader } from './AILoader';
import { VoiceInterface } from './VoiceInterface';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
  rpmCount: number;
  rpmLimit: number;
  rpmResetSeconds: number;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas,
  rpmCount,
  rpmLimit,
  rpmResetSeconds
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [showRateAlert, setShowRateAlert] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const baseInputRef = useRef<string>(''); // Stores text present before mic started

  const rahixPersona = `
    Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
    Mission: Provide expert-level environment for engineering, coding, and technical analysis.
    Tone: Professional, objective, and expert system.
    Language Policy: You are a native speaker of all languages. Always detect the language of the user's input and respond fluently and naturally in that EXACT same language.
  `;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  useEffect(() => {
    if (rpmCount === 50 && !showRateAlert) {
      setShowRateAlert(true);
      setTimeout(() => setShowRateAlert(false), 5000);
    }
  }, [rpmCount]);

  // Speech Recognition Setup
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let sessionTranscript = '';
        for (let i = 0; i < event.results.length; i++) {
          sessionTranscript += event.results[i][0].transcript;
        }

        // Dynamic "Audio Typing" effect
        const finalOutput = baseInputRef.current + (baseInputRef.current && !baseInputRef.current.endsWith(' ') ? ' ' : '') + sessionTranscript;
        setInput(finalOutput);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('Speech recognition error:', event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      // Capture what was already typed to append speech correctly
      baseInputRef.current = input.trim();
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (isListening) recognitionRef.current?.stop();
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const handleDownloadImage = async (e: React.MouseEvent, dataUrl: string, id: string) => {
    e.stopPropagation();
    try {
      let blob: Blob;
      if (dataUrl.startsWith('data:')) {
        const parts = dataUrl.split(';base64,');
        const contentType = parts[0].split(':')[1];
        const raw = window.atob(parts[1]);
        const rawLength = raw.length;
        const uInt8Array = new Uint8Array(rawLength);
        for (let i = 0; i < rawLength; ++i) {
          uInt8Array[i] = raw.charCodeAt(i);
        }
        blob = new Blob([uInt8Array], { type: contentType });
      } else {
        const response = await fetch(dataUrl);
        blob = await response.blob();
      }
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `rahul-ai-gen-${id.substring(0, 5)}.png`;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        window.URL.revokeObjectURL(blobUrl);
      }, 200);
    } catch (err) {
      console.error("Download failed:", err);
      window.open(dataUrl, '_blank');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const RahiEye = ({ animating = false, size = "w-6 h-6" }) => (
    <div className={`relative ${size} flex items-center justify-center ${animating ? 'animate-pulse' : ''}`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <circle cx="50" cy="50" r="45" fill="#1e293b" stroke="#334155" strokeWidth="5" />
        <circle cx="50" cy="50" r="20" fill="#22d3ee" className={animating ? "animate-ping" : ""}>
          <animate attributeName="opacity" values="0.4;1;0.4" dur="2s" repeatCount="indefinite" />
        </circle>
        <circle cx="50" cy="50" r="10" fill="white" />
      </svg>
    </div>
  );

  const isRateLimited = rpmCount >= rpmLimit;

  return (
    <div className="flex flex-col h-full relative overflow-hidden bg-transparent text-slate-200">
      <VoiceInterface 
        isOpen={isVoiceOpen} 
        onClose={() => setIsVoiceOpen(false)} 
        persona={rahixPersona} 
      />

      {/* Rate Limit Toast */}
      {showRateAlert && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="bg-amber-600/20 backdrop-blur-xl border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-2xl">
            <div className="w-2 h-2 rounded-full bg-amber-500 animate-ping"></div>
            <p className="text-xs font-bold text-amber-200 uppercase tracking-widest">Approaching Rahix AI rate limits</p>
          </div>
        </div>
      )}

      {/* Image Preview Modal */}
      {previewImage && (
        <div 
          className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 md:p-12 animate-in fade-in duration-300"
          onClick={() => setPreviewImage(null)}
        >
          <button 
            className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center bg-white/10 hover:bg-white/20 rounded-full text-white transition-all border border-white/10 z-[101]"
            onClick={() => setPreviewImage(null)}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
          <img 
            src={previewImage} 
            className="max-w-full max-h-full rounded-2xl shadow-2xl object-contain animate-in zoom-in-95 duration-300 shadow-indigo-500/10 border border-white/10"
            alt="Preview"
            onClick={(e) => e.stopPropagation()}
