                              className="text-[10px] font-black px-3 py-1.5 bg-white/5 hover:bg-white/10 rounded-lg flex items-center gap-2 border border-white/10 transition-all text-slate-200"
                            >
                              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" /></svg>
                              DOWNLOAD
                            </button>
                          </div>
                        </>
                      ) : (
                        <div className="p-8 border border-white/10 bg-black/20 rounded-xl text-center">
                          <p className="text-slate-400 text-sm italic">Image synthesis failed to initialize.</p>
                        </div>
                      )}
                   </div>
                ) : (
                  <div className="prose prose-invert max-w-none text-slate-200">
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                )}

                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-6 pt-4 border-t border-white/5 space-y-3">
                    <p className="text-[9px] text-indigo-400 font-black uppercase tracking-[0.2em]">Grounding Knowledge</p>
                    <div className="flex flex-wrap gap-2">
                      {msg.sources.map((s, idx) => (
                        <a 
                          key={idx} 
                          href={s.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-[10px] font-bold bg-white/5 hover:bg-indigo-500/10 text-slate-400 hover:text-indigo-300 px-3 py-1.5 rounded-lg border border-white/5 flex items-center gap-2 transition-all"
                        >
                          <span className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,1)]"></span>
                          <span className="truncate max-w-[120px]">{s.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex items-center gap-1 mt-2 px-1 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-1 group-hover:translate-y-0">
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'text')}
                    className="p-2 hover:bg-indigo-500/10 rounded-lg text-slate-500 hover:text-indigo-400 transition-all group/btn"
                    title="Edit in Workspace"
                  >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                  </button>
                  <button 
                    onClick={() => handleCopy(msg.text, msg.id)}
                    className={`p-2 rounded-lg transition-all ${copiedId === msg.id ? 'bg-emerald-500/20 text-emerald-400' : 'hover:bg-slate-800 text-slate-500 hover:text-slate-200'}`}
                    title={copiedId === msg.id ? "Copied!" : "Copy to Clipboard"}
                  >
                    {copiedId === msg.id ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    ) : (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                    )}
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-500 gap-3 items-center">
            <RahiEye size="w-8 h-8" animating={true} />
            <div className="ai-bubble p-4 pr-8 flex items-center gap-6 border border-white/5 min-w-[200px]">
              <div className="shrink-0 scale-50 -ml-4 -mr-4">
                <QuantumLoader />
              </div>
              <div className="flex flex-col gap-1">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] whitespace-nowrap">Rahix Processing</span>
                <span className="text-[9px] text-slate-500 font-medium italic">Synthesizing neural workspace...</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-8 pt-0">
        <div className="max-w-4xl mx-auto relative">
          <div className="glass-card rounded-[40px] shadow-2xl border border-white/10 p-2 flex flex-col gap-2">

            <div className="flex items-center gap-2 px-4 pt-1">
               <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
               <div className="h-4 w-px bg-white/10 mx-1"></div>
               <button 
                  onClick={() => setIsVoiceOpen(true)}
                  className="flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border bg-white/5 text-slate-400 border-white/5 hover:bg-white/10"
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
                 NEURAL VOICE
               </button>
               <button 
                  onClick={() => setUseDeepResearch(!useDeepResearch)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    useDeepResearch 
                      ? 'bg-indigo-600 text-white border-white/20 shadow-[0_0_15px_rgba(99,102,241,0.4)]' 
                      : 'bg-white/5 text-slate-400 border-white/5 hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>
                 DEEP RESEARCH
               </button>
               <button 
                  onClick={() => setIsImageMode(!isImageMode)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    isImageMode 
                      ? 'bg-pink-600 text-white border-white/20 shadow-[0_0_15px_rgba(236,72,153,0.4)]' 
                      : 'bg-white/5 text-slate-400 border-white/5 hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>
                 IMAGE MODE
               </button>
            </div>

            <div className="relative flex items-center">
              <div className="flex items-center pl-4 pr-2">
                <div className="relative">
                  {isListening && (
                    <div className="absolute inset-0 bg-indigo-500/20 rounded-full animate-ping pointer-events-none" />
                  )}
                  <button 
                    onClick={toggleListening}
                    className={`p-2 rounded-full transition-all duration-300 relative z-10 ${isListening ? 'bg-indigo-600 text-white shadow-[0_0_15px_rgba(99,102,241,0.6)]' : 'text-slate-400 hover:bg-white/5'}`}
                    title={isListening ? "Stop Listening" : "Audio Typing"}
                  >
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                      <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                      <path d="M19 10v2a7 7 0 0 1-14 0v-2"/>
                      <line x1="12" y1="19" x2="12" y2="23"/>
                      <line x1="8" y1="23" x2="16" y2="23"/>
                    </svg>
                  </button>
                </div>
              </div>

              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                disabled={isRateLimited}
                placeholder={isRateLimited ? `Rate limit reached. Resetting in ${rpmResetSeconds}s...` : isImageMode ? "Describe the vision you want to generate..." : isListening ? "Listening to your thoughts..." : "Message Rahix AI..."}
                className={`w-full bg-transparent text-slate-100 rounded-[32px] py-4 pl-2 pr-16 resize-none min-h-[64px] max-h-[200px] transition-all outline-none text-[15px] font-medium ${isRateLimited ? 'opacity-50 cursor-not-allowed' : ''} ${isListening ? 'animate-pulse text-indigo-200' : ''}`}
                rows={1}
              />
              <button
                onClick={handleSend}
                disabled={isLoading || isRateLimited || (!input.trim() && files.length === 0)}
                className={`absolute right-3 p-3 text-white rounded-full transition-all shadow-xl ${
                  isRateLimited 
                    ? 'bg-slate-700 cursor-not-allowed' 
                    : isImageMode 
                      ? 'bg-pink-600 hover:bg-pink-500 shadow-pink-500/20' 
                      : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/20'
                }`}
              >
                {isRateLimited ? (
                  <span className="text-[10px] font-bold">{rpmResetSeconds}s</span>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                    <line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <div className="flex justify-center mt-3">
             <p className="text-[9px] text-slate-600 font-black uppercase tracking-[0.4em] flex items-center gap-3">
                <span>Rahix AI Pro Workspace</span>
                <span className="w-1 h-1 rounded-full bg-slate-700"></span>
                <span>Optimized Engine</span>
             </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { QuantumLoader } from './AILoader';
import { VoiceInterface } from './VoiceInterface';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
  rpmCount: number;
  rpmLimit: number;
  rpmResetSeconds: number;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas,
  rpmCount,
  rpmLimit,
  rpmResetSeconds
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [showRateAlert, setShowRateAlert] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const finalTranscriptRef = useRef<string>(''); // Accumulates final results
  const baseInputRef = useRef<string>(''); // Text before STT session

  const rahixPersona = `
    Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
    Mission: Provide expert-level environment for engineering, coding, and technical analysis.
    Tone: Professional, objective, and expert system.
    Language Policy: You are a native speaker of all languages. Always detect the language of the user's input and respond fluently and naturally in that EXACT same language.
  `;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  useEffect(() => {
    if (rpmCount === 50 && !showRateAlert) {
      setShowRateAlert(true);
      setTimeout(() => setShowRateAlert(false), 5000);
    }
  }, [rpmCount]);

  // Speech Recognition (Voice-to-Text / Audio Typing)
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let sessionInterimTranscript = '';
        let sessionFinalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; i++) {
          const transcriptChunk = event.results[i][0].transcript;
          if (event.results[i].isFinal) {
            sessionFinalTranscript += transcriptChunk;
          } else {
            sessionInterimTranscript += transcriptChunk;
          }
        }

        if (sessionFinalTranscript) {
           finalTranscriptRef.current += sessionFinalTranscript;
        }

        // The "Audio Typing" effect: Combine base text + accumulated final + current interim
        const combined = baseInputRef.current + 
                         (baseInputRef.current && !baseInputRef.current.endsWith(' ') ? ' ' : '') + 
                         finalTranscriptRef.current + 
                         sessionInterimTranscript;

        setInput(combined);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('STT Error:', event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      baseInputRef.current = input.trim();
      finalTranscriptRef.current = '';
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (isListening) recognitionRef.current?.stop();
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const handleDownloadImage = async (e: React.MouseEvent, dataUrl: string, id: string) => {
    e.stopPropagation();
    try {
      let blob: Blob;
      if (dataUrl.startsWith('data:')) {
        const parts = dataUrl.split(';base64,');
        const contentType = parts[0].split(':')[1];
        const raw = window.atob(parts[1]);
        const rawLength = raw.length;
        const uInt8Array = new Uint8Array(rawLength);
        for (let i = 0; i < rawLength; ++i) {
          uInt8Array[i] = raw.charCodeAt(i);
        }
        blob = new Blob([uInt8Array], { type: contentType });
      } else {
        const response = await fetch(dataUrl);
        blob = await response.blob();
      }
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `rahul-ai-gen-${id.substring(0, 5)}.png`;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        window.URL.revokeObjectURL(blobUrl);
      }, 200);
    } catch (err) {
      console.error("Download failed:", err);
      window.open(dataUrl, '_blank');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const RahiEye = ({ animating = false, size = "w-6 h-6" }) => (
    <div className={`relative ${size} flex items-center justify-center ${animating ? 'animate-pulse' : ''}`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <circle cx="50" cy="50" r="45" fill="#1e293b" stroke="#334155" strokeWidth="5" />
        <circle cx="50" cy="50" r="20" fill="#22d3ee" className={animating ? "animate-ping" : ""}>
          <animate attributeName="opacity" values="0.4;1;0.4" dur="2s" repeatCount="indefinite" />
        </circle>
        <circle cx="50" cy="50" r="10" fill="white" />
      </svg>
    </div>
  );

  const isRateLimited = rpmCount >= rpmLimit;

  return (
    <div className="flex flex-col h-full relative overflow-hidden bg-transparent text-slate-200">
      {/* 1. NEURAL VOICE MODE (Real-time Conversation) */}
      <VoiceInterface 
        isOpen={isVoiceOpen} 
        onClose={() => setIsVoiceOpen(false)} 
        persona={rahixPersona} 
      />

      {/* Rate Limit Toast */}
      {showRateAlert && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="bg-amber-600/20 backdrop-blur-xl border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-2xl">
            <div className="w-2 h-2 rounded-full bg-amber-500 animate-ping"></div>
            <p className="text-xs font-bold text-amber-200 uppercase tracking-widest">Approaching Rahix AI rate limits</p>
          </div>
        </div>
      )}

      {/* Image Preview Modal */}
      {previewImage && (
        <div 
          className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 md:p-12 animate-in fade-in duration-300"
          onClick={() => setPreviewImage(null)}
        >
          <button 
            className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center bg-white/10 hover:bg-white/20 rounded-full text-white transition-all border border-white/10 z-[101]"
            onClick={() => setPreviewImage(null)}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
          <img 
            src={previewImage} 
            className="max-w-full max-h-full rounded-2xl shadow-2xl object-contain animate-in zoom-in-95 duration-300 shadow-indigo-500/10 border border-white/10"
            alt="Preview"
            onClick={(e) => e.stopPropagation()}
            loading="lazy"
          />
        </div>
      )}

      {/* Messages Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-10 pb-32 scroll-smooth"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12">
            <div className="w-20 h-20 mb-8 glass-card rounded-3xl flex items-center justify-center animate-float">
              <RahiEye size="w-10 h-10" />
            </div>
            <h2 className="text-3xl font-black text-white mb-4 tracking-tight">Rahix AI Pro</h2>
            <p className="text-slate-400 text-lg leading-relaxed">
              Your high-performance intelligent workspace. Deep research, code engineering, and document generation.
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-4 duration-500`}
          >
            <div className="shrink-0 mb-1">
              {msg.role === Role.USER ? (
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-pink-500 flex items-center justify-center text-[10px] font-black text-white shadow-lg">RS</div>
              ) : (
                <RahiEye size="w-8 h-8" />
              )}
            </div>

            <div className={`max-w-[75%] group flex flex-col ${msg.role === Role.USER ? 'items-end' : 'items-start'}`}>
              <div 
                className={`p-5 transition-all ${
                  msg.role === Role.USER 
                    ? 'user-bubble text-slate-100' 
                    : 'ai-bubble text-slate-200'
                }`}
              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {msg.files.map((f, idx) => (
                      <div 
                        key={idx} 
                        onClick={() => f.type.startsWith('image/') && setPreviewImage(f.previewUrl || f.data)}
                        className={`bg-white/5 backdrop-blur-md p-2 rounded-xl flex items-center gap-3 border border-white/10 ${f.type.startsWith('image/') ? 'cursor-pointer hover:bg-white/10 transition-all' : ''}`}
                      >
                        {f.type.startsWith('image/') ? (
                          <img src={f.previewUrl || f.data} className="w-10 h-10 object-cover rounded-lg" loading="lazy" />
                        ) : (
                          <div className="w-10 h-10 bg-indigo-500/20 rounded-lg flex items-center justify-center text-xl">📄</div>
                        )}
                        <div className="text-[10px] max-w-[80px]">
                          <p className="font-bold truncate text-current">{f.name}</p>
                          <p className="opacity-60">{(f.size / 1024).toFixed(1)} KB</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {msg.isImageGeneration ? (
                   <div className="space-y-4">
                      {msg.text && (msg.text.startsWith('data:image') || msg.text.startsWith('http')) ? (
                        <>
                          <img 
                            src={msg.text} 
                            className="w-full rounded-xl shadow-2xl border border-white/10 hover:scale-[1.01] transition-transform duration-500 cursor-zoom-in" 
                            onClick={() => setPreviewImage(msg.text)}
                            loading="lazy"
                            alt="Generated content"
                          />
                          <div className="flex gap-2">
                            <button 
                              onClick={(e) => handleDownloadImage(e, msg.text, msg.id)}
                              className="text-[10px] font-black px-3 py-1.5 bg-white/5 hover:bg-white/10 rounded-lg flex items-center gap-2 border border-white/10 transition-all text-slate-200"
                            >
                              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" /></svg>
                              DOWNLOAD
                            </button>
                          </div>
                        </>
                      ) : (
                        <div className="p-8 border border-white/10 bg-black/20 rounded-xl text-center">
                          <p className="text-slate-400 text-sm italic">Image synthesis failed to initialize.</p>
                        </div>
                      )}
                   </div>
                ) : (
                  <div className="prose prose-invert max-w-none text-slate-200">
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                )}

                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-6 pt-4 border-t border-white/5 space-y-3">
                    <p className="text-[9px] text-indigo-400 font-black uppercase tracking-[0.2em]">Grounding Knowledge</p>
                    <div className="flex flex-wrap gap-2">
                      {msg.sources.map((s, idx) => (
                        <a 
                          key={idx} 
                          href={s.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-[10px] font-bold bg-white/5 hover:bg-indigo-500/10 text-slate-400 hover:text-indigo-300 px-3 py-1.5 rounded-lg border border-white/5 flex items-center gap-2 transition-all"
                        >
                          <span className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,1)]"></span>
                          <span className="truncate max-w-[120px]">{s.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex items-center gap-1 mt-2 px-1 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-1 group-hover:translate-y-0">
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'text')}
                    className="p-2 hover:bg-indigo-500/10 rounded-lg text-slate-500 hover:text-indigo-400 transition-all group/btn"
                    title="Edit in Workspace"
                  >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                  </button>
                  <button 
                    onClick={() => handleCopy(msg.text, msg.id)}
                    className={`p-2 rounded-lg transition-all ${copiedId === msg.id ? 'bg-emerald-500/20 text-emerald-400' : 'hover:bg-slate-800 text-slate-500 hover:text-slate-200'}`}
                    title={copiedId === msg.id ? "Copied!" : "Copy to Clipboard"}
                  >
                    {copiedId === msg.id ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    ) : (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                    )}
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-500 gap-3 items-center">
            <RahiEye size="w-8 h-8" animating={true} />
            <div className="ai-bubble p-4 pr-8 flex items-center gap-6 border border-white/5 min-w-[200px]">
              <div className="shrink-0 scale-50 -ml-4 -mr-4">
                <QuantumLoader />
              </div>
              <div className="flex flex-col gap-1">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] whitespace-nowrap">Rahix Processing</span>
                <span className="text-[9px] text-slate-500 font-medium italic">Synthesizing neural workspace...</span>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Input Bar Section */}
      <div className="absolute bottom-0 left-0 right-0 p-8 pt-0">
        <div className="max-w-4xl mx-auto relative">
          <div className="glass-card rounded-[40px] shadow-2xl border border-white/10 p-2 flex flex-col gap-2">

            {/* Top Row: Mode Toggles & File Upload */}
            <div className="flex items-center gap-2 px-4 pt-1">
               <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
               <div className="h-4 w-px bg-white/10 mx-1"></div>

               {/* Button for Full Neural Voice Session */}
               <button 
                  onClick={() => setIsVoiceOpen(true)}
                  className="flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border bg-white/5 text-slate-400 border-white/5 hover:bg-white/10"
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
                 NEURAL VOICE
               </button>

               <button 
                  onClick={() => setUseDeepResearch(!useDeepResearch)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    useDeepResearch 
                      ? 'bg-indigo-600 text-white border-white/20 shadow-[0_0_15px_rgba(99,102,241,0.4)]' 
                      : 'bg-white/5 text-slate-400 border-white/5 hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>
                 DEEP RESEARCH
               </button>
               <button 
                  onClick={() => setIsImageMode(!isImageMode)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    isImageMode 
                      ? 'bg-pink-600 text-white border-white/20 shadow-[0_0_15px_rgba(236,72,153,0.4)]' 
                      : 'bg-white/5 text-slate-400 border-white/5 hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>
                 IMAGE MODE
               </button>
            </div>

            {/* 2. VOICE-TO-TEXT / AUDIO TYPING Mic Button & Input Area */}
            <div className="relative flex items-center">
              <div className="flex items-center pl-4 pr-2">
                <div className="relative">
                  {isListening && (
                    <div className="absolute inset-0 bg-indigo-500/20 rounded-full animate-ping pointer-events-none" />
                  )}
                  <button 
                    onClick={toggleListening}
                    className={`p-2 rounded-full transition-all duration-300 relative z-10 ${
                      isListening 
                        ? 'bg-indigo-600 text-white shadow-[0_0_20px_rgba(99,102,241,0.6)]' 
                        : 'text-slate-400 hover:bg-white/5'
                    }`}
                    title={isListening ? "Stop Recording (Audio Typing)" : "Start Recording (Audio Typing)"}
                  >
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                      <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                      <path d="M19 10v2a7 7 0 0 1-14 0v-2"/>
                      <line x1="12" y1="19" x2="12" y2="23"/>
                      <line x1="8" y1="23" x2="16" y2="23"/>
                    </svg>
                  </button>
                </div>
              </div>

              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                disabled={isRateLimited}
                placeholder={isRateLimited ? `Rate limit reached. Resetting in ${rpmResetSeconds}s...` : isImageMode ? "Describe the vision you want to generate..." : isListening ? "Synthesizing your thoughts into text..." : "Message Rahix AI..."}
                className={`w-full bg-transparent text-slate-100 rounded-[32px] py-4 pl-2 pr-16 resize-none min-h-[64px] max-h-[200px] transition-all outline-none text-[15px] font-medium ${isRateLimited ? 'opacity-50 cursor-not-allowed' : ''} ${isListening ? 'animate-pulse text-indigo-200 placeholder:text-indigo-400/50' : ''}`}
                rows={1}
              />

              <button
                onClick={handleSend}
                disabled={isLoading || isRateLimited || (!input.trim() && files.length === 0)}
                className={`absolute right-3 p-3 text-white rounded-full transition-all shadow-xl ${
                  isRateLimited 
                    ? 'bg-slate-700 cursor-not-allowed' 
                    : isImageMode 
                      ? 'bg-pink-600 hover:bg-pink-500 shadow-pink-500/20' 
                      : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/20'
                }`}
              >
                {isRateLimited ? (
                  <span className="text-[10px] font-bold">{rpmResetSeconds}s</span>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                    <line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <div className="flex justify-center mt-3">
             <p className="text-[9px] text-slate-600 font-black uppercase tracking-[0.4em] flex items-center gap-3">
                <span>Rahix AI Pro Workspace</span>
                <span className="w-1 h-1 rounded-full bg-slate-700"></span>
                <span>Optimized Engine</span>
             </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { QuantumLoader } from './AILoader';
import { VoiceInterface } from './VoiceInterface';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
  rpmCount: number;
  rpmLimit: number;
  rpmResetSeconds: number;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas,
  rpmCount,
  rpmLimit,
  rpmResetSeconds
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [showRateAlert, setShowRateAlert] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const baseInputRef = useRef<string>(''); 

  const rahixPersona = `
    Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
    Mission: Provide expert-level environment for engineering, coding, and technical analysis.
    Tone: Professional, objective, and expert system.
    Language Policy: You are a native speaker of all languages. Always detect the language of the user's input and respond fluently and naturally in that EXACT same language.
    Voice Mode Policy: Keep responses concise (under 3 sentences) and highly focused for audio consumption.
  `;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  useEffect(() => {
    if (rpmCount === 50 && !showRateAlert) {
      setShowRateAlert(true);
      setTimeout(() => setShowRateAlert(false), 5000);
    }
  }, [rpmCount]);

  // Speech Recognition (Voice-to-Text / Audio Typing)
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let sessionTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          sessionTranscript += event.results[i][0].transcript;
        }

        // Audio Typing Logic: Base text + session text
        const finalOutput = baseInputRef.current + (baseInputRef.current && !baseInputRef.current.endsWith(' ') ? ' ' : '') + sessionTranscript;
        setInput(finalOutput);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('STT Error:', event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      baseInputRef.current = input.trim();
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (isListening) recognitionRef.current?.stop();
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const handleDownloadImage = async (e: React.MouseEvent, dataUrl: string, id: string) => {
    e.stopPropagation();
    try {
      let blob: Blob;
      if (dataUrl.startsWith('data:')) {
        const parts = dataUrl.split(';base64,');
        const contentType = parts[0].split(':')[1];
        const raw = window.atob(parts[1]);
        const rawLength = raw.length;
        const uInt8Array = new Uint8Array(rawLength);
        for (let i = 0; i < rawLength; ++i) {
          uInt8Array[i] = raw.charCodeAt(i);
        }
        blob = new Blob([uInt8Array], { type: contentType });
      } else {
        const response = await fetch(dataUrl);
        blob = await response.blob();
      }
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `rahul-ai-gen-${id.substring(0, 5)}.png`;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        window.URL.revokeObjectURL(blobUrl);
      }, 200);
    } catch (err) {
      console.error("Download failed:", err);
      window.open(dataUrl, '_blank');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const RahiEye = ({ animating = false, size = "w-6 h-6" }) => (
    <div className={`relative ${size} flex items-center justify-center ${animating ? 'animate-pulse' : ''}`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <circle cx="50" cy="50" r="45" fill="#1e293b" stroke="#334155" strokeWidth="5" />
        <circle cx="50" cy="50" r="20" fill="#22d3ee" className={animating ? "animate-ping" : ""}>
          <animate attributeName="opacity" values="0.4;1;0.4" dur="2s" repeatCount="indefinite" />
        </circle>
        <circle cx="50" cy="50" r="10" fill="white" />
      </svg>
    </div>
  );

  const isRateLimited = rpmCount >= rpmLimit;

  return (
    <div className="flex flex-col h-full relative overflow-hidden bg-transparent text-slate-200">
      <VoiceInterface 
        isOpen={isVoiceOpen} 
        onClose={() => setIsVoiceOpen(false)} 
        persona={rahixPersona} 
      />

      {showRateAlert && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="bg-amber-600/20 backdrop-blur-xl border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-2xl">
            <div className="w-2 h-2 rounded-full bg-amber-500 animate-ping"></div>
            <p className="text-xs font-bold text-amber-200 uppercase tracking-widest">Approaching Rahix AI rate limits</p>
          </div>
        </div>
      )}

      {previewImage && (
        <div 
          className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 md:p-12 animate-in fade-in duration-300"
          onClick={() => setPreviewImage(null)}
        >
          <button 
            className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center bg-white/10 hover:bg-white/20 rounded-full text-white transition-all border border-white/10 z-[101]"
            onClick={() => setPreviewImage(null)}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
          <img 
            src={previewImage} 
            className="max-w-full max-h-full rounded-2xl shadow-2xl object-contain animate-in zoom-in-95 duration-300 shadow-indigo-500/10 border border-white/10"
            alt="Preview"
            onClick={(e) => e.stopPropagation()}
            loading="lazy"
          />
        </div>
      )}

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-10 pb-32 scroll-smooth"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12">
            <div className="w-20 h-20 mb-8 glass-card rounded-3xl flex items-center justify-center animate-float">
              <RahiEye size="w-10 h-10" />
            </div>
            <h2 className="text-3xl font-black text-white mb-4 tracking-tight">Rahix AI Pro</h2>
            <p className="text-slate-400 text-lg leading-relaxed">
              Your high-performance intelligent workspace. Deep research, code engineering, and document generation.
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-4 duration-500`}
          >
            <div className="shrink-0 mb-1">
              {msg.role === Role.USER ? (
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-pink-500 flex items-center justify-center text-[10px] font-black text-white shadow-lg">RS</div>
              ) : (
                <RahiEye size="w-8 h-8" />
              )}
            </div>

            <div className={`max-w-[75%] group flex flex-col ${msg.role === Role.USER ? 'items-end' : 'items-start'}`}>
              <div 
                className={`p-5 transition-all ${
                  msg.role === Role.USER 
                    ? 'user-bubble text-slate-100' 
                    : 'ai-bubble text-slate-200'
                }`}
              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {msg.files.map((f, idx) => (
                      <div 
                        key={idx} 
                        onClick={() => f.type.startsWith('image/') && setPreviewImage(f.previewUrl || f.data)}
                        className={`bg-white/5 backdrop-blur-md p-2 rounded-xl flex items-center gap-3 border border-white/10 ${f.type.startsWith('image/') ? 'cursor-pointer hover:bg-white/10 transition-all' : ''}`}
                      >
                        {f.type.startsWith('image/') ? (
                          <img src={f.previewUrl || f.data} className="w-10 h-10 object-cover rounded-lg" loading="lazy" />
                        ) : (
                          <div className="w-10 h-10 bg-indigo-500/20 rounded-lg flex items-center justify-center text-xl">📄</div>
                        )}
                        <div className="text-[10px] max-w-[80px]">
                          <p className="font-bold truncate text-current">{f.name}</p>
                          <p className="opacity-60">{(f.size / 1024).toFixed(1)} KB</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {msg.isImageGeneration ? (
                   <div className="space-y-4">
                      {msg.text && (msg.text.startsWith('data:image') || msg.text.startsWith('http')) ? (
                        <>
                          <img 
                            src={msg.text} 
                            className="w-full rounded-xl shadow-2xl border border-white/10 hover:scale-[1.01] transition-transform duration-500 cursor-zoom-in" 
                            onClick={() => setPreviewImage(msg.text)}
                            loading="lazy"
                            alt="Generated content"
                          />
                          <div className="flex gap-2">
                            <button 
                              onClick={(e) => handleDownloadImage(e, msg.text, msg.id)}
                              className="text-[10px] font-black px-3 py-1.5 bg-white/5 hover:bg-white/10 rounded-lg flex items-center gap-2 border border-white/10 transition-all text-slate-200"
                            >
                              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" /></svg>
                              DOWNLOAD
                            </button>
                          </div>
                        </>
                      ) : (
                        <div className="p-8 border border-white/10 bg-black/20 rounded-xl text-center">
                          <p className="text-slate-400 text-sm italic">Image synthesis failed to initialize.</p>
                        </div>
                      )}
                   </div>
                ) : (
                  <div className="prose prose-invert max-w-none text-slate-200">
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                )}

                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-6 pt-4 border-t border-white/5 space-y-3">
                    <p className="text-[9px] text-indigo-400 font-black uppercase tracking-[0.2em]">Grounding Knowledge</p>
                    <div className="flex flex-wrap gap-2">
                      {msg.sources.map((s, idx) => (
                        <a 
                          key={idx} 
                          href={s.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-[10px] font-bold bg-white/5 hover:bg-indigo-500/10 text-slate-400 hover:text-indigo-300 px-3 py-1.5 rounded-lg border border-white/5 flex items-center gap-2 transition-all"
                        >
                          <span className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,1)]"></span>
                          <span className="truncate max-w-[120px]">{s.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex items-center gap-1 mt-2 px-1 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-1 group-hover:translate-y-0">
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'text')}
                    className="p-2 hover:bg-indigo-500/10 rounded-lg text-slate-500 hover:text-indigo-400 transition-all group/btn"
                    title="Edit in Workspace"
                  >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                  </button>
                  <button 
                    onClick={() => handleCopy(msg.text, msg.id)}
                    className={`p-2 rounded-lg transition-all ${copiedId === msg.id ? 'bg-emerald-500/20 text-emerald-400' : 'hover:bg-slate-800 text-slate-500 hover:text-slate-200'}`}
                    title={copiedId === msg.id ? "Copied!" : "Copy to Clipboard"}
                  >
                    {copiedId === msg.id ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    ) : (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                    )}
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-500 gap-3 items-center">
            <RahiEye size="w-8 h-8" animating={true} />
            <div className="ai-bubble p-4 pr-8 flex items-center gap-6 border border-white/5 min-w-[200px]">
              <div className="shrink-0 scale-50 -ml-4 -mr-4">
                <QuantumLoader />
              </div>
              <div className="flex flex-col gap-1">
                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] whitespace-nowrap">Rahix Processing</span>
