import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

interface VoiceInterfaceProps {
  isOpen: boolean;
  onClose: () => void;
  persona: string;
}

type AudioState = 'idle' | 'connecting' | 'listening' | 'speaking';

// --- Visual Sub-Components ---

const WaveBar: React.FC<{ height: number; delay: number; color: string }> = ({ height, delay, color }) => (
  <motion.div
    className={`w-1.5 rounded-full ${color}`}
    initial={{ height: 4 }}
    animate={{ 
      height: Math.max(6, height * 100),
      opacity: height > 0.1 ? 1 : 0.4
    }}
    transition={{ 
      type: "spring",
      stiffness: 300,
      damping: 20,
      delay: delay * 0.005
    }}
    style={{
      boxShadow: height > 0.5 ? `0 0 15px ${color.includes('emerald') ? '#10b981' : '#a78bfa'}` : 'none'
    }}
  />
);

const Ripple: React.FC<{ delay: number; color: string }> = ({ delay, color }) => (
  <motion.div
    className={`absolute rounded-full border-2 ${color} opacity-0`}
    initial={{ width: 100, height: 100, opacity: 0 }}
    animate={{
      width: [100, 450],
      height: [100, 450],
      opacity: [0.6, 0],
      borderWidth: [2, 0]
    }}
    transition={{
      duration: 3,
      repeat: Infinity,
      delay: delay * 0.8,
      ease: "easeOut"
    }}
  />
);

const Particle: React.FC<{ angle: number }> = ({ angle }) => (
  <motion.div
    className="absolute w-1 h-1 bg-indigo-400 rounded-full"
    style={{ left: '50%', top: '50%' }}
    animate={{
      x: [0, Math.cos(angle * Math.PI / 180) * 150],
      y: [0, Math.sin(angle * Math.PI / 180) * 150],
      opacity: [1, 0],
      scale: [1, 0]
    }}
    transition={{
      duration: 2,
      repeat: Infinity,
      delay: Math.random() * 1,
      ease: "easeOut"
    }}
  />
);

export const VoiceInterface: React.FC<VoiceInterfaceProps> = ({ isOpen, onClose, persona }) => {
  const [status, setStatus] = useState<AudioState>('idle');
  const [transcription, setTranscription] = useState('');
  const [aiTranscription, setAiTranscription] = useState('');
  const [volumeData, setVolumeData] = useState<number[]>(new Array(32).fill(0));

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // PCM Helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const updateVolume = (data: Float32Array) => {
    let sum = 0;
    for (let i = 0; i < data.length; i++) sum += data[i] * data[i];
    const rms = Math.sqrt(sum / data.length);
    const normalized = Math.min(rms * 8, 1);

    setVolumeData(prev => {
      const next = [...prev];
      next.shift();
      next.push(normalized);
      return next;
    });
  };

  const startSession = async () => {
    setStatus('connecting');
    try {
      const ai = new GoogleGenAI({ apiKey: (process.env.API_KEY as string) });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('listening');
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              updateVolume(inputData);

              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;

              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => session && session.sendRealtimeInput({ media: pcmBlob })).catch(() => {});
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              setAiTranscription(prev => prev + message.serverContent!.outputTranscription!.text);
              setStatus('speaking');
            }
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => prev + message.serverContent!.inputTranscription!.text);
              setAiTranscription('');
              setStatus('listening');
            }
            if (message.serverContent?.turnComplete) {
              setStatus('listening');
              setTranscription('');
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current && outputContextRef.current.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputContextRef.current.currentTime);
              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, 24000, 1);

              updateVolume(buffer.getChannelData(0));

              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputContextRef.current.destination);
              source.onended = () => sourcesRef.current.delete(source);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setStatus('listening');
            }
          },
          onclose: () => handleClose(),
          onerror: () => handleClose()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: persona + " MANDATORY: Keep responses under 3 concise sentences. Optimize for audio speed.",
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } }
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      handleClose();
    }
  };

  const handleClose = () => {
    setStatus('idle');
    if (audioContextRef.current?.state !== 'closed') audioContextRef.current?.close().catch(() => {});
    if (outputContextRef.current?.state !== 'closed') outputContextRef.current?.close().catch(() => {});
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    onClose();
  };

  useEffect(() => {
    if (isOpen) startSession();
    return () => handleClose();
  }, [isOpen]);

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[200] flex items-center justify-center bg-[#030305]/98 backdrop-blur-3xl"
        >
          {/* Ambient Glow */}
          <div className={`absolute inset-0 opacity-25 transition-colors duration-1000 ${
            status === 'listening' ? 'bg-emerald-600/10' : 
            status === 'speaking' ? 'bg-indigo-600/10' : 'bg-slate-900/10'
          }`} />

          <div className="relative max-w-4xl w-full h-full flex flex-col items-center justify-center p-8 gap-16 text-center">

            <div className="relative w-96 h-96 flex items-center justify-center">
              {status === 'listening' && (
                <>
                  <Ripple delay={0} color="border-emerald-500/30" />
                  <Ripple delay={1} color="border-emerald-500/20" />
                </>
              )}

              {status === 'speaking' && (
                <>
                  {[...Array(16)].map((_, i) => (
                    <Particle key={i} angle={i * 22.5} />
                  ))}
                </>
              )}

              {/* mascot's pulsing eye */}
              <motion.div 
                animate={{
                  scale: status === 'listening' ? [1, 1.1, 1] : status === 'speaking' ? [1, 1.05, 1] : 1,
                  boxShadow: status === 'listening' 
                    ? '0 0 100px rgba(16, 185, 129, 0.4)' 
                    : status === 'speaking' 
                    ? '0 0 100px rgba(99, 102, 241, 0.4)' 
                    : '0 0 40px rgba(255, 255, 255, 0.05)'
                }}
                transition={{ duration: 2, repeat: Infinity }}
                className={`relative z-20 w-48 h-48 rounded-full flex items-center justify-center border-4 border-white/10 transition-colors duration-700 ${
                  status === 'listening' ? 'bg-emerald-600' : 
                  status === 'speaking' ? 'bg-indigo-600' : 
                  'bg-slate-800'
                }`}
              >
                {/* Minimal Eye SVG */}
                <svg viewBox="0 0 100 100" className="w-24 h-24">
                  <circle cx="50" cy="50" r="45" fill="black" opacity="0.2" />
                  <circle cx="50" cy="50" r="20" fill="white" />
                  <motion.circle 
                    animate={{
                      scale: status === 'speaking' ? [1, 1.2, 1] : 1,
                      x: status === 'listening' ? [0, 5, -5, 0] : 0
                    }}
                    transition={{ duration: 1, repeat: Infinity }}
                    cx="55" cy="45" r="8" fill="#22d3ee" 
                  />
                </svg>
              </motion.div>
            </div>

            <div className="flex items-center justify-center gap-1.5 h-32">
              {volumeData.map((v, i) => (
                <WaveBar 
                  key={i} 
                  height={v} 
                  delay={i} 
                  color={status === 'listening' ? 'bg-emerald-400' : 'bg-indigo-400'} 
                />
              ))}
            </div>

            <div className="space-y-6 w-full max-w-2xl">
              <h2 className={`text-sm font-black uppercase tracking-[0.5em] ${
                status === 'listening' ? 'text-emerald-400' : 
                status === 'speaking' ? 'text-indigo-400' : 'text-slate-500'
              }`}>
                {status === 'connecting' ? '建立神经链接' : 
                 status === 'listening' ? 'System Listening' : 
                 status === 'speaking' ? 'Neural Response' : 'Standby'}
              </h2>

              <div className="min-h-[120px] px-8 py-6 rounded-3xl bg-white/5 border border-white/5 backdrop-blur-xl flex flex-col justify-center gap-4">
                <AnimatePresence mode="wait">
                  {transcription && (
                    <motion.p 
                      key="usr"
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      className="text-slate-400 font-medium italic text-lg"
                    >
                      "{transcription}"
                    </motion.p>
                  )}
                  {aiTranscription && (
                    <motion.p 
                      key="ai"
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      className="text-white font-bold text-2xl leading-tight"
                    >
                      {aiTranscription}
                    </motion.p>
                  )}
                </AnimatePresence>
              </div>
            </div>

            <button 
              onClick={handleClose}
              className="px-12 py-4 bg-rose-600/10 hover:bg-rose-600/20 text-rose-500 rounded-full font-black text-xs tracking-widest border border-rose-500/20 transition-all uppercase"
            >
              Exit Neural Mode
            </button>
          </div>
        </div>
      )}
    </AnimatePresence>
  );
};

