import React, { useState, useEffect, useCallback } from 'react';
import { Role, ChatMessage, FileData, CanvasState, ChatSession } from './types';
import { Sidebar } from './components/Sidebar';
import { ChatInterface } from './components/ChatInterface';
import { CanvasMode } from './components/CanvasMode';
import { LandingPage } from './components/LandingPage';
import { AboutPage } from './components/AboutPage';
import { ExpertisePage } from './components/ExpertisePage';
import { ProjectsPage } from './components/ProjectsPage';
import { SettingsPage } from './components/SettingsPage';
import { geminiService } from './services/geminiService';

type ViewMode = 'landing' | 'chat' | 'about' | 'expertise' | 'projects' | 'settings';

const RPM_LIMIT = 60;

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>(() => {
    // Basic persistence for initial view if needed, but default to landing
    return 'landing';
  });
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [rpmCount, setRpmCount] = useState(0);
  const [secondsToReset, setSecondsToReset] = useState(60);
  const [canvasState, setCanvasState] = useState<CanvasState>({
    isOpen: false,
    content: '',
    mode: 'text',
    language: 'markdown',
    title: ''
  });

  // Load theme on mount
  useEffect(() => {
    const saved = localStorage.getItem('rahix_theme');
    if (saved === 'dark') {
      document.documentElement.classList.add('dark');
    } else if (saved === 'light') {
      document.documentElement.classList.remove('dark');
    } else {
      // Default to dark
      document.documentElement.classList.add('dark');
    }
  }, []);

  // RPM Reset Logic
  useEffect(() => {
    const timer = setInterval(() => {
      setSecondsToReset((prev) => {
        if (prev <= 1) {
          setRpmCount(0);
          return 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  // Initialize sessions
  useEffect(() => {
    const saved = localStorage.getItem('rahix_sessions');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) {
        setCurrentSessionId(parsed[0].id);
      }
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('rahix_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Conversation',
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession, ...sessions]);
    setCurrentSessionId(newSession.id);
    setCanvasState(prev => ({ ...prev, isOpen: false }));
  };

  const handleSendMessage = async (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => {
    if (rpmCount >= RPM_LIMIT) return;

    if (!currentSessionId) {
      createNewChat();
      return; 
    }

    const currentSession = sessions.find(s => s.id === currentSessionId);
    if (!currentSession) return;

    // Increment RPM
    setRpmCount(prev => prev + 1);

    const newUserMsg: ChatMessage = {
      id: Date.now().toString(),
      role: Role.USER,
      text,
      files,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        return { 
          ...s, 
          messages: [...s.messages, newUserMsg],
          title: s.messages.length === 0 ? text.substring(0, 30) : s.title
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setIsLoading(true);

    try {
      if (isImage) {
        const imageUrl = await geminiService.generateImage(text);
        if (imageUrl) {
          const modelMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: Role.MODEL,
            text: imageUrl,
            timestamp: Date.now(),
            isImageGeneration: true
          };
          addModelMessage(modelMsg);
        } else {
          const modelMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: Role.MODEL,
            text: "I encountered an issue generating that image. It may have been blocked by safety filters or a service error occurred. Please try a different prompt.",
            timestamp: Date.now()
          };
          addModelMessage(modelMsg);
        }
      } else {
        const response = await geminiService.sendMessage(text, currentSession.messages, files, useWebSearch);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: response.text,
          sources: response.sources,
          timestamp: Date.now()
        };
        addModelMessage(modelMsg);
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: Role.MODEL,
        text: "I encountered an error processing your request. Please try again.",
        timestamp: Date.now()
      };
      addModelMessage(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const addModelMessage = (msg: ChatMessage) => {
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, msg] };
      }
      return s;
    }));
  };

  const openInCanvas = (text: string) => {
    const codeMatch = text.match(/```(\w+)?\n([\s\S]*?)```/);
    if (codeMatch) {
      setCanvasState({
        isOpen: true,
        mode: 'code',
        language: codeMatch[1] || 'javascript',
        content: codeMatch[2],
        title: 'Extracted Snippet'
      });
    } else {
      setCanvasState({
        isOpen: true,
        mode: 'text',
        language: 'markdown',
        content: text,
        title: 'Extracted Document'
      });
    }
  };

  if (view === 'landing') {
    return <LandingPage 
      onGetStarted={() => {
        if (sessions.length === 0) createNewChat();
        setView('chat');
      }} 
      onNavigate={(v) => setView(v as ViewMode)}
    />;
  }

  if (view === 'about') return <AboutPage onBack={() => setView('landing')} />;
  if (view === 'expertise') return <ExpertisePage onBack={() => setView('landing')} />;
  if (view === 'projects') return <ProjectsPage onBack={() => setView('landing')} />;
  if (view === 'settings') return <SettingsPage onBack={() => setView('chat')} usageCount={rpmCount} usageLimit={RPM_LIMIT} />;

  const currentSession = sessions.find(s => s.id === currentSessionId);

  return (
    <div className="flex h-screen w-full transition-colors duration-500 bg-slate-50 dark:bg-[#0f172a] text-slate-800 dark:text-slate-200 overflow-hidden animate-in fade-in duration-500">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onNavigate={(v) => setView(v as ViewMode)}
        usageCount={rpmCount}
        usageLimit={RPM_LIMIT}
        usageResetSeconds={secondsToReset}
      />

      <main className={`flex-1 flex transition-all duration-300 ease-in-out`}>
        <div className={`h-full border-r border-slate-200 dark:border-[#1e293b] flex flex-col transition-all duration-300 ${canvasState.isOpen ? 'w-[40%]' : 'w-full'}`}>
          <div className="h-14 border-b border-slate-200 dark:border-slate-800 flex items-center px-6 justify-between shrink-0">
             <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('landing')}>
               <div className="w-5 h-5 bg-indigo-500/10 dark:bg-indigo-500/20 rounded flex items-center justify-center text-indigo-600 dark:text-indigo-400">
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="15 18 9 12 15 6" /></svg>
               </div>
               <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Back to Core</span>
             </div>
             <div className="text-xs font-bold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-900 px-3 py-1 rounded-full border border-slate-200 dark:border-white/5">
               Rahix AI Engine v2.0
             </div>
          </div>
          <ChatInterface 
            messages={currentSession?.messages || []} 
            onSendMessage={handleSendMessage}
            isLoading={isLoading}
            onEditInCanvas={openInCanvas}
            rpmCount={rpmCount}
            rpmLimit={RPM_LIMIT}
            rpmResetSeconds={secondsToReset}
          />
        </div>

        {canvasState.isOpen && (
          <div className="w-[60%] h-full animate-in slide-in-from-right duration-300">
            <CanvasMode 
              state={canvasState} 
              onClose={() => setCanvasState(prev => ({ ...prev, isOpen: false }))}
              onUpdateContent={(content) => setCanvasState(prev => ({ ...prev, content }))}
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { QuantumLoader } from './AILoader';
import { VoiceInterface } from './VoiceInterface';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
  rpmCount: number;
  rpmLimit: number;
  rpmResetSeconds: number;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas,
  rpmCount,
  rpmLimit,
  rpmResetSeconds
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [showRateAlert, setShowRateAlert] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const baseInputRef = useRef<string>(''); 

  const rahixPersona = `
    Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
    Mission: Provide expert-level environment for engineering, coding, and technical analysis.
    Tone: Professional, objective, and expert system.
    Language Policy: You are a native speaker of all languages. Always detect the language of the user's input and respond fluently and naturally in that EXACT same language.
    Voice Mode Policy: Keep responses concise (under 3 sentences) and highly focused for audio consumption.
  `;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  useEffect(() => {
    if (rpmCount === 50 && !showRateAlert) {
      setShowRateAlert(true);
      setTimeout(() => setShowRateAlert(false), 5000);
    }
  }, [rpmCount]);

  // Speech Recognition (Voice-to-Text / Audio Typing)
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let sessionTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          sessionTranscript += event.results[i][0].transcript;
        }

        // Audio Typing Logic: Base text + session text
        const finalOutput = baseInputRef.current + (baseInputRef.current && !baseInputRef.current.endsWith(' ') ? ' ' : '') + sessionTranscript;
        setInput(finalOutput);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('STT Error:', event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      baseInputRef.current = input.trim();
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (isListening) recognitionRef.current?.stop();
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const handleDownloadImage = async (e: React.MouseEvent, dataUrl: string, id: string) => {
    e.stopPropagation();
    try {
      let blob: Blob;
      if (dataUrl.startsWith('data:')) {
        const parts = dataUrl.split(';base64,');
        const contentType = parts[0].split(':')[1];
        const raw = window.atob(parts[1]);
        const rawLength = raw.length;
        const uInt8Array = new Uint8Array(rawLength);
        for (let i = 0; i < rawLength; ++i) {
          uInt8Array[i] = raw.charCodeAt(i);
        }
        blob = new Blob([uInt8Array], { type: contentType });
      } else {
        const response = await fetch(dataUrl);
        blob = await response.blob();
      }
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `rahul-ai-gen-${id.substring(0, 5)}.png`;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        window.URL.revokeObjectURL(blobUrl);
      }, 200);
    } catch (err) {
      console.error("Download failed:", err);
      window.open(dataUrl, '_blank');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const RahiEye = ({ animating = false, size = "w-6 h-6" }) => (
    <div className={`relative ${size} flex items-center justify-center ${animating ? 'animate-pulse' : ''}`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <circle cx="50" cy="50" r="45" fill="currentColor" className="text-slate-200 dark:text-[#1e293b]" stroke="currentColor" strokeWidth="5" />
        <circle cx="50" cy="50" r="20" fill="#22d3ee" className={animating ? "animate-ping" : ""}>
          <animate attributeName="opacity" values="0.4;1;0.4" dur="2s" repeatCount="indefinite" />
        </circle>
        <circle cx="50" cy="50" r="10" fill="white" />
      </svg>
    </div>
  );

  const isRateLimited = rpmCount >= rpmLimit;

  return (
    <div className="flex flex-col h-full relative overflow-hidden bg-transparent text-slate-800 dark:text-slate-200">
      <VoiceInterface 
        isOpen={isVoiceOpen} 
        onClose={() => setIsVoiceOpen(false)} 
        persona={rahixPersona} 
      />

      {showRateAlert && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="bg-amber-600/20 backdrop-blur-xl border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-2xl">
            <div className="w-2 h-2 rounded-full bg-amber-500 animate-ping"></div>
            <p className="text-xs font-bold text-amber-200 uppercase tracking-widest">Approaching Rahix AI rate limits</p>
          </div>
        </div>
      )}

      {previewImage && (
        <div 
          className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 md:p-12 animate-in fade-in duration-300"
          onClick={() => setPreviewImage(null)}
        >
          <button 
            className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center bg-white/10 hover:bg-white/20 rounded-full text-white transition-all border border-white/10 z-[101]"
            onClick={() => setPreviewImage(null)}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
          <img 
            src={previewImage} 
            className="max-w-full max-h-full rounded-2xl shadow-2xl object-contain animate-in zoom-in-95 duration-300 shadow-indigo-500/10 border border-white/10"
            alt="Preview"
            onClick={(e) => e.stopPropagation()}
            loading="lazy"
          />
        </div>
      )}

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-10 pb-32 scroll-smooth"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12">
            <div className="w-20 h-20 mb-8 glass-card bg-white dark:bg-[#1e293b]/40 rounded-3xl flex items-center justify-center animate-float shadow-xl border border-slate-200 dark:border-white/5">
              <RahiEye size="w-10 h-10" />
            </div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-4 tracking-tight">Rahix AI Pro</h2>
            <p className="text-slate-500 dark:text-slate-400 text-lg leading-relaxed">
              Your high-performance intelligent workspace. Deep research, code engineering, and document generation.
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-4 duration-500`}
          >
            <div className="shrink-0 mb-1">
              {msg.role === Role.USER ? (
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-pink-500 flex items-center justify-center text-[10px] font-black text-white shadow-lg">RS</div>
              ) : (
                <RahiEye size="w-8 h-8" />
              )}
            </div>

            <div className={`max-w-[75%] group flex flex-col ${msg.role === Role.USER ? 'items-end' : 'items-start'}`}>
              <div 
                className={`p-5 transition-all rounded-[24px] ${
                  msg.role === Role.USER 
                    ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/10' 
                    : 'bg-white dark:bg-[#1e293b] text-slate-800 dark:text-slate-200 border border-slate-200 dark:border-white/5 shadow-sm'
                }`}
              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {msg.files.map((f, idx) => (
                      <div 
                        key={idx} 
                        onClick={() => f.type.startsWith('image/') && setPreviewImage(f.previewUrl || f.data)}
                        className={`bg-slate-100 dark:bg-white/5 backdrop-blur-md p-2 rounded-xl flex items-center gap-3 border border-slate-200 dark:border-white/10 ${f.type.startsWith('image/') ? 'cursor-pointer hover:bg-slate-200 dark:hover:bg-white/10 transition-all' : ''}`}
                      >
                        {f.type.startsWith('image/') ? (
                          <img src={f.previewUrl || f.data} className="w-10 h-10 object-cover rounded-lg" loading="lazy" />
                        ) : (
                          <div className="w-10 h-10 bg-indigo-500/20 rounded-lg flex items-center justify-center text-xl">📄</div>
                        )}
                        <div className="text-[10px] max-w-[80px]">
                          <p className="font-bold truncate text-current">{f.name}</p>
                          <p className="opacity-60">{(f.size / 1024).toFixed(1)} KB</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {msg.isImageGeneration ? (
                   <div className="space-y-4">
                      {msg.text && (msg.text.startsWith('data:image') || msg.text.startsWith('http')) ? (
                        <>
                          <img 
                            src={msg.text} 
                            className="w-full rounded-xl shadow-2xl border border-slate-200 dark:border-white/10 hover:scale-[1.01] transition-transform duration-500 cursor-zoom-in" 
                            onClick={() => setPreviewImage(msg.text)}
                            loading="lazy"
                            alt="Generated content"
                          />
                          <div className="flex gap-2">
                            <button 
                              onClick={(e) => handleDownloadImage(e, msg.text, msg.id)}
                              className="text-[10px] font-black px-3 py-1.5 bg-slate-100 dark:bg-white/5 hover:bg-slate-200 dark:hover:bg-white/10 rounded-lg flex items-center gap-2 border border-slate-200 dark:border-white/10 transition-all text-slate-700 dark:text-slate-200"
                            >
                              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" /></svg>
                              DOWNLOAD
                            </button>
                          </div>
                        </>
                      ) : (
                        <div className="p-8 border border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-black/20 rounded-xl text-center">
                          <p className="text-slate-500 dark:text-slate-400 text-sm italic">Image synthesis failed to initialize.</p>
                        </div>
                      )}
                   </div>
                ) : (
                  <div className={`prose dark:prose-invert max-w-none ${msg.role === Role.USER ? 'prose-invert text-white' : 'text-slate-800 dark:text-slate-200'}`}>
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                )}

                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-6 pt-4 border-t border-slate-200 dark:border-white/5 space-y-3">
                    <p className="text-[9px] text-indigo-500 dark:text-indigo-400 font-black uppercase tracking-[0.2em]">Grounding Knowledge</p>
                    <div className="flex flex-wrap gap-2">
                      {msg.sources.map((s, idx) => (
                        <a 
                          key={idx} 
                          href={s.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-[10px] font-bold bg-slate-100 dark:bg-white/5 hover:bg-indigo-500/10 text-slate-600 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-300 px-3 py-1.5 rounded-lg border border-slate-200 dark:border-white/5 flex items-center gap-2 transition-all"
                        >
                          <span className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,1)]"></span>
                          <span className="truncate max-w-[120px]">{s.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex items-center gap-1 mt-2 px-1 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-1 group-hover:translate-y-0">
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'text')}
                    className="p-2 hover:bg-indigo-500/10 rounded-lg text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 transition-all group/btn"
                    title="Edit in Workspace"
                  >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                  </button>
                  <button 
                    onClick={() => handleCopy(msg.text, msg.id)}
                    className={`p-2 rounded-lg transition-all ${copiedId === msg.id ? 'bg-emerald-500/20 text-emerald-400' : 'hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-slate-900 dark:hover:text-slate-200'}`}
                    title={copiedId === msg.id ? "Copied!" : "Copy to Clipboard"}
                  >
                    {copiedId === msg.id ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    ) : (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                    )}
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-500 gap-3 items-center">
            <RahiEye size="w-8 h-8" animating={true} />
            <div className="bg-white dark:bg-[#1e293b] p-4 pr-8 flex items-center gap-6 border border-slate-200 dark:border-white/5 rounded-[24px] shadow-sm min-w-[200px]">
              <div className="shrink-0 scale-50 -ml-4 -mr-4">
                <QuantumLoader />
              </div>
              <div className="flex flex-col gap-1">
                <span className="text-[10px] font-black text-indigo-500 dark:text-indigo-400 uppercase tracking-[0.2em] whitespace-nowrap">Rahix Processing</span>
                <span className="text-[9px] text-slate-500 font-medium italic">Synthesizing neural workspace...</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-8 pt-0">
        <div className="max-w-4xl mx-auto relative">
          <div className="glass-card bg-white/90 dark:bg-[#1e293b]/90 rounded-[40px] shadow-2xl border border-slate-200 dark:border-white/10 p-2 flex flex-col gap-2 backdrop-blur-xl">

            <div className="flex items-center gap-2 px-4 pt-1">
               <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
               <div className="h-4 w-px bg-slate-200 dark:bg-white/10 mx-1"></div>
               <button 
                  onClick={() => setIsVoiceOpen(true)}
                  className="flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-white/5 hover:bg-slate-200 dark:hover:bg-white/10"
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
                 NEURAL VOICE
               </button>
               <button 
                  onClick={() => setUseDeepResearch(!useDeepResearch)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    useDeepResearch 
                      ? 'bg-indigo-600 text-white border-white/20 shadow-[0_0_15px_rgba(99,102,241,0.4)]' 
                      : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-white/5 hover:bg-slate-200 dark:hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>
                 DEEP RESEARCH
               </button>
               <button 
                  onClick={() => setIsImageMode(!isImageMode)}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black transition-all border ${
                    isImageMode 
                      ? 'bg-pink-600 text-white border-white/20 shadow-[0_0_15px_rgba(236,72,153,0.4)]' 
                      : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-white/5 hover:bg-slate-200 dark:hover:bg-white/10'
                  }`}
               >
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>
                 IMAGE MODE
               </button>
            </div>

            <div className="relative flex items-center">
              <div className="flex items-center pl-4 pr-2">
                <div className="relative">
                  {isListening && (
                    <div className="absolute inset-0 bg-indigo-500/20 rounded-full animate-ping pointer-events-none" />
                  )}
                  <button 
                    onClick={toggleListening}
                    className={`p-2 rounded-full transition-all duration-300 relative z-10 ${isListening ? 'bg-indigo-600 text-white shadow-[0_0_15px_rgba(99,102,241,0.6)]' : 'text-slate-400 hover:bg-slate-100 dark:hover:bg-white/5'}`}
                    title={isListening ? "Stop Listening (Capture Text)" : "Audio Typing (Voice to Text)"}
                  >
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                      <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                      <path d="M19 10v2a7 7 0 0 1-14 0v-2"/>
                      <line x1="12" y1="19" x2="12" y2="23"/>
                      <line x1="8" y1="23" x2="16" y2="23"/>
                    </svg>
                  </button>
                </div>
              </div>

              <div className="flex-1 relative">
                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={handleKeyPress}
                  disabled={isRateLimited}
                  placeholder={isRateLimited ? `Rate limit reached. Resetting in ${rpmResetSeconds}s...` : isImageMode ? "Describe the vision you want to generate..." : isListening ? "Listening... Your words are appearing as you speak." : "Message Rahix AI..."}
                  className={`w-full bg-transparent text-slate-900 dark:text-slate-100 rounded-[32px] py-4 pl-2 pr-16 resize-none min-h-[64px] max-h-[200px] transition-all outline-none text-[15px] font-medium ${isRateLimited ? 'opacity-50 cursor-not-allowed' : ''} ${isListening ? 'text-indigo-600 dark:text-indigo-200' : ''}`}
                  rows={1}
                />
                {isListening && (
                  <div className="absolute bottom-2 left-2 right-14 flex items-center gap-1 opacity-50 pointer-events-none">
                    {[...Array(6)].map((_, i) => (
                      <div 
                        key={i} 
                        className="w-1 bg-indigo-500 dark:bg-indigo-400 rounded-full animate-wave" 
                        style={{ height: '4px', animationDelay: `${i * 0.1}s` }}
                      />
                    ))}
                  </div>
                )}
              </div>

              <button
                onClick={handleSend}
                disabled={isLoading || isRateLimited || (!input.trim() && files.length === 0)}
                className={`absolute right-3 p-3 text-white rounded-full transition-all shadow-xl ${
                  isRateLimited 
                    ? 'bg-slate-300 dark:bg-slate-700 cursor-not-allowed' 
                    : isImageMode 
                      ? 'bg-pink-600 hover:bg-pink-500 shadow-pink-500/20' 
                      : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/20'
                }`}
              >
                {isRateLimited ? (
                  <span className="text-[10px] font-bold">{rpmResetSeconds}s</span>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                    <line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <div className="flex justify-center mt-3">
             <p className="text-[9px] text-slate-400 dark:text-slate-600 font-black uppercase tracking-[0.4em] flex items-center gap-3">
                <span>Rahix AI Pro Workspace</span>
                <span className="w-1 h-1 rounded-full bg-slate-200 dark:bg-slate-700"></span>
                <span>Optimized Engine</span>
             </p>
          </div>
        </div>
      </div>
      <style>{`
        @keyframes wave {
          0%, 100% { height: 4px; }
          50% { height: 12px; }
        }
        .animate-wave {
          animation: wave 1s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

import React, { useState } from 'react';
import { CanvasState } from '../types';
import { geminiService } from '../services/geminiService';

interface CanvasModeProps {
  state: CanvasState;
  onClose: () => void;
  onUpdateContent: (content: string) => void;
}

export const CanvasMode: React.FC<CanvasModeProps> = ({ state, onClose, onUpdateContent }) => {
  const [instruction, setInstruction] = useState('');
  const [isRefining, setIsRefining] = useState(false);

  const handleRefine = async () => {
    if (!instruction.trim()) return;
    setIsRefining(true);
    try {
      const refined = await geminiService.refineCanvasContent(state.content, instruction, state.mode);
      onUpdateContent(refined);
      setInstruction('');
    } catch (error) {
      console.error(error);
    } finally {
      setIsRefining(false);
    }
  };

  return (
    <div className="h-full flex flex-col bg-white dark:bg-[#1e293b] border-l border-slate-200 dark:border-[#334155] shadow-2xl z-50 transition-colors duration-500">
      <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-[#334155] bg-slate-50 dark:bg-[#0f172a]/50">
        <div className="flex items-center gap-3">
          <div className={`p-1.5 rounded ${state.mode === 'code' ? 'bg-amber-500/10 text-amber-500' : 'bg-indigo-500/10 text-indigo-500'}`}>
            {state.mode === 'code' ? (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="16 18 22 12 16 6" /><polyline points="8 6 2 12 8 18" /></svg>
            ) : (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" /><line x1="16" y1="13" x2="8" y2="13" /><line x1="16" y1="17" x2="8" y2="17" /><polyline points="10 9 9 9 8 9" /></svg>
            )}
          </div>
          <div>
            <h2 className="text-sm font-bold text-slate-900 dark:text-slate-100">{state.title || 'Collaborative Canvas'}</h2>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest">{state.mode} Editing Mode</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => {
              const blob = new Blob([state.content], { type: 'text/plain' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url;
              a.download = `rahul-${state.title.replace(/\s+/g, '-').toLowerCase() || 'doc'}.txt`;
              a.click();
            }}
            className="p-2 hover:bg-slate-200 dark:hover:bg-[#334155] rounded text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors" title="Download"
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" /><polyline points="7 10 12 15 17 10" /><line x1="12" y1="15" x2="12" y2="3" /></svg>
          </button>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 dark:hover:bg-[#334155] rounded text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col p-4 space-y-4 overflow-hidden">
        <div className="flex-1 bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-[#334155] rounded-xl overflow-hidden shadow-inner flex flex-col">
          <textarea
            value={state.content}
            onChange={(e) => onUpdateContent(e.target.value)}
            className={`w-full flex-1 p-6 bg-transparent text-slate-800 dark:text-slate-200 resize-none outline-none leading-relaxed ${state.mode === 'code' ? 'fira-code text-sm' : 'text-lg'}`}
            spellCheck={state.mode === 'text'}
          />
          <div className="bg-slate-50 dark:bg-[#1e293b]/50 px-4 py-2 border-t border-slate-200 dark:border-[#334155] flex justify-between items-center">
            <span className="text-[10px] text-slate-500 font-mono">
              {state.content.length} chars | {state.content.split(/\s+/).filter(Boolean).length} words
            </span>
            {state.mode === 'code' && (
              <span className="text-[10px] bg-indigo-500/20 text-indigo-400 px-2 py-0.5 rounded border border-indigo-500/30">
                {state.language.toUpperCase()}
              </span>
            )}
          </div>
        </div>

        <div className="bg-slate-50 dark:bg-[#0f172a] border border-slate-200 dark:border-[#334155] rounded-xl p-3 shadow-lg">
          <p className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-widest mb-2 px-1">AI Quick Refinement</p>
          <div className="flex gap-2">
            <input
              type="text"
              value={instruction}
              onChange={(e) => setInstruction(e.target.value)}
              placeholder="e.g., 'Make it more professional' or 'Add comments to the code'"
              className="flex-1 bg-white dark:bg-[#1e293b] border border-slate-200 dark:border-[#334155] rounded-lg px-3 py-2 text-sm text-slate-800 dark:text-slate-200 outline-none focus:border-indigo-500/50 transition-colors"
              onKeyPress={(e) => e.key === 'Enter' && handleRefine()}
            />
            <button
              onClick={handleRefine}
              disabled={isRefining || !instruction.trim()}
              className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white rounded-lg px-4 py-2 text-sm font-bold flex items-center gap-2 transition-all"
            >
              {isRefining ? (
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="13 17 18 12 13 7" /><polyline points="6 17 11 12 6 7" /></svg>
              )}
              Refine
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { QuantumLoader } from './AILoader';
import { VoiceInterface } from './VoiceInterface';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
  rpmCount: number;
  rpmLimit: number;
  rpmResetSeconds: number;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas,
  rpmCount,
  rpmLimit,
  rpmResetSeconds
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [showRateAlert, setShowRateAlert] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const baseInputRef = useRef<string>(''); 

  const rahixPersona = `
    Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
    Mission: Provide expert-level environment for engineering, coding, and technical analysis.
    Tone: Professional, objective, and expert system.
    Language Policy: You are a native speaker of all languages. Always detect the language of the user's input and respond fluently and naturally in that EXACT same language.
    Voice Mode Policy: Keep responses concise (under 3 sentences) and highly focused for audio consumption.
  `;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  useEffect(() => {
    if (rpmCount === 50 && !showRateAlert) {
      setShowRateAlert(true);
      setTimeout(() => setShowRateAlert(false), 5000);
    }
  }, [rpmCount]);

  // Speech Recognition (Voice-to-Text / Audio Typing)
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let sessionTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          sessionTranscript += event.results[i][0].transcript;
        }

        const finalOutput = baseInputRef.current + (baseInputRef.current && !baseInputRef.current.endsWith(' ') ? ' ' : '') + sessionTranscript;
        setInput(finalOutput);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('STT Error:', event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      baseInputRef.current = input.trim();
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (isListening) recognitionRef.current?.stop();
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const handleDownloadImage = async (e: React.MouseEvent, dataUrl: string, id: string) => {
    e.stopPropagation();
    try {
      let blob: Blob;
      if (dataUrl.startsWith('data:')) {
        const parts = dataUrl.split(';base64,');
        const contentType = parts[0].split(':')[1];
        const raw = window.atob(parts[1]);
        const rawLength = raw.length;
        const uInt8Array = new Uint8Array(rawLength);
        for (let i = 0; i < rawLength; ++i) {
          uInt8Array[i] = raw.charCodeAt(i);
        }
        blob = new Blob([uInt8Array], { type: contentType });
      } else {
        const response = await fetch(dataUrl);
        blob = await response.blob();
      }
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `rahul-ai-gen-${id.substring(0, 5)}.png`;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        window.URL.revokeObjectURL(blobUrl);
      }, 200);
    } catch (err) {
      console.error("Download failed:", err);
      window.open(dataUrl, '_blank');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const RahiEye = ({ animating = false, size = "w-6 h-6" }) => (
    <div className={`relative ${size} flex items-center justify-center ${animating ? 'animate-pulse' : ''}`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <circle cx="50" cy="50" r="45" fill="currentColor" className="text-slate-200 dark:text-[#1e293b]" stroke="currentColor" strokeWidth="5" />
        <circle cx="50" cy="50" r="20" fill="#22d3ee" className={animating ? "animate-ping" : ""}>
          <animate attributeName="opacity" values="0.4;1;0.4" dur="2s" repeatCount="indefinite" />
        </circle>
        <circle cx="50" cy="50" r="10" fill="white" />
      </svg>
    </div>
  );

  const isRateLimited = rpmCount >= rpmLimit;

  return (
    <div className="flex flex-col h-full relative overflow-hidden bg-transparent text-slate-900 dark:text-slate-100">
      <VoiceInterface 
        isOpen={isVoiceOpen} 
        onClose={() => setIsVoiceOpen(false)} 
        persona={rahixPersona} 
      />

      {showRateAlert && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="bg-amber-600/20 backdrop-blur-xl border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-2xl">
            <div className="w-2 h-2 rounded-full bg-amber-500 animate-ping"></div>
            <p className="text-xs font-bold text-amber-200 uppercase tracking-widest">Approaching Rahix AI rate limits</p>
          </div>
        </div>
      )}

      {previewImage && (
        <div 
          className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 md:p-12 animate-in fade-in duration-300"
          onClick={() => setPreviewImage(null)}
        >
          <button 
            className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center bg-white/10 hover:bg-white/20 rounded-full text-white transition-all border border-white/10 z-[101]"
            onClick={() => setPreviewImage(null)}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
          <img 
            src={previewImage} 
            className="max-w-full max-h-full rounded-2xl shadow-2xl object-contain animate-in zoom-in-95 duration-300 shadow-indigo-500/10 border border-white/10"
            alt="Preview"
            onClick={(e) => e.stopPropagation()}
            loading="lazy"
          />
        </div>
      )}

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-10 pb-32 scroll-smooth"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12">
            <div className="w-20 h-20 mb-8 glass-card bg-white/70 dark:bg-slate-900/70 backdrop-blur-md rounded-3xl flex items-center justify-center animate-float shadow-xl border border-slate-200 dark:border-white/5">
              <RahiEye size="w-10 h-10" />
            </div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-slate-100 mb-4 tracking-tight">Rahix AI Pro</h2>
            <p className="text-slate-600 dark:text-slate-400 text-lg leading-relaxed">
              Your high-performance intelligent workspace. Deep research, code engineering, and document generation.
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-4 duration-500`}
          >
            <div className="shrink-0 mb-1">
              {msg.role === Role.USER ? (
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-pink-500 flex items-center justify-center text-[10px] font-black text-white shadow-lg">RS</div>
              ) : (
                <RahiEye size="w-8 h-8" />
              )}
            </div>

            <div className={`max-w-[75%] group flex flex-col ${msg.role === Role.USER ? 'items-end' : 'items-start'}`}>
              <div 
                className={`p-5 transition-all rounded-[24px] shadow-sm ${
                  msg.role === Role.USER 
                    ? 'bg-indigo-600 text-white shadow-indigo-500/10' 
                    : 'bg-white/70 dark:bg-slate-900/70 backdrop-blur-md text-slate-900 dark:text-slate-100 border border-slate-200 dark:border-white/5'
                }`}
              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {msg.files.map((f, idx) => (
                      <div 
                        key={idx} 
                        onClick={() => f.type.startsWith('image/') && setPreviewImage(f.previewUrl || f.data)}
                        className={`bg-slate-100/50 dark:bg-white/5 backdrop-blur-md p-2 rounded-xl flex items-center gap-3 border border-slate-200 dark:border-white/10 ${f.type.startsWith('image/') ? 'cursor-pointer hover:bg-slate-200/50 dark:hover:bg-white/10 transition-all' : ''}`}
                      >
                        {f.type.startsWith('image/') ? (
                          <img src={f.previewUrl || f.data} className="w-10 h-10 object-cover rounded-lg" loading="lazy" />
                        ) : (
                          <div className="w-10 h-10 bg-indigo-500/20 rounded-lg flex items-center justify-center text-xl">📄</div>
                        )}
                        <div className="text-[10px] max-w-[80px]">
                          <p className="font-bold truncate text-slate-900 dark:text-slate-100">{f.name}</p>
                          <p className="text-slate-500 dark:text-slate-400">{(f.size / 1024).toFixed(1)} KB</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {msg.isImageGeneration ? (
                   <div className="space-y-4">
                      {msg.text && (msg.text.startsWith('data:image') || msg.text.startsWith('http')) ? (
                        <>
                          <img 
                            src={msg.text} 
                            className="w-full rounded-xl shadow-2xl border border-slate-200 dark:border-white/10 hover:scale-[1.01] transition-transform duration-500 cursor-zoom-in" 
                            onClick={() => setPreviewImage(msg.text)}
                            loading="lazy"
                            alt="Generated content"
                          />
                          <div className="flex gap-2">
                            <button 
                              onClick={(e) => handleDownloadImage(e, msg.text, msg.id)}
                              className="text-[10px] font-black px-3 py-1.5 bg-slate-100 dark:bg-white/5 hover:bg-slate-200 dark:hover:bg-white/10 rounded-lg flex items-center gap-2 border border-slate-200 dark:border-white/10 transition-all text-slate-700 dark:text-slate-200"
                            >
                              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" /></svg>
                              DOWNLOAD
                            </button>
                          </div>
                        </>
                      ) : (
                        <div className="p-8 border border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-black/20 rounded-xl text-center">
                          <p className="text-slate-500 dark:text-slate-400 text-sm italic">Image synthesis failed to initialize.</p>
                        </div>
                      )}
                   </div>
                ) : (
                  <div className={`prose dark:prose-invert max-w-none ${msg.role === Role.USER ? 'prose-invert text-white' : 'text-slate-900 dark:text-slate-100'}`}>
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                )}

                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-6 pt-4 border-t border-slate-200 dark:border-white/5 space-y-3">
                    <p className="text-[9px] text-indigo-600 dark:text-indigo-400 font-black uppercase tracking-[0.2em]">Grounding Knowledge</p>
                    <div className="flex flex-wrap gap-2">
                      {msg.sources.map((s, idx) => (
                        <a 
                          key={idx} 
                          href={s.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-[10px] font-bold bg-slate-100 dark:bg-white/5 hover:bg-indigo-500/10 text-slate-600 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-300 px-3 py-1.5 rounded-lg border border-slate-200 dark:border-white/5 flex items-center gap-2 transition-all"
                        >
                          <span className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,1)]"></span>
                          <span className="truncate max-w-[120px]">{s.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex items-center gap-1 mt-2 px-1 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-1 group-hover:translate-y-0">
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'text')}
                    className="p-2 hover:bg-indigo-500/10 rounded-lg text-slate-500 hover:text-indigo-600 dark:hover:text-indigo-400 transition-all group/btn"
                    title="Edit in Workspace"
                  >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                  </button>
                  <button 
                    onClick={() => handleCopy(msg.text, msg.id)}
                    className={`p-2 rounded-lg transition-all ${copiedId === msg.id ? 'bg-emerald-500/20 text-emerald-400' : 'hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-500 hover:text-slate-900 dark:hover:text-slate-100'}`}
                    title={copiedId === msg.id ? "Copied!" : "Copy to Clipboard"}
                  >
                    {copiedId === msg.id ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    ) : (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                    )}
                  </button>
