import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { QuantumLoader } from './AILoader';
import { VoiceInterface } from './VoiceInterface';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
  rpmCount: number;
  rpmLimit: number;
  rpmResetSeconds: number;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas,
  rpmCount,
  rpmLimit,
  rpmResetSeconds
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [showRateAlert, setShowRateAlert] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const baseInputRef = useRef<string>(''); 

  const rahixPersona = `
    Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
    Mission: Provide expert-level environment for engineering, coding, and technical analysis.
    Tone: Professional, objective, and expert system.
    Language Policy: You are a native speaker of all languages. Always detect the language of the user's input and respond fluently and naturally in that EXACT same language.
    Voice Mode Policy: Keep responses concise (under 3 sentences) and highly focused for audio consumption.
  `;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  useEffect(() => {
    if (rpmCount === 50 && !showRateAlert) {
      setShowRateAlert(true);
      setTimeout(() => setShowRateAlert(false), 5000);
    }
  }, [rpmCount]);

  // Speech Recognition (Voice-to-Text / Audio Typing)
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let sessionTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          sessionTranscript += event.results[i][0].transcript;
        }

        const finalOutput = baseInputRef.current + (baseInputRef.current && !baseInputRef.current.endsWith(' ') ? ' ' : '') + sessionTranscript;
        setInput(finalOutput);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('STT Error:', event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      baseInputRef.current = input.trim();
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (isListening) recognitionRef.current?.stop();
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const handleDownloadImage = async (e: React.MouseEvent, dataUrl: string, id: string) => {
    e.stopPropagation();
    try {
      let blob: Blob;
      if (dataUrl.startsWith('data:')) {
        const parts = dataUrl.split(';base64,');
        const contentType = parts[0].split(':')[1];
        const raw = window.atob(parts[1]);
        const rawLength = raw.length;
        const uInt8Array = new Uint8Array(rawLength);
        for (let i = 0; i < rawLength; ++i) {
          uInt8Array[i] = raw.charCodeAt(i);
        }
        blob = new Blob([uInt8Array], { type: contentType });
      } else {
        const response = await fetch(dataUrl);
        blob = await response.blob();
      }
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `rahul-ai-gen-${id.substring(0, 5)}.png`;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        window.URL.revokeObjectURL(blobUrl);
      }, 200);
    } catch (err) {
      console.error("Download failed:", err);
      window.open(dataUrl, '_blank');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const RahiEye = ({ animating = false, size = "w-6 h-6" }) => (
    <div className={`relative ${size} flex items-center justify-center ${animating ? 'animate-pulse' : ''}`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <circle cx="50" cy="50" r="45" fill="currentColor" className="text-slate-200 dark:text-slate-800" stroke="currentColor" strokeWidth="5" />
        <circle cx="50" cy="50" r="20" fill="#22d3ee" className={animating ? "animate-ping" : ""}>
          <animate attributeName="opacity" values="0.4;1;0.4" dur="2s" repeatCount="indefinite" />
        </circle>
        <circle cx="50" cy="50" r="10" fill="currentColor" className="text-slate-100 dark:text-slate-200" />
      </svg>
    </div>
  );

  const isRateLimited = rpmCount >= rpmLimit;

  return (
    <div className="flex flex-col h-full relative overflow-hidden bg-transparent text-slate-900 dark:text-slate-100">
      <VoiceInterface 
        isOpen={isVoiceOpen} 
        onClose={() => setIsVoiceOpen(false)} 
        persona={rahixPersona} 
      />

      {showRateAlert && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="bg-amber-600/20 backdrop-blur-xl border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-2xl">
            <div className="w-2 h-2 rounded-full bg-amber-500 animate-ping"></div>
            <p className="text-xs font-bold text-amber-900 dark:text-amber-200 uppercase tracking-widest">Approaching Rahix AI rate limits</p>
          </div>
        </div>
      )}

      {previewImage && (
        <div 
          className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 md:p-12 animate-in fade-in duration-300"
          onClick={() => setPreviewImage(null)}
        >
          <button 
            className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center bg-white/10 hover:bg-white/20 rounded-full text-slate-100 transition-all border border-slate-200 dark:border-slate-800 z-[101]"
            onClick={() => setPreviewImage(null)}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
          <img 
            src={previewImage} 
            className="max-w-full max-h-full rounded-2xl shadow-2xl object-contain animate-in zoom-in-95 duration-300 shadow-indigo-500/10 border border-slate-200 dark:border-slate-800"
            alt="Preview"
            onClick={(e) => e.stopPropagation()}
            loading="lazy"
          />
        </div>
      )}

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-10 pb-32 scroll-smooth"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12">
            <div className="w-20 h-20 mb-8 glass-card bg-white/70 dark:bg-slate-900/70 backdrop-blur-md rounded-3xl flex items-center justify-center animate-float shadow-xl border border-slate-200 dark:border-slate-800">
              <RahiEye size="w-10 h-10" />
            </div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-slate-100 mb-4 tracking-tight">Rahix AI Pro</h2>
            <p className="text-slate-600 dark:text-slate-400 text-lg leading-relaxed">
              Your high-performance intelligent workspace. Deep research, code engineering, and document generation.
            </p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-4 duration-500`}
          >
            <div className="shrink-0 mb-1">
              {msg.role === Role.USER ? (
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-pink-500 flex items-center justify-center text-[10px] font-black text-slate-100 shadow-lg">RS</div>
              ) : (
                <RahiEye size="w-8 h-8" />
              )}
            </div>

            <div className={`max-w-[75%] group flex flex-col ${msg.role === Role.USER ? 'items-end' : 'items-start'}`}>
              <div 
                className={`p-5 transition-all rounded-[24px] shadow-sm ${
                  msg.role === Role.USER 
                    ? 'bg-indigo-600 text-slate-100 shadow-indigo-500/10' 
                    : 'bg-white/70 dark:bg-slate-900/70 backdrop-blur-md text-slate-900 dark:text-slate-100 border border-slate-200 dark:border-slate-800 shadow-sm'
                }`}
              >
                {msg.files && msg.files.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {msg.files.map((f, idx) => (
                      <div 
                        key={idx} 
                        onClick={() => f.type.startsWith('image/') && setPreviewImage(f.previewUrl || f.data)}
                        className={`bg-slate-200/50 dark:bg-white/5 backdrop-blur-md p-2 rounded-xl flex items-center gap-3 border border-slate-200 dark:border-slate-800 ${f.type.startsWith('image/') ? 'cursor-pointer hover:bg-slate-300/50 dark:hover:bg-white/10 transition-all' : ''}`}
                      >
                        {f.type.startsWith('image/') ? (
                          <img src={f.previewUrl || f.data} className="w-10 h-10 object-cover rounded-lg" loading="lazy" />
                        ) : (
                          <div className="w-10 h-10 bg-indigo-500/20 rounded-lg flex items-center justify-center text-xl">📄</div>
                        )}
                        <div className="text-[10px] max-w-[80px]">
                          <p className="font-bold truncate text-slate-900 dark:text-slate-100">{f.name}</p>
                          <p className="text-slate-600 dark:text-slate-400">{(f.size / 1024).toFixed(1)} KB</p>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {msg.isImageGeneration ? (
                   <div className="space-y-4">
                      {msg.text && (msg.text.startsWith('data:image') || msg.text.startsWith('http')) ? (
                        <>
                          <img 
                            src={msg.text} 
                            className="w-full rounded-xl shadow-2xl border border-slate-200 dark:border-slate-800 hover:scale-[1.01] transition-transform duration-500 cursor-zoom-in" 
                            onClick={() => setPreviewImage(msg.text)}
                            loading="lazy"
                            alt="Generated content"
                          />
                          <div className="flex gap-2">
                            <button 
                              onClick={(e) => handleDownloadImage(e, msg.text, msg.id)}
                              className="text-[10px] font-black px-3 py-1.5 bg-slate-200 dark:bg-white/5 hover:bg-slate-300 dark:hover:bg-white/10 rounded-lg flex items-center gap-2 border border-slate-200 dark:border-slate-800 transition-all text-slate-900 dark:text-slate-100"
                            >
                              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" /></svg>
                              DOWNLOAD
                            </button>
                          </div>
                        </>
                      ) : (
                        <div className="p-8 border border-slate-200 dark:border-slate-800 bg-slate-100 dark:bg-black/20 rounded-xl text-center">
                          <p className="text-slate-600 dark:text-slate-400 text-sm italic">Image synthesis failed to initialize.</p>
                        </div>
                      )}
                   </div>
                ) : (
                  <div className={`prose dark:prose-invert max-w-none ${msg.role === Role.USER ? 'prose-invert text-slate-100' : 'text-slate-900 dark:text-slate-100'}`}>
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                )}

                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-6 pt-4 border-t border-slate-200 dark:border-slate-800 space-y-3">
                    <p className="text-[9px] text-indigo-600 dark:text-indigo-400 font-black uppercase tracking-[0.2em]">Grounding Knowledge</p>
                    <div className="flex flex-wrap gap-2">
                      {msg.sources.map((s, idx) => (
                        <a 
                          key={idx} 
                          href={s.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-[10px] font-bold bg-slate-200 dark:bg-white/5 hover:bg-indigo-500/10 text-slate-600 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-300 px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-800 flex items-center gap-2 transition-all"
                        >
                          <span className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,1)]"></span>
                          <span className="truncate max-w-[120px]">{s.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {msg.role === Role.MODEL && !msg.isImageGeneration && (
                <div className="flex items-center gap-1 mt-2 px-1 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-1 group-hover:translate-y-0">
                  <button 
                    onClick={() => onEditInCanvas(msg.text, 'text')}
                    className="p-2 hover:bg-indigo-500/10 rounded-lg text-slate-600 dark:hover:text-indigo-400 transition-all group/btn"
                    title="Edit in Workspace"
                  >
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 20h9M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                  </button>
                  <button 
                    onClick={() => handleCopy(msg.text, msg.id)}
                    className={`p-2 rounded-lg transition-all ${copiedId === msg.id ? 'bg-emerald-500/20 text-emerald-400' : 'hover:bg-slate-200 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-100'}`}
                    title={copiedId === msg.id ? "Copied!" : "Copy to Clipboard"}
                  >
                    {copiedId === msg.id ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>
                    ) : (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
                    )}
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-500 gap-3 items-center">
            <RahiEye size="w-8 h-8" animating={true} />
            <div className="bg-white/70 dark:bg-slate-900/70 backdrop-blur-md p-4 pr-8 flex items-center gap-6 border border-slate-200 dark:border-slate-800 rounded-[24px] shadow-sm min-w-[200px]">
              <div className="shrink-0 scale-50 -ml-4 -mr-4">
                <QuantumLoader />
              </div>
