import React, { useEffect, useRef, useState } from 'react';

export const RahiRobot: React.FC = () => {
  const robotRef = useRef<HTMLDivElement>(null);
  const [eyePos, setEyePos] = useState({ x: 0, y: 0 });
  const [tilt, setTilt] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!robotRef.current) return;
      const rect = robotRef.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;

      const angle = Math.atan2(e.clientY - centerY, e.clientX - centerX);
      const distance = Math.min(8, Math.hypot(e.clientX - centerX, e.clientY - centerY) / 30);

      setEyePos({
        x: Math.cos(angle) * distance,
        y: Math.sin(angle) * distance
      });

      setTilt({
        x: (e.clientX - window.innerWidth / 2) / 60,
        y: (e.clientY - window.innerHeight / 2) / 60
      });
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  return (
    <div 
      ref={robotRef}
      className="relative flex flex-col items-center justify-center animate-float select-none"
      style={{
        perspective: '1000px',
        transform: `rotateY(${tilt.x}deg) rotateX(${-tilt.y}deg)`
      }}
    >
      {/* Speech Bubble */}
      <div className="absolute -top-16 -right-12 bg-white/90 dark:bg-slate-800/90 text-slate-900 dark:text-slate-100 backdrop-blur-sm border border-slate-200 dark:border-slate-700 px-4 py-2 rounded-2xl text-sm font-bold shadow-xl animate-bounce">
