      </div>

      {/* Head */}
      <div className="robot-head w-[180px] h-[160px] relative flex items-center justify-center z-20">
        <div className="robot-face w-[140px] h-[90px] rounded-[28px] flex items-center justify-center gap-6 overflow-hidden">
          {/* Eyes */}
          {[0, 1].map((i) => (
            <div key={i} className="w-9 h-9 bg-black rounded-full flex items-center justify-center text-cyan-400">
              <div 
                className="w-5 h-5 bg-cyan-400 rounded-full eye-glow relative"
                style={{ transform: `translate(${eyePos.x}px, ${eyePos.y}px)` }}
              >
                <div className="absolute top-1 right-1 w-1.5 h-1.5 bg-white/80 rounded-full"></div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Neck */}
      <div className="w-12 h-6 bg-slate-400 -mt-1 z-10"></div>

      {/* Body */}
      <div className="robot-body w-[150px] h-[180px] -mt-2 relative overflow-hidden flex flex-col items-center">
        <div className="mt-8 w-[100px] h-[80px] bg-slate-200/50 dark:bg-white/20 backdrop-blur-md rounded-xl border border-slate-300 dark:border-white/20 shadow-inner">
           <div className="w-full h-full flex items-center justify-center">
             <div className="w-2 h-2 bg-pink-500 rounded-full animate-pulse shadow-[0_0_10px_#ec4899]"></div>
           </div>
        </div>

        {/* Arms with Cute Hands */}
        <div className="absolute left-[-25px] top-4 w-10 h-32 bg-slate-300 rounded-full rotate-[15deg] shadow-lg flex items-end justify-center">
          <div className="w-11 h-11 bg-white rounded-full -mb-5 shadow-md border-4 border-slate-300 animate-pulse"></div>
        </div>
        <div className="absolute right-[-25px] top-4 w-10 h-32 bg-slate-300 rounded-full rotate-[-15deg] shadow-lg flex items-end justify-center">
