import React, { useState, useEffect, useCallback } from 'react';
import { Role, ChatMessage, FileData, CanvasState, ChatSession } from './types';
import { Sidebar } from './components/Sidebar';
import { ChatInterface } from './components/ChatInterface';
import { CanvasMode } from './components/CanvasMode';
import { LandingPage } from './components/LandingPage';
import { AboutPage } from './components/AboutPage';
import { ExpertisePage } from './components/ExpertisePage';
import { ProjectsPage } from './components/ProjectsPage';
import { SettingsPage } from './components/SettingsPage';
import { geminiService } from './services/geminiService';

type ViewMode = 'landing' | 'chat' | 'about' | 'expertise' | 'projects' | 'settings';

const RPM_LIMIT = 60;

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>(() => {
    return 'landing';
  });
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [rpmCount, setRpmCount] = useState(0);
  const [secondsToReset, setSecondsToReset] = useState(60);
  const [isPremium, setIsPremium] = useState(false);
  const [canvasState, setCanvasState] = useState<CanvasState>({
    isOpen: false,
    content: '',
    mode: 'text',
    language: 'markdown',
    title: ''
  });

  // Load settings on mount
  useEffect(() => {
    const savedTheme = localStorage.getItem('rahix_theme');
    const savedPremium = localStorage.getItem('rahix_premium_ui');

    if (savedTheme === 'dark') {
      document.documentElement.classList.add('dark');
    } else if (savedTheme === 'light') {
      document.documentElement.classList.remove('dark');
    } else {
      document.documentElement.classList.add('dark');
    }

    setIsPremium(savedPremium === 'true');
  }, []);

  // RPM Reset Logic
  useEffect(() => {
    const timer = setInterval(() => {
      setSecondsToReset((prev) => {
        if (prev <= 1) {
          setRpmCount(0);
          return 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  // Initialize sessions
  useEffect(() => {
    const saved = localStorage.getItem('rahix_sessions');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) {
        setCurrentSessionId(parsed[0].id);
      }
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('rahix_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Conversation',
      messages: [],
      createdAt: Date.now()
    };
    setSessions([newSession, ...sessions]);
    setCurrentSessionId(newSession.id);
    setCanvasState(prev => ({ ...prev, isOpen: false }));
  };

  const handleSendMessage = async (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => {
    if (rpmCount >= RPM_LIMIT) return;

    if (!currentSessionId) {
      createNewChat();
      return; 
    }

    const currentSession = sessions.find(s => s.id === currentSessionId);
    if (!currentSession) return;

    setRpmCount(prev => prev + 1);

    const newUserMsg: ChatMessage = {
      id: Date.now().toString(),
      role: Role.USER,
      text,
      files,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        return { 
          ...s, 
          messages: [...s.messages, newUserMsg],
          title: s.messages.length === 0 ? text.substring(0, 30) : s.title
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setIsLoading(true);

    try {
      if (isImage) {
        const imageUrl = await geminiService.generateImage(text);
        if (imageUrl) {
          const modelMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: Role.MODEL,
            text: imageUrl,
            timestamp: Date.now(),
            isImageGeneration: true
          };
          addModelMessage(modelMsg);
        } else {
          const modelMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: Role.MODEL,
            text: "I encountered an issue generating that image. It may have been blocked by safety filters or a service error occurred. Please try a different prompt.",
            timestamp: Date.now()
          };
          addModelMessage(modelMsg);
        }
      } else {
        const response = await geminiService.sendMessage(text, currentSession.messages, files, useWebSearch);
        const modelMsg: ChatMessage = {
          id: (Date.now() + 1).toString(),
          role: Role.MODEL,
          text: response.text,
          sources: response.sources,
          timestamp: Date.now()
        };
        addModelMessage(modelMsg);
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: Role.MODEL,
        text: "I encountered an error processing your request. Please try again.",
        timestamp: Date.now()
      };
      addModelMessage(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const addModelMessage = (msg: ChatMessage) => {
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, msg] };
      }
      return s;
    }));
  };

  const openInCanvas = (text: string) => {
    const codeMatch = text.match(/```(\w+)?\n([\s\S]*?)```/);
    if (codeMatch) {
      setCanvasState({
        isOpen: true,
        mode: 'code',
        language: codeMatch[1] || 'javascript',
        content: codeMatch[2],
        title: 'Extracted Snippet'
      });
    } else {
      setCanvasState({
        isOpen: true,
        mode: 'text',
        language: 'markdown',
        content: text,
        title: 'Extracted Document'
      });
    }
  };

  const syncSettings = () => {
    const savedPremium = localStorage.getItem('rahix_premium_ui');
    setIsPremium(savedPremium === 'true');
  };

  if (view === 'landing') {
    return <LandingPage 
      onGetStarted={() => {
        if (sessions.length === 0) createNewChat();
        setView('chat');
      }} 
      onNavigate={(v) => setView(v as ViewMode)}
    />;
  }

  if (view === 'about') return <AboutPage onBack={() => setView('landing')} />;
  if (view === 'expertise') return <ExpertisePage onBack={() => setView('landing')} />;
  if (view === 'projects') return <ProjectsPage onBack={() => setView('landing')} />;
  if (view === 'settings') return <SettingsPage onBack={() => { setView('chat'); syncSettings(); }} usageCount={rpmCount} usageLimit={RPM_LIMIT} />;

  const currentSession = sessions.find(s => s.id === currentSessionId);

  return (
    <div className="flex h-screen w-full transition-colors duration-500 bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 overflow-hidden animate-in fade-in duration-500">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onNavigate={(v) => setView(v as ViewMode)}
        usageCount={rpmCount}
        usageLimit={RPM_LIMIT}
        usageResetSeconds={secondsToReset}
      />

      <main className={`flex-1 flex transition-all duration-300 ease-in-out`}>
        <div className={`h-full border-r border-slate-200 dark:border-slate-800 flex flex-col transition-all duration-300 ${canvasState.isOpen ? 'w-[40%]' : 'w-full'}`}>
          <div className="h-14 border-b border-slate-200 dark:border-slate-800 flex items-center px-6 justify-between shrink-0">
             <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('landing')}>
               <div className="w-5 h-5 bg-indigo-500/10 dark:bg-indigo-500/20 rounded flex items-center justify-center text-indigo-600 dark:text-indigo-400">
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="15 18 9 12 15 6" /></svg>
               </div>
               <span className="text-xs font-bold text-slate-600 dark:text-slate-400 uppercase tracking-widest">Back to Core</span>
             </div>
             <div className="text-xs font-bold text-slate-600 dark:text-slate-400 bg-slate-100 dark:bg-slate-900 px-3 py-1 rounded-full border border-slate-200 dark:border-slate-800">
               Rahix AI Engine v2.0
             </div>
          </div>
          <ChatInterface 
            messages={currentSession?.messages || []} 
            onSendMessage={handleSendMessage}
            isLoading={isLoading}
            onEditInCanvas={openInCanvas}
            rpmCount={rpmCount}
            rpmLimit={RPM_LIMIT}
            rpmResetSeconds={secondsToReset}
            isPremium={isPremium}
          />
        </div>

        {canvasState.isOpen && (
          <div className="w-[60%] h-full animate-in slide-in-from-right duration-300">
            <CanvasMode 
              state={canvasState} 
              onClose={() => setCanvasState(prev => ({ ...prev, isOpen: false }))}
              onUpdateContent={(content) => setCanvasState(prev => ({ ...prev, content }))}
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

