  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [showRateAlert, setShowRateAlert] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const baseInputRef = useRef<string>(''); 

  const rahixPersona = `
    Identity: You are Rahix AI, a state-of-the-art Intelligent Workspace. 
    Mission: Provide expert-level environment for engineering, coding, and technical analysis.
    Tone: Professional, objective, and expert system.
    Language Policy: Fluently multilingual.
  `;

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  useEffect(() => {
    if (rpmCount >= 50 && !showRateAlert) {
      setShowRateAlert(true);
      setTimeout(() => setShowRateAlert(false), 5000);
    }
  }, [rpmCount]);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let sessionTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          sessionTranscript += event.results[i][0].transcript;
        }
        const finalOutput = baseInputRef.current + (baseInputRef.current && !baseInputRef.current.endsWith(' ') ? ' ' : '') + sessionTranscript;
        setInput(finalOutput);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      baseInputRef.current = input.trim();
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (isListening) recognitionRef.current?.stop();
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const RahiEye = ({ animating = false, size = "w-6 h-6" }) => (
    <div className={`relative ${size} flex items-center justify-center ${animating ? 'animate-pulse' : ''}`}>
      <svg viewBox="0 0 100 100" className="w-full h-full">
        <circle cx="50" cy="50" r="45" fill="currentColor" className="text-slate-200 dark:text-slate-800" stroke="currentColor" strokeWidth="5" />
        <circle cx="50" cy="50" r="20" fill="#6366f1" className={animating ? "animate-ping" : ""}>
          <animate attributeName="opacity" values="0.4;1;0.4" dur="2s" repeatCount="indefinite" />
        </circle>
        <circle cx="50" cy="50" r="10" fill="white" />
      </svg>
    </div>
  );

  const isRateLimited = rpmCount >= rpmLimit;

  return (
    <div className={`flex flex-col h-full relative overflow-hidden transition-all duration-700 ${isPremium ? 'bg-gradient-to-br from-white via-indigo-50/20 to-slate-50/20 dark:from-slate-950 dark:via-indigo-950/10 dark:to-slate-950' : 'bg-transparent'}`}>

      {isPremium && (
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <motion.div animate={{ scale: [1, 1.2, 1], opacity: [0.15, 0.25, 0.15], x: [0, 30, 0] }} transition={{ duration: 10, repeat: Infinity }} className="absolute top-1/4 -left-20 w-96 h-96 bg-indigo-400/20 rounded-full blur-[100px]" />
          <motion.div animate={{ scale: [1, 1.3, 1], opacity: [0.1, 0.2, 0.1], y: [0, 40, 0] }} transition={{ duration: 15, repeat: Infinity }} className="absolute bottom-1/4 -right-20 w-80 h-80 bg-pink-400/20 rounded-full blur-[100px]" />
        </div>
      )}

      <VoiceInterface isOpen={isVoiceOpen} onClose={() => setIsVoiceOpen(false)} persona={rahixPersona} />

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 pb-32 scroll-smooth scrollbar-hide relative z-10">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12">
            <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="w-20 h-20 mb-8 glass-card bg-white/70 dark:bg-slate-900/70 backdrop-blur-md rounded-3xl flex items-center justify-center animate-float shadow-xl border border-slate-200 dark:border-slate-800">
              <RahiEye size="w-10 h-10" />
            </motion.div>
            <h2 className="text-3xl font-light text-slate-900 dark:text-slate-100 mb-4 tracking-tight">Ask our AI anything</h2>
            <p className="text-slate-600 dark:text-slate-400 text-lg leading-relaxed">Your professional workspace for intelligent analysis and creative synthesis.</p>
          </div>
        )}

        <AnimatePresence initial={false}>
          {messages.map((msg) => (
            isPremium ? <PremiumMessage key={msg.id} msg={msg} /> : (
              <div key={msg.id} className={`flex items-end gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-2`}>
                <div className="shrink-0 mb-1">
                  {msg.role === Role.USER ? (
                    <div className="w-8 h-8 rounded-full bg-slate-900 dark:bg-slate-100 flex items-center justify-center text-[10px] font-black text-white dark:text-slate-950">ME</div>
                  ) : <RahiEye size="w-8 h-8" />}
                </div>
                <div className={`p-4 rounded-[24px] shadow-sm max-w-[75%] ${msg.role === Role.USER ? 'bg-indigo-600 text-slate-100' : 'bg-white/70 dark:bg-slate-900/70 backdrop-blur-md text-slate-900 dark:text-slate-100 border border-slate-200 dark:border-slate-800'}`}>
                  <div className="prose dark:prose-invert max-w-none prose-sm">
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.text}</ReactMarkdown>
                  </div>
                </div>
              </div>
            )
          ))}
        </AnimatePresence>

        {isLoading && (
          <div className="flex justify-start items-center gap-3">
            <RahiEye size="w-8 h-8" animating />
            <div className="bg-white/70 dark:bg-slate-900/70 backdrop-blur-md px-6 py-4 border border-slate-200 dark:border-slate-800 rounded-[24px] shadow-sm flex items-center gap-4">
              <div className="flex gap-1">
                {[0, 1, 2].map(i => <motion.div key={i} animate={{ y: [0, -4, 0] }} transition={{ repeat: Infinity, duration: 0.6, delay: i * 0.1 }} className="w-1.5 h-1.5 bg-indigo-500 rounded-full" />)}
              </div>
              <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">Processing</span>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-8 pt-0 z-20">
        <div className="max-w-3xl mx-auto">
          <div className={`glass-card rounded-[32px] shadow-xl border border-slate-200 dark:border-slate-800 p-2 flex flex-col gap-2 transition-all ${isPremium ? 'bg-white dark:bg-slate-900 shadow-indigo-100/50 dark:shadow-none' : 'bg-white/70 dark:bg-slate-900/70 backdrop-blur-md'}`}>
            <div className="flex items-center gap-2 px-4 pt-1">
              <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
              <div className="h-4 w-px bg-slate-200 dark:bg-slate-800 mx-1"></div>
              <button onClick={() => setUseDeepResearch(!useDeepResearch)} className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black transition-all border ${useDeepResearch ? 'bg-indigo-600 text-slate-100 border-indigo-400' : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-slate-800 hover:bg-slate-200'}`}>DEEP RESEARCH</button>
              <button onClick={() => setIsImageMode(!isImageMode)} className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black transition-all border ${isImageMode ? 'bg-pink-600 text-slate-100 border-pink-400' : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-slate-800 hover:bg-slate-200'}`}>IMAGE MODE</button>
            </div>

            <div className="relative flex items-center">
              <button onClick={toggleListening} className={`ml-4 p-2 rounded-full ${isListening ? 'bg-indigo-600 text-slate-100' : 'text-slate-400 hover:bg-slate-100 dark:hover:bg-white/5'}`}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
              </button>
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                disabled={isRateLimited}
                placeholder={isRateLimited ? `Rate limit active...` : "Ask Rahix anything..."}
                className="flex-1 bg-transparent text-slate-900 dark:text-slate-100 py-4 px-4 resize-none min-h-[56px] max-h-32 outline-none text-[15px] font-medium"
                rows={1}
              />
              <button onClick={handleSend} disabled={isLoading || isRateLimited || (!input.trim() && files.length === 0)} className={`mr-2 p-3 rounded-2xl transition-all ${isRateLimited ? 'bg-slate-300' : 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-950 hover:scale-105'}`}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" /></svg>
              </button>
            </div>
          </div>
          <p className="text-center mt-3 text-[11px] text-slate-600 dark:text-slate-500 font-medium">AI can make mistakes. Please verify important information.</p>
        </div>
      </div>
    </div>
  );
};

