                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>
</head>
<body>
    <div class="ui-layer">
        <div class="instruction">
            <h1>🤖 Rahix Interactive</h1>
            <p><strong>Move Cursor:</strong> Eyes follow your focus<br>
            <strong>Click Robot:</strong> Trigger playful reaction<br>
            <strong>Grab Arms:</strong> Drag and move limbs<br>
            <strong>Right Click:</strong> Rotate workspace</p>
        </div>
    </div>

    <div id="status" class="status">System Online</div>
    <div id="loading" class="loading">Initializing Assistant...</div>
    <div id="canvas-container"></div>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        const scene = new THREE.Scene();
        // Matching Rahix Background
        scene.background = null; 
        scene.fog = new THREE.Fog(0x0f172a, 5, 40);

        const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(0, 3, 10);

        const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        document.getElementById('canvas-container').appendChild(renderer.domElement);

        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.minDistance = 5;
        controls.maxDistance = 15;

        // Lights
        scene.add(new THREE.AmbientLight(0xffffff, 0.5));
        const spotlight = new THREE.SpotLight(0xffffff, 1.5);
        spotlight.position.set(5, 10, 5);
        spotlight.castShadow = true;
        scene.add(spotlight);

        // Materials - Premium Look
        const materials = {
            rahixWhite: new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.1, metalness: 0.2 }),
            indigo: new THREE.MeshStandardMaterial({ color: 0x6366f1, roughness: 0.3, metalness: 0.5 }),
            eyeGreen: new THREE.MeshStandardMaterial({ color: 0x22c55e, emissive: 0x22c55e, emissiveIntensity: 2 }),
            darkFrame: new THREE.MeshStandardMaterial({ color: 0x1e293b })
        };

        const robot = new THREE.Group();
        scene.add(robot);

        // Body
        const body = new THREE.Mesh(new THREE.CylinderGeometry(0.8, 0.7, 1.5, 32), materials.rahixWhite);
        body.castShadow = true;
        robot.add(body);

        // Head Group
        const headGroup = new THREE.Group();
        headGroup.position.y = 1;
        robot.add(headGroup);

        const head = new THREE.Mesh(new THREE.SphereGeometry(0.7, 32, 32, 0, Math.PI*2, 0, Math.PI/2), materials.rahixWhite);
        headGroup.add(head);

        // Visor/Eyes
        const visor = new THREE.Mesh(new THREE.BoxGeometry(0.8, 0.3, 0.1), materials.darkFrame);
        visor.position.set(0, 0.3, 0.6);
        headGroup.add(visor);

        const createEye = (x) => {
            const eye = new THREE.Mesh(new THREE.PlaneGeometry(0.12, 0.12), materials.eyeGreen);
            eye.position.set(x, 0.3, 0.66);
            headGroup.add(eye);
            return eye;
        };
        const leftEye = createEye(-0.2);
        const rightEye = createEye(0.2);

        // State & Interaction
        const mouse = new THREE.Vector2();
        const raycaster = new THREE.Raycaster();

        window.addEventListener('mousemove', (e) => {
            mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
            mouse.y = -(e.clientY / window.innerHeight) * 2 + 1;

            // Simple look-at math
            const targetX = mouse.x * 0.5;
            const targetY = -mouse.y * 0.2;
            headGroup.rotation.y = THREE.MathUtils.lerp(headGroup.rotation.y, targetX, 0.1);
            headGroup.rotation.x = THREE.MathUtils.lerp(headGroup.rotation.x, targetY, 0.1);
        });

        window.addEventListener('mousedown', () => {
            raycaster.setFromCamera(mouse, camera);
            if(raycaster.intersectObject(body).length > 0) {
                triggerJump();
            }
        });

        function triggerJump() {
            const status = document.getElementById('status');
            status.textContent = "Rahix AI: Initiating Pulse! ⚡";
            status.classList.add('visible');
            setTimeout(() => status.classList.remove('visible'), 1500);

            // Simple Jump animation logic
            let t = 0;
            const jump = setInterval(() => {
                t += 0.1;
                robot.position.y = Math.sin(t * Math.PI) * 1.5;
                if(t >= 1) {
                    robot.position.y = 0;
                    clearInterval(jump);
                }
            }, 20);
        }

        function animate() {
            requestAnimationFrame(animate);
            const time = Date.now() * 0.002;

            // Idle hover
            robot.position.y += Math.sin(time) * 0.005;
            // Pulse eyes
            materials.eyeGreen.emissiveIntensity = 1.5 + Math.sin(time * 2) * 0.5;

            controls.update();
            renderer.render(scene, camera);
        }

        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        document.getElementById('loading').remove();
        animate();
    </script>
</body>
</html>
