import React, { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { motion, AnimatePresence } from 'framer-motion';

export const RahiRobot: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const [status, setStatus] = useState<string | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    // Scene setup
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(45, 1, 0.1, 1000);
    camera.position.set(0, 1.5, 6);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(window.devicePixelRatio);
    renderer.setSize(400, 400); // Fixed size for the landing page hero section
    renderer.shadowMap.enabled = true;
    containerRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // Lights
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambientLight);

    const spotLight = new THREE.SpotLight(0xffffff, 1.5);
    spotLight.position.set(5, 10, 5);
    spotLight.castShadow = true;
    scene.add(spotLight);

    // Materials
    const materials = {
      whiteBody: new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.1, metalness: 0.1 }),
      eyeGreen: new THREE.MeshStandardMaterial({ 
        color: 0x22c55e, 
        emissive: 0x22c55e, 
        emissiveIntensity: 2 
      }),
      darkVisor: new THREE.MeshStandardMaterial({ color: 0x1e293b, roughness: 0.2 }),
      indigoCore: new THREE.MeshStandardMaterial({ 
        color: 0x6366f1, 
        emissive: 0x6366f1, 
        emissiveIntensity: 1 
      })
    };

    // Robot Geometry
    const robot = new THREE.Group();
    scene.add(robot);

    // Body (Cylinder)
    const bodyGeo = new THREE.CylinderGeometry(0.7, 0.6, 1.2, 32);
    const body = new THREE.Mesh(bodyGeo, materials.whiteBody);
    body.castShadow = true;
    body.position.y = 0;
    robot.add(body);

    // Core (Glowing light on chest)
    const coreGeo = new THREE.SphereGeometry(0.15, 16, 16);
    const core = new THREE.Mesh(coreGeo, materials.indigoCore);
    core.position.set(0, 0.2, 0.6);
    robot.add(core);

    // Head Group
    const headGroup = new THREE.Group();
    headGroup.position.y = 1;
    robot.add(headGroup);

    // Head Sphere
    const headGeo = new THREE.SphereGeometry(0.65, 32, 32, 0, Math.PI * 2, 0, Math.PI / 1.5);
    const head = new THREE.Mesh(headGeo, materials.whiteBody);
    headGroup.add(head);

    // Visor
    const visorGeo = new THREE.BoxGeometry(0.7, 0.25, 0.1);
    const visor = new THREE.Mesh(visorGeo, materials.darkVisor);
    visor.position.set(0, 0.25, 0.55);
    headGroup.add(visor);

    // Eyes
    const eyeGeo = new THREE.PlaneGeometry(0.12, 0.12);
    const leftEye = new THREE.Mesh(eyeGeo, materials.eyeGreen);
    leftEye.position.set(-0.18, 0.25, 0.61);
    headGroup.add(leftEye);

    const rightEye = new THREE.Mesh(eyeGeo, materials.eyeGreen);
    rightEye.position.set(0.18, 0.25, 0.61);
    headGroup.add(rightEye);

    // Arms
    const createArm = (side: number) => {
      const armGroup = new THREE.Group();
      armGroup.position.set(side * 0.85, 0.4, 0);

      const shoulderGeo = new THREE.SphereGeometry(0.15, 16, 16);
      const shoulder = new THREE.Mesh(shoulderGeo, materials.whiteBody);
      armGroup.add(shoulder);

      const upperArmGeo = new THREE.CylinderGeometry(0.08, 0.08, 0.8, 16);
      const upperArm = new THREE.Mesh(upperArmGeo, materials.whiteBody);
      upperArm.position.y = -0.4;
      armGroup.add(upperArm);

      const handGeo = new THREE.SphereGeometry(0.12, 16, 16);
      const hand = new THREE.Mesh(handGeo, materials.whiteBody);
      hand.position.y = -0.85;
      armGroup.add(hand);

      return armGroup;
    };
    const leftArm = createArm(-1);
    const rightArm = createArm(1);
    robot.add(leftArm);
    robot.add(rightArm);

    // Interaction state
    const mouse = new THREE.Vector2();
    const raycaster = new THREE.Raycaster();
    let isJumping = false;

    const handleMouseMove = (e: MouseEvent) => {
      const rect = renderer.domElement.getBoundingClientRect();
      mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
      mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;

      // Cursor tracking
      const targetRotationY = mouse.x * 0.5;
      const targetRotationX = -mouse.y * 0.2;
      headGroup.rotation.y = THREE.MathUtils.lerp(headGroup.rotation.y, targetRotationY, 0.1);
      headGroup.rotation.x = THREE.MathUtils.lerp(headGroup.rotation.x, targetRotationX, 0.1);
    };

    const handleMouseDown = () => {
      if (isJumping) return;
      raycaster.setFromCamera(mouse, camera);
      const intersects = raycaster.intersectObjects([body, head]);
      if (intersects.length > 0) {
        triggerJump();
      }
    };

    const triggerJump = () => {
      isJumping = true;
      setStatus("Initializing Pulse! ⚡");
      setTimeout(() => setStatus(null), 1500);

      let t = 0;
      const jumpInterval = setInterval(() => {
        t += 0.1;
        robot.position.y = Math.sin(t * Math.PI) * 1.2;
        robot.rotation.z = Math.sin(t * Math.PI) * 0.1;
        if (t >= 1) {
          robot.position.y = 0;
          robot.rotation.z = 0;
          clearInterval(jumpInterval);
          isJumping = false;
        }
      }, 16);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mousedown', handleMouseDown);

    // Animation loop
    let animationId: number;
    const animate = () => {
      animationId = requestAnimationFrame(animate);
      const time = Date.now() * 0.002;

      // Idle hover
      if (!isJumping) {
        robot.position.y = Math.sin(time) * 0.1;
      }

      // Pulse eyes and core
      materials.eyeGreen.emissiveIntensity = 2 + Math.sin(time * 3) * 1;
      materials.indigoCore.emissiveIntensity = 1 + Math.sin(time * 2) * 0.5;

      // Slow rotation if mouse not focus
      if (Math.abs(mouse.x) < 0.1 && Math.abs(mouse.y) < 0.1) {
        robot.rotation.y = THREE.MathUtils.lerp(robot.rotation.y, 0, 0.05);
      }

      renderer.render(scene, camera);
    };
    animate();

    // Cleanup
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
      cancelAnimationFrame(animationId);
      if (rendererRef.current) {
        rendererRef.current.dispose();
        rendererRef.current.forceContextLoss();
      }
    };
  }, []);

  return (
    <div className="relative w-[400px] h-[400px] flex items-center justify-center cursor-pointer select-none">
      <AnimatePresence>
        {status && (
          <motion.div 
            initial={{ opacity: 0, y: 20, scale: 0.8 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, scale: 0.8 }}
            className="absolute top-0 z-50 bg-gradient-to-r from-indigo-600 to-pink-600 text-white px-6 py-2 rounded-full text-xs font-black uppercase tracking-widest shadow-2xl"
          >
            {status}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Speech Bubble / Hint */}
      <div className="absolute -top-10 -right-4 bg-white/90 dark:bg-slate-800/90 text-slate-900 dark:text-slate-100 backdrop-blur-sm border border-slate-200 dark:border-slate-700 px-4 py-2 rounded-2xl text-sm font-bold shadow-xl animate-bounce z-40">
        Hi I'm Rahix!
        <div className="absolute bottom-[-6px] left-4 w-3 h-3 bg-white/90 dark:bg-slate-800 rotate-45 border-r border-b border-slate-200 dark:border-slate-700"></div>
      </div>

      <div ref={containerRef} className="w-full h-full z-10" />

      {/* Shadow */}
      <div className="absolute bottom-10 w-[140px] h-4 bg-black/10 dark:bg-black/40 blur-xl rounded-full scale-x-150" />
    </div>
  );
};

