interface VoiceInterfaceProps {
  isOpen: boolean;
  onClose: () => void;
  persona: string;
}

type AudioState = 'idle' | 'connecting' | 'listening' | 'speaking' | 'error';

// --- Visual Sub-Components ---

const WaveBar: React.FC<{ height: number; delay: number; color: string }> = ({ height, delay, color }) => (
  <motion.div
    className={`w-1.5 rounded-full ${color}`}
    initial={{ height: 4 }}
    animate={{ 
      height: Math.max(6, height * 100),
      opacity: height > 0.1 ? 1 : 0.4
    }}
    transition={{ 
      type: "spring",
      stiffness: 300,
      damping: 20,
      delay: delay * 0.005
    }}
    style={{
      boxShadow: height > 0.5 ? `0 0 15px ${color.includes('emerald') ? '#10b981' : '#a78bfa'}` : 'none'
    }}
  />
);

export const VoiceInterface: React.FC<VoiceInterfaceProps> = ({ isOpen, onClose, persona }) => {
  const [status, setStatus] = useState<AudioState>('idle');
  const [transcription, setTranscription] = useState('');
  const [aiTranscription, setAiTranscription] = useState('');
  const [volumeData, setVolumeData] = useState<number[]>(new Array(32).fill(0));

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // PCM Helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const updateVolume = (data: Float32Array) => {
    let sum = 0;
    for (let i = 0; i < data.length; i++) sum += data[i] * data[i];
    const rms = Math.sqrt(sum / data.length);
    const normalized = Math.min(rms * 8, 1);

    setVolumeData(prev => {
      const next = [...prev];
      next.shift();
      next.push(normalized);
      return next;
    });
  };

  const startSession = async () => {
    setStatus('connecting');
    try {
      const ai = new GoogleGenAI({ apiKey: (process.env.API_KEY as string) });
      // Only request microphone when explicitly starting the session
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('listening');
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              updateVolume(inputData);

              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;

              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => {
                if (session) session.sendRealtimeInput({ media: pcmBlob });
              }).catch(() => {});
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              setAiTranscription(prev => prev + message.serverContent!.outputTranscription!.text);
              setStatus('speaking');
            }
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => prev + message.serverContent!.inputTranscription!.text);
              setAiTranscription('');
              setStatus('listening');
            }
            if (message.serverContent?.turnComplete) {
              setStatus('listening');
              setTranscription('');
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputContextRef.current && outputContextRef.current.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputContextRef.current.currentTime);
              const buffer = await decodeAudioData(decode(audioData), outputContextRef.current, 24000, 1);

              updateVolume(buffer.getChannelData(0));

              const source = outputContextRef.current.createBufferSource();
              source.buffer = buffer;
              source.connect(outputContextRef.current.destination);
              source.onended = () => sourcesRef.current.delete(source);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setStatus('listening');
            }
          },
          onclose: () => handleClose(),
          onerror: (e) => {
            console.error("Voice Error:", e);
            setStatus('error');
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `${persona} MANDATORY: Keep responses under 3 concise sentences. Optimize for audio speed.`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } }
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus('error');
    }
  };

  const handleClose = () => {
    if (audioContextRef.current?.state !== 'closed') audioContextRef.current?.close().catch(() => {});
    if (outputContextRef.current?.state !== 'closed') outputContextRef.current?.close().catch(() => {});
    if (sessionRef.current) {
      try { 
        sessionRef.current.close(); 
      } catch (e) {
        console.warn("Session already closed");
      }
    }
    setStatus('idle');
    setTranscription('');
    setAiTranscription('');
    onClose();
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/90 backdrop-blur-xl p-4"
      >
        <div className="relative w-full max-w-lg bg-slate-900 border border-white/10 rounded-[40px] p-10 flex flex-col items-center gap-10 overflow-hidden shadow-2xl">
          {/* Status Header */}
          <div className="text-center space-y-2">
            <h2 className="text-indigo-400 text-[10px] font-black uppercase tracking-[0.5em]">Neural Voice Interface</h2>
            <div className={`px-4 py-1 rounded-full border text-[9px] font-bold uppercase transition-all ${
              status === 'listening' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
              status === 'speaking' ? 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20' :
              status === 'connecting' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20 animate-pulse' :
              'bg-slate-800 text-slate-400 border-slate-700'
            }`}>
              {status}
            </div>
          </div>

          {/* Waveform Visualization */}
          <div className="flex items-center justify-center gap-1.5 h-32 w-full">
            {volumeData.map((v, i) => (
              <WaveBar 
                key={i} 
                height={v} 
                delay={i} 
                color={status === 'listening' ? 'bg-emerald-500' : 'bg-indigo-500'} 
              />
            ))}
          </div>

          {/* Transcription Display */}
          <div className="w-full text-center space-y-4 min-h-[80px]">
            {transcription && (
              <p className="text-slate-400 text-sm font-medium italic animate-in fade-in slide-in-from-bottom-2">
                "{transcription}"
              </p>
            )}
            {aiTranscription && (
              <p className="text-slate-100 text-lg font-bold leading-relaxed animate-in fade-in slide-in-from-top-2">
                {aiTranscription}
              </p>
            )}
          </div>

          {/* Controls */}
          <div className="flex items-center gap-6">
            {status === 'idle' ? (
              <button
                onClick={startSession}
                className="px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full font-bold text-sm transition-all shadow-xl shadow-indigo-600/20 flex items-center gap-3 group"
              >
                <div className="w-2 h-2 rounded-full bg-white animate-pulse" />
                Initialize Neural Link
              </button>
            ) : (
              <button
                onClick={handleClose}
                className="p-5 bg-rose-500/10 hover:bg-rose-500 text-rose-500 hover:text-white rounded-full transition-all border border-rose-500/20 group"
              >
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <path d="M18 6L6 18M6 6l12 12" />
                </svg>
              </button>
            )}
          </div>

          {/* Minimal Close */}
          <button 
            onClick={handleClose}
            className="absolute top-6 right-6 p-2 text-slate-600 hover:text-white transition-colors"
          >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <path d="M18 6L6 18M6 6l12 12" />
            </svg>
          </button>
        </div>
      </motion.div>
    </AnimatePresence>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { motion, AnimatePresence } from 'framer-motion';
import { Role, ChatMessage, FileData } from '../types';
import { FileUpload } from './FileUpload';
import { QuantumLoader } from './AILoader';
import { VoiceInterface } from './VoiceInterface';

// Fix for framer-motion type errors by casting to any
const Motion = motion as any;

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string, files: FileData[], useWebSearch: boolean, isImage: boolean) => void;
  isLoading: boolean;
  onEditInCanvas: (text: string, mode?: 'text' | 'code' | 'presentation') => void;
  rpmCount: number;
  rpmLimit: number;
  rpmResetSeconds: number;
  isPremium?: boolean;
}

const SUGGESTIONS = [
  "Analyze technical docs",
  "Write clean React code",
  "Generate 4K render",
  "Workspace summary"
];

// Typewriter Component for Premium Mode
const TypewriterText: React.FC<{ text: string }> = ({ text }) => {
  const [displayedText, setDisplayedText] = useState('');
  useEffect(() => {
    let index = 0;
    const timer = setInterval(() => {
      if (index < text.length) {
        setDisplayedText(text.slice(0, index + 1));
        index++;
      } else clearInterval(timer);
    }, 15);
    return () => clearInterval(timer);
  }, [text]);
  return <ReactMarkdown remarkPlugins={[remarkGfm]}>{displayedText}</ReactMarkdown>;
};

// Premium AI Message entry with interactive actions and glow
const PremiumMessage: React.FC<{ msg: ChatMessage; onEdit: (t: string) => void }> = ({ msg, onEdit }) => {
  const [isHovered, setIsHovered] = useState(false);
  const isModel = msg.role === Role.MODEL;

  return (
    // Use casted Motion component to bypass type errors
    <Motion.div
      initial={{ opacity: 0, y: 20, scale: 0.98 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      className={`flex flex-col ${isModel ? 'items-start' : 'items-end'} mb-8 group w-full`}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <Motion.span 
        initial={{ opacity: 0 }}
        animate={{ opacity: 0.6 }}
        className={`text-[9px] font-black tracking-[0.2em] uppercase mb-2 ${isModel ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-600 dark:text-slate-400'}`}
      >
        {isModel ? 'Rahix System' : 'Owner'}
      </Motion.span>

      <div className={`relative max-w-[85%] ${isModel ? 'mr-auto' : 'ml-auto'}`}>
        <Motion.div
          whileHover={{ scale: 1.01 }}
          className={`relative px-6 py-4 rounded-[28px] text-[15px] leading-relaxed shadow-sm transition-all duration-300 ${
            !isModel 
              ? 'bg-slate-900 text-slate-100 dark:bg-slate-100 dark:text-slate-900 rounded-tr-sm' 
              : 'bg-white/80 dark:bg-slate-900/80 backdrop-blur-md text-slate-900 dark:text-slate-100 border border-indigo-100 dark:border-indigo-900/50 rounded-tl-sm'
          }`}
        >
          {isModel && (
            <Motion.div 
              className="absolute -inset-1 bg-gradient-to-r from-indigo-500/10 to-pink-500/10 rounded-[30px] blur-md -z-10 opacity-0 group-hover:opacity-100 transition-opacity" 
            />
          )}

          <div className="prose dark:prose-invert max-w-none prose-sm prose-slate">
            {isModel ? <TypewriterText text={msg.text} /> : <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.text}</ReactMarkdown>}
          </div>

          {msg.isImageGeneration && <img src={msg.text} className="mt-4 rounded-xl border border-indigo-200 dark:border-indigo-800 shadow-xl w-full" alt="AI Workspace Render" />}
        </Motion.div>

        <AnimatePresence>
          {isHovered && isModel && (
            <Motion.div
              initial={{ opacity: 0, y: 5 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 5 }}
              className="absolute top-0 -right-12 flex flex-col gap-2"
            >
              <button onClick={() => onEdit(msg.text)} className="p-2 bg-white dark:bg-slate-800 rounded-full shadow-lg border border-slate-200 dark:border-slate-700 text-slate-400 hover:text-indigo-600 transition-all">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" /><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" /></svg>
              </button>
            </Motion.div>
          )}
        </AnimatePresence>
      </div>

      <span className="text-[10px] text-slate-500 dark:text-slate-600 mt-2 px-1 font-medium">
        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
      </span>
    </Motion.div>
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  onSendMessage, 
  isLoading,
  onEditInCanvas,
  rpmCount,
  rpmLimit,
  rpmResetSeconds,
  isPremium = false
}) => {
  const [input, setInput] = useState('');
  const [files, setFiles] = useState<FileData[]>([]);
  const [useDeepResearch, setUseDeepResearch] = useState(false);
  const [isImageMode, setIsImageMode] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const baseInputRef = useRef<string>(''); 

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isLoading]);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.onresult = (event: any) => {
        let transcript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) transcript += event.results[i][0].transcript;
        setInput(baseInputRef.current + (baseInputRef.current ? ' ' : '') + transcript);
      };
      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const toggleListening = () => {
    if (isListening) recognitionRef.current?.stop();
    else {
      baseInputRef.current = input;
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleSend = () => {
    if (rpmCount >= rpmLimit) return;
    if (input.trim() || files.length > 0) {
      onSendMessage(input, files, useDeepResearch, isImageMode);
      setInput('');
      setFiles([]);
    }
  };

  return (
    <div className={`flex flex-col h-full relative overflow-hidden transition-all duration-1000 ${isPremium ? 'bg-gradient-to-br from-slate-50 via-indigo-50/20 to-white dark:from-slate-950 dark:via-indigo-950/10 dark:to-slate-950' : 'bg-transparent'}`}>

      {isPremium && (
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <Motion.div animate={{ scale: [1, 1.2, 1], opacity: [0.2, 0.3, 0.2], x: [0, 50, 0] }} transition={{ duration: 10, repeat: Infinity }} className="absolute top-1/4 -left-32 w-96 h-96 bg-indigo-400/20 dark:bg-indigo-600/30 rounded-full blur-[120px]" />
          <Motion.div animate={{ scale: [1, 1.3, 1], opacity: [0.15, 0.25, 0.15], y: [0, 40, 0] }} transition={{ duration: 15, repeat: Infinity }} className="absolute bottom-1/4 -right-32 w-96 h-96 bg-pink-400/20 dark:bg-pink-600/30 rounded-full blur-[120px]" />
        </div>
      )}

      <VoiceInterface isOpen={isVoiceOpen} onClose={() => setIsVoiceOpen(false)} persona="System Assistant" />

      <div ref={scrollRef} className="flex-1 overflow-y-auto px-6 py-8 space-y-2 pb-48 scrollbar-hide relative z-10">
        {messages.length === 0 && (
          <Motion.div 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="h-full flex flex-col items-center justify-center text-center max-w-lg mx-auto py-12"
          >
            <div className="w-20 h-20 mb-8 glass-card bg-white/70 dark:bg-slate-900/70 backdrop-blur-md rounded-3xl flex items-center justify-center animate-float shadow-xl border border-slate-200 dark:border-slate-800">
              <svg viewBox="0 0 100 100" className="w-10 h-10">
                <circle cx="50" cy="50" r="45" fill="currentColor" className="text-slate-100 dark:text-slate-800" stroke="currentColor" strokeWidth="5" />
                <circle cx="50" cy="50" r="20" fill="#6366f1" className="animate-pulse" />
              </svg>
            </div>
            <h2 className="text-4xl font-light text-slate-900 dark:text-slate-100 mb-4 tracking-tight">How can Rahix help?</h2>
            <p className="text-slate-600 dark:text-slate-400 text-lg leading-relaxed font-medium">Your intelligent workspace for deep analysis and creation.</p>
          </Motion.div>
        )}

        <AnimatePresence initial={false}>
          {messages.map((msg) => (
            isPremium ? (
              <PremiumMessage key={msg.id} msg={msg} onEdit={onEditInCanvas} />
            ) : (
              <div key={msg.id} className={`flex items-end gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-2`}>
                <div className={`p-4 rounded-[24px] shadow-sm max-w-[75%] ${msg.role === Role.USER ? 'bg-indigo-600 text-slate-100' : 'bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100 border border-slate-200 dark:border-slate-800'}`}>
                  <div className="prose dark:prose-invert max-w-none prose-sm">
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.text}</ReactMarkdown>
                  </div>
                </div>
              </div>
            )
          ))}
        </AnimatePresence>

        {isLoading && (
          <Motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex items-center gap-4 ml-2">
            <div className="bg-indigo-500/10 p-3 rounded-2xl flex gap-1">
              {[0, 1, 2].map(i => <Motion.div key={i} animate={{ y: [0, -4, 0] }} transition={{ repeat: Infinity, duration: 0.6, delay: i * 0.1 }} className="w-1.5 h-1.5 bg-indigo-500 rounded-full" />)}
            </div>
            <span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Neural Processing</span>
          </Motion.div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-8 pt-0 z-20">
        <div className="max-w-3xl mx-auto space-y-6">
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide justify-center">
            {SUGGESTIONS.map((s, idx) => (
              <Motion.button
                key={idx}
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => setInput(s)}
                className="whitespace-nowrap px-4 py-2 bg-white/70 dark:bg-slate-900/70 backdrop-blur-md border border-slate-200 dark:border-slate-800 rounded-full text-xs font-bold text-slate-600 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 transition-all shadow-sm"
              >
                {s}
              </Motion.button>
            ))}
          </div>

          <div className={`glass-card rounded-[36px] shadow-2xl border border-slate-200 dark:border-slate-800 p-2 flex flex-col gap-2 transition-all duration-500 ${isPremium ? 'bg-white dark:bg-slate-900 ring-2 ring-indigo-500/10' : 'bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl'}`}>
            <div className="flex items-center gap-2 px-4 pt-1">
              <FileUpload onFilesSelected={setFiles} selectedFiles={files} />
              <div className="h-4 w-px bg-slate-200 dark:bg-slate-800 mx-1"></div>
              <button onClick={() => setUseDeepResearch(!useDeepResearch)} className={`px-3 py-1.5 rounded-full text-[10px] font-black transition-all border ${useDeepResearch ? 'bg-indigo-600 text-slate-100 border-indigo-400' : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-slate-800 hover:bg-slate-200'}`}>DEEP RESEARCH</button>
              <button onClick={() => setIsImageMode(!isImageMode)} className={`px-3 py-1.5 rounded-full text-[10px] font-black transition-all border ${isImageMode ? 'bg-pink-600 text-slate-100 border-pink-400' : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-slate-800 hover:bg-slate-200'}`}>IMAGE MODE</button>
              <button onClick={() => setIsVoiceOpen(true)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors ml-auto"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg></button>
            </div>

            <div className="relative flex items-center pr-2">
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSend())}
                placeholder={rpmCount >= rpmLimit ? "Rate limit reached..." : "Command Rahix..."}
                className="flex-1 bg-transparent text-slate-900 dark:text-slate-100 py-4 px-6 resize-none min-h-[64px] max-h-32 outline-none text-[15px] font-medium placeholder:text-slate-400 dark:placeholder:text-slate-600"
                rows={1}
              />
              <Motion.button 
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={handleSend} 
                disabled={isLoading || rpmCount >= rpmLimit || (!input.trim() && files.length === 0)} 
                className={`p-3 rounded-2xl transition-all shadow-lg ${input.trim() ? 'bg-indigo-600 text-white shadow-indigo-500/40' : 'bg-slate-200 dark:bg-slate-800 text-slate-400'}`}
              >
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" /></Motion.button>
            </div>
          </div>
          <div className="text-center">
            <span className="text-[10px] text-slate-500 dark:text-slate-600 font-bold uppercase tracking-widest">Workspace Link Stable • RPM {rpmCount}/{rpmLimit}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { motion, AnimatePresence } from 'framer-motion';

// Fix for framer-motion type errors
const Motion = motion as any;

export const RahiRobot: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const [status, setStatus] = useState<string | null>(null);

  // Interaction targets
  const mouse = useRef({ x: 0, y: 0 });
  const targetRotation = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!containerRef.current) return;

    // --- Scene Setup ---
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(45, 1, 0.1, 1000);
    camera.position.set(0, 0.5, 7);

    const renderer = new THREE.WebGLRenderer({ 
      antialias: true, 
      alpha: true,
      powerPreference: "high-performance"
    });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(400, 400);
    renderer.shadowMap.enabled = true;
    containerRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // --- Lighting ---
    // Top-Left White Light
    const dirLight = new THREE.DirectionalLight(0xffffff, 2.5);
    dirLight.position.set(-5, 10, 5);
    scene.add(dirLight);

    // Cyberpunk Rim Light (Vivid Purple)
    const pointLight = new THREE.PointLight(0xa855f7, 15, 20);
    pointLight.position.set(5, 2, 5);
    scene.add(pointLight);

    // Soft Ambient
    const ambLight = new THREE.AmbientLight(0x6366f1, 0.4);
    scene.add(ambLight);

    // --- Materials ---
    const arcticWhite = new THREE.MeshStandardMaterial({
      color: 0xffffff,
      roughness: 0.1,
      metalness: 0.2,
    });

    const smokedGlass = new THREE.MeshPhysicalMaterial({
      color: 0x111111,
      metalness: 0,
      roughness: 0.1,
      transmission: 0.6,
      thickness: 0.2,
      transparent: true,
      opacity: 0.9,
    });

    const digitalEye = new THREE.MeshStandardMaterial({
      color: 0x22d3ee,
      emissive: 0x22d3ee,
      emissiveIntensity: 8,
    });

    // --- Geometry Construction ---
    const robotGroup = new THREE.Group();
    scene.add(robotGroup);

    // 1. Floating Capsule Body
    const bodyGeo = new THREE.CapsuleGeometry(0.8, 1.2, 16, 32);
    const body = new THREE.Mesh(bodyGeo, arcticWhite);
    body.position.y = 0;
    robotGroup.add(body);

    // 2. Detached Floating Head
    const headGroup = new THREE.Group();
    headGroup.position.y = 1.8;
    robotGroup.add(headGroup);

    const headGeo = new THREE.SphereGeometry(0.7, 32, 32, 0, Math.PI * 2, 0, Math.PI * 0.7);
    const head = new THREE.Mesh(headGeo, arcticWhite);
    head.rotation.x = 0.2;
    headGroup.add(head);

    // 3. Curved Glass Visor
    const visorGeo = new THREE.SphereGeometry(0.71, 32, 32, Math.PI * 0.35, Math.PI * 0.3, Math.PI * 0.35, Math.PI * 0.3);
    const visor = new THREE.Mesh(visorGeo, smokedGlass);
    headGroup.add(visor);

    // 4. Digital Eyes
    const createEye = (x: number) => {
      const eyeGeo = new THREE.CircleGeometry(0.08, 32);
      const eye = new THREE.Mesh(eyeGeo, digitalEye);
      eye.position.set(x, 0.15, 0.65);
      headGroup.add(eye);
      return eye;
    };
    const leftEye = createEye(-0.2);
    const rightEye = createEye(0.2);

    // --- Interaction ---
    const handleMouseMove = (e: MouseEvent) => {
      const rect = renderer.domElement.getBoundingClientRect();
      const x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
      const y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
      mouse.current = { x, y };
    };

    window.addEventListener('mousemove', handleMouseMove);

    // --- Animation Loop ---
    let animationId: number;
    const clock = new THREE.Clock();

    const animate = () => {
      animationId = requestAnimationFrame(animate);
      const time = clock.getElapsedTime();

      // 1. Smooth Smoothing (lerp)
      targetRotation.current.y = THREE.MathUtils.lerp(targetRotation.current.y, mouse.current.x * 0.4, 0.05);
      targetRotation.current.x = THREE.MathUtils.lerp(targetRotation.current.x, -mouse.current.y * 0.2, 0.05);

      headGroup.rotation.y = targetRotation.current.y;
      headGroup.rotation.x = targetRotation.current.x;

      body.rotation.y = targetRotation.current.y * 0.3;

      // 2. Floating Idle Animation
      robotGroup.position.y = Math.sin(time * 1.5) * 0.15;

      // 3. Eye Pulse
      digitalEye.emissiveIntensity = 8 + Math.sin(time * 4) * 4;

      renderer.render(scene, camera);
    };

    animate();

    // --- Cleanup ---
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationId);
      renderer.dispose();
      bodyGeo.dispose();
      headGeo.dispose();
      visorGeo.dispose();
      arcticWhite.dispose();
      smokedGlass.dispose();
      digitalEye.dispose();
    };
  }, []);

  return (
    <div className="relative w-[400px] h-[400px] flex items-center justify-center select-none">
      <AnimatePresence>
        {status && (
          <Motion.div 
            initial={{ opacity: 0, y: 20, scale: 0.8 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, scale: 0.8 }}
            className="absolute top-0 z-50 bg-gradient-to-r from-indigo-600 to-pink-600 text-white px-6 py-2 rounded-full text-xs font-black uppercase tracking-widest shadow-2xl"
          >
            {status}
          </Motion.div>
        )}
      </AnimatePresence>

      {/* Dynamic Tag */}
      <div className="absolute -top-10 -right-4 bg-white/90 dark:bg-slate-800/90 text-slate-900 dark:text-slate-100 backdrop-blur-sm border border-slate-200 dark:border-slate-700 px-4 py-2 rounded-2xl text-sm font-bold shadow-xl animate-bounce z-40">
        Engine Online
        <div className="absolute bottom-[-6px] left-4 w-3 h-3 bg-white/90 dark:bg-slate-800 rotate-45 border-r border-b border-slate-200 dark:border-slate-700"></div>
      </div>

      <div ref={containerRef} className="w-full h-full relative z-10" />

      {/* 3D Contact Shadow */}
      <div className="absolute bottom-10 w-[160px] h-6 bg-black/10 dark:bg-black/40 blur-2xl rounded-full scale-x-150" />
    </div>
  );
};

