              </svg>
            </button>

            {showTooltip && (
              <div className="absolute bottom-full left-0 mb-2 w-48 p-2 bg-slate-800 border border-white/10 rounded-lg shadow-2xl z-50 animate-in fade-in slide-in-from-bottom-1">
                <p className="text-[9px] text-slate-300 leading-relaxed font-medium">
                  Rahix AI uses the Gemini 2.0 Flash Free Tier. Usage is limited to {limit} requests per minute. Resetting in {resetSeconds}s.
