                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSend())}
                  placeholder={rpmCount >= rpmLimit ? "Neural Link Throttled..." : "Command Rahix..."}
                  className="flex-1 bg-transparent text-slate-900 dark:text-slate-100 py-3 md:py-4 resize-none min-h-[50px] md:min-h-[60px] max-h-32 outline-none text-sm md:text-base font-medium placeholder:text-slate-400"
                  rows={1}
                />
                <button 
                  onClick={handleSend} 
                  disabled={isLoading || rpmCount >= rpmLimit || (!input.trim() && files.length === 0)} 
                  className={`p-3 md:p-4 rounded-[20px] md:rounded-[24px] transition-all shadow-lg ${input.trim() || files.length > 0 ? 'bg-indigo-600 text-white shadow-indigo-500/40' : 'bg-slate-200 dark:bg-slate-800 text-slate-400'}`}
                >
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" /></svg>
                </button>
              </div>
            </div>

            {/* Status Footer - Reduced height */}
            <div className="flex items-center justify-center gap-4 py-1">
               <div className="flex items-center gap-2 px-4 py-1.5 bg-white dark:bg-slate-900 rounded-full border border-slate-200 dark:border-slate-800 shadow-sm text-[9px] font-bold">
                 <span className="text-slate-500 uppercase tracking-widest">Neural Load</span>
                 <div className="w-20 md:w-32 h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-indigo-500 transition-all duration-500" style={{ width: `${usagePercent}%` }} />
                 </div>
                 <span className="text-indigo-600 dark:text-indigo-400 tabular-nums">{rpmCount}/{rpmLimit} RPM</span>
                 <div className="h-3 w-px bg-slate-200 dark:bg-slate-800 mx-1" />
                 <span className="text-slate-400 uppercase tracking-widest">RESET {rpmResetSeconds}s</span>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

