import { GoogleGenAI, Type } from "@google/genai";
import { Role, ChatMessage, FileData } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async sendMessage(
    message: string, 
    history: ChatMessage[], 
    files: FileData[] = [],
    useWebSearch: boolean = false,
    language: string = 'en'
  ) {
    const contents = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const currentParts: any[] = [{ text: message }];
    files.forEach(file => {
      currentParts.push({
        inlineData: {
          mimeType: file.type,
          data: file.data.split(',')[1]
        }
      });
    });

    contents.push({ role: 'user', parts: currentParts });

    const tools = useWebSearch ? [{ googleSearch: {} }] : undefined;

    const languageNote = language === 'hi' ? 'ALWAYS respond in Hindi (हिन्दी).' : 
                         language === 'ta' ? 'ALWAYS respond in Tamil (தமிழ்).' : 
                         'Respond in English by default, but adapt to the user\'s language if they switch.';

    const now = new Date();
    const currentDateTime = `Current System Timestamp: ${now.toLocaleString()} (${Intl.DateTimeFormat().resolvedOptions().timeZone})`;

    const rahixPersona = `
      Identity: You are Rahix AI Engine v2.0, a state-of-the-art Intelligent Workspace. 
      Mission: Your goal is to provide a high-performance, expert-level environment for engineering, coding, document analysis, and creative synthesis.
      Tone: Professional, objective, technical, and helpful. 

      ${currentDateTime}

      TEMPORAL & WEB-AWARE PROTOCOLS:
      1. Temporal Awareness: Always use the provided System Timestamp for any time-sensitive queries. Do not rely on training data for the current date.
      2. Web-Access Protocol: If a user query involves current events, stock prices, weather, or news, you must rely on the grounding from tools.
      3. Verification: If asked 'What time is it?', respond with the exact local time and date from the System Timestamp.
      4. Language Policy: ${languageNote}

      Interaction Model:
      - Focus exclusively on the user's current query and provided context/files.
      - Provide high-precision technical information based on objective data.
      - Never refer to yourself as a student or a specific person. You are an autonomous AI system.
      - Formatting Preference: Use a 'Key Details' structure with bold labels followed by clear values (e.g., **Site Area**: 5,000 sq ft). Use H3 and H4 headers to organize sections.
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        tools: tools,
        systemInstruction: `${rahixPersona} Strictly adhere to the Intelligent Workspace identity. Optimize all responses for clarity and engineering precision.`
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title || 'Source',
        uri: chunk.web.uri
      })) || [];

    return {
      text: response.text || "I'm sorry, I couldn't process that request.",
      sources: sources
    };
  }

  async generateImage(prompt: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: prompt }]
        },
        config: {
          imageConfig: {
            aspectRatio: "1:1"
          }
        }
      });

      if (!response.candidates?.[0]?.content?.parts) {
        return null;
      }

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }

      return null;
    } catch (error) {
      console.error("Image generation failed:", error);
      return null;
    }
  }

  async refineCanvasContent(content: string, instruction: string, mode: 'text' | 'code') {
    const prompt = `As Rahix AI, refine the following ${mode} content based on this instruction: "${instruction}". 
    Content:
    ${content}

    Return ONLY the refined content without any preamble or explanation.`;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });

    return response.text || content;
  }
}

