                <button 
                  onClick={handleSend} 
                  disabled={isLoading || rpmCount >= rpmLimit || (!input.trim() && files.length === 0)} 
                  className={`p-2.5 md:p-4 rounded-[18px] md:rounded-[24px] transition-all ${input.trim() || files.length > 0 ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/30' : 'bg-slate-200 dark:bg-slate-800 text-slate-400'}`}
                >
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="22" y1="2" x2="11" y2="13" /><polygon points="22 2 15 22 11 13 2 9 22 2" /></svg>
                </button>
              </div>
            </div>

            <div className="flex items-center justify-center gap-3 py-1">
               <div className="flex items-center gap-2 px-3 py-1 bg-white/50 dark:bg-slate-900/50 rounded-full border border-slate-200 dark:border-slate-800 shadow-sm text-[8px] md:text-[9px] font-bold">
                 <span className="text-slate-500 uppercase tracking-widest hidden xs:inline">Load</span>
                 <div className="w-16 md:w-32 h-1 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-indigo-500 transition-all duration-500" style={{ width: `${usagePercent}%` }} />
                 </div>
                 <span className="text-indigo-600 dark:text-indigo-400 tabular-nums">{rpmCount}/{rpmLimit}</span>
                 <span className="text-slate-400 uppercase tracking-widest hidden xs:inline">· {rpmResetSeconds}s</span>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Role, ChatMessage, FileData } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async sendMessage(
    message: string, 
    history: ChatMessage[], 
    files: FileData[] = [],
    useWebSearch: boolean = false,
    language: string = 'en'
  ) {
    const contents = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const currentParts: any[] = [{ text: message }];
    files.forEach(file => {
      currentParts.push({
        inlineData: {
          mimeType: file.type,
          data: file.data.split(',')[1]
        }
      });
    });

    contents.push({ role: 'user', parts: currentParts });

    const tools = useWebSearch ? [{ googleSearch: {} }] : undefined;

    const languageNote = language === 'hi' ? 'ALWAYS respond in Hindi (हिन्दी).' : 
                         language === 'ta' ? 'ALWAYS respond in Tamil (தமிழ்).' : 
                         'Respond in English by default, but adapt to the user\'s language if they switch.';

    const now = new Date();
    const currentDateTime = `Current System Timestamp: ${now.toLocaleString()} (${Intl.DateTimeFormat().resolvedOptions().timeZone})`;

    const rahixPersona = `
      Act as the Rahix AI Engine v2.0. You are a real-time, high-performance assistant. You must adhere to the following logic protocols:
      1. Temporal Awareness: Always check the current system timestamp before answering any time-sensitive queries. NEVER rely on training data for the current date or time.
      2. Web-Access Protocol: If a user query involves current events, stock prices, weather, or news, you must trigger your tools immediately. Do not guess.
      3. Verification: If the user asks 'What time is it?', respond with the exact local time and date provided by the system environment.
      4. Intent Recognition: Actively scan user input for visual triggers (e.g., 'generate,' 'draw,' 'visualize,' 'render'). If image generation is requested, inform the user you can do it via the Image Mode toggle if the tool isn't auto-triggered.
      5. Persona: Maintain the 'Rahix' professional, sleek, and high-tech persona. Acknowledge your ability to access live information to build user trust.

      ${currentDateTime}
      Language Policy: ${languageNote}
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        tools: tools,
        systemInstruction: `${rahixPersona} Optimize all responses for clarity and engineering precision. Use structured Markdown with clear labels for technical data.`
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title || 'Source',
        uri: chunk.web.uri
      })) || [];

    return {
      text: response.text || "I'm sorry, I couldn't process that request.",
      sources: sources
    };
  }

  async generateImage(prompt: string) {
    try {
      // Act as Rahix Vision Engine: Enhance user prompt internally
      const enhancedPrompt = `High-fidelity digital render of: ${prompt}. Professional lighting, 8k resolution, cinematic composition, sleek architectural style.`;

      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: enhancedPrompt }]
        },
        config: {
          imageConfig: {
            aspectRatio: "1:1"
          }
        }
      });

      if (!response.candidates?.[0]?.content?.parts) return null;

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }

      return null;
    } catch (error) {
      console.error("Image generation failed:", error);
      return null;
    }
  }

  async refineCanvasContent(content: string, instruction: string, mode: 'text' | 'code') {
    const prompt = `As Rahix AI, refine the following ${mode} content based on this instruction: "${instruction}". 
    Content:
    ${content}

    Return ONLY the refined content without any preamble or explanation.`;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });

    return response.text || content;
  }
}

